INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (170, 'Dibujo para colorear chef con gorro alto', 'dibujo-para-colorear-chef-con-gorro-alto', 'Chef profesional con gorro de cocina', '<p>El maestro de la cocina aparece con su impecable gorro *toque blanche* y su uniforme de chef. Esta lámina celebra la gastronomía y el arte de preparar alimentos deliciosos, fomentando el interés por la comida saludable y creativa.</p>
  <h4>El mundo de la cocina</h4>
  <p>La ilustración suele incluir elementos como una cuchara de madera o un bol. Es una forma divertida de que los niños identifiquen los utensilios básicos y se imaginen preparando su plato favorito mientras colorean.</p>
  <h4>Sombras en blanco</h4>
  <p>Como el uniforme del chef suele ser blanco, el reto artístico es usar sombras grises muy suaves en los pliegues de la ropa y el gorro para darle volumen sin perder la sensación de limpieza y profesionalismo.</p>', 'chef, cocina, gorro alto, gastronomía, profesión culinaria', 'dibujo-para-colorear-chef-con-gorro-alto', 4, NULL, '2026-03-07T00:42:42.664Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280259/coloring-web/profesiones-oficios/dibujo-para-colorear-chef-con-gorro-alto.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-chef-con-gorro-alto') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
