INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (280, 'Dibujo para colorear patineta con fondo de montaña', 'dibujo-para-colorear-patineta-con-fondo-de-montana', 'Dibujo para colorear patineta con fondo de montaña', 'Un dibujo detallado de Dibujo para colorear patineta con fondo de montaña, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'patineta, skateboard, skate, deporte urbano, deporte, patineta con paisaje', 'dibujo-para-colorear-patineta-con-fondo-de-montana', 5, NULL, '2026-03-12T02:07:06.360Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280387/coloring-web/vehiculos/dibujo-para-colorear-patineta-con-fondo-de-montana.webp', 'coloring-web/vehiculos/dibujo-para-colorear-patineta-con-fondo-de-montana') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (260, 'Dibujo para colorear camión con grúa telescópica', 'dibujo-para-colorear-camion-con-grua-telescopica', 'Camión con grúa telescópica trabajando en construcción', '<p>La versatilidad de la logística moderna se aprecia en este camión equipado con una grúa de brazo extensible. Es un vehículo esencial para elevar cargas pesadas en puertos, fábricas y grandes proyectos de construcción urbana.</p>
  <h4>Concepto de equilibrio y peso</h4>
  <p>El brazo de la grúa permite hablar sobre la física básica. Los niños pueden colorear los cables y el gancho con especial cuidado, entendiendo cómo estas máquinas pueden levantar objetos mucho más grandes que ellas mismas.</p>
  <h4>Técnicas para el metal</h4>
  <p>Recomendamos usar colores como el naranja o el blanco para el brazo extensible. Dejar pequeñas zonas en blanco en la parte superior de los tubos simulará el reflejo del sol sobre el metal liso, dándole un acabado 3D.</p>', 'camión grúa, grúa telescópica, construcción, maquinaria de obra, ingeniería, elevación de cargas, vehículo de obra', 'dibujo-para-colorear-camion-con-grua-telescopica', 5, NULL, '2026-03-12T01:58:41.678Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280362/coloring-web/vehiculos/dibujo-para-colorear-camion-con-grua-telescopica.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-con-grua-telescopica') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
