INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (429, 'Familia de Triceratops cuidando su nido para colorear', 'familia-de-triceratops-cuidando-su-nido-para-colorear', 'familia de triceratops cuidando huevos dibujo para colorear', 'Un increíble dibujo de Familia de Triceratops cuidando su nido para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'triceratops familia, dinosaurios crías, dinosaurios nido, dinosaurios grupo, dibujos para colorear dinosaurios', 'familia-de-triceratops-cuidando-su-nido-para-colorear', 7, NULL, '2026-03-21T05:25:41.730Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774059940/coloring-web/dinosaurios/familia-de-triceratops-cuidando-su-nido-para-colorear.webp', 'coloring-web/dinosaurios/familia-de-triceratops-cuidando-su-nido-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (475, 'Princesa viajando en carruaje para colorear | Dibujo de transporte real y fantasía', 'princesa-viajando-en-carruaje-para-colorear-or-dibujo-de-transporte-real-y-fantasia', 'Princesa viajando en un carruaje clásico tirado por caballos, ilustración infantil en blanco y negro para colorear.', '<h3>Un viaje digno de la realeza</h3> <p>Esta ilustración muestra a una princesa viajando en un elegante carruaje, un medio de transporte clásico asociado a los cuentos de hadas. La escena invita a imaginar largos recorridos por caminos rodeados de naturaleza y castillos lejanos.</p> <h3>Elementos que enriquecen la escena</h3> <p>El carruaje, las ruedas y los detalles estructurales permiten trabajar distintas formas y texturas, haciendo que el dibujo sea más completo y entretenido.</p> <h3>Colores inspirados en cuentos clásicos</h3> <p>Se pueden usar tonos dorados, marrones y colores brillantes para destacar el carruaje, mientras que el entorno puede complementarse con verdes y azules.</p> <h3>Estimulación narrativa</h3> <p>Este tipo de ilustraciones fomenta la creación de historias, donde los niños pueden imaginar hacia dónde viaja la princesa y qué aventuras le esperan.</p>', 'princesa carruaje, transporte real, carruaje caballo, viaje princesa, fantasía medieval, dibujo infantil, princesa en movimiento, castillo viaje, ilustración detallada, cuento de hadas, actividad niños, arte para colorear, reino mágico, creatividad, escena clásica', 'princesa-viajando-en-carruaje-para-colorear-or-dibujo-de-transporte-real-y-fantasia', 8, NULL, '2026-04-01T18:08:37.206Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056116/coloring-web/princesas/princesa-viajando-en-carruaje-para-colorear-or-dibujo-de-transporte-real-y-fantasia.webp', 'coloring-web/princesas/princesa-viajando-en-carruaje-para-colorear-or-dibujo-de-transporte-real-y-fantasia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (11, 'Dibujo de perrito cachorro durmiendo en su manta para colorear', 'dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear', 'Dibujo lineal de un cachorro pequeño descansando plácidamente sobre una alfombra o manta dentro de una casa.', '<p>La máxima ternura se captura en este dibujo. Un pequeño cachorro de perro duerme profundamente, enrollado sobre una manta suave decorada con estrellas, creando una imagen llena de calidez y bienestar hogareño.</p>
  <h4>Texturas suaves y repetitivas</h4>
  <p>La manta ofrece una gran superficie para practicar patrones repetitivos. Los niños pueden colorear cada estrella de un color diferente o usar un solo tono de fondo suave (celeste, lavanda) para que el perrito resalte por contraste.</p>
  <h4>Tips para el cachorro</h4>
  <p>Para que el perrito se vea esponjoso, sugerimos colores crema o café claro. Dejar la punta de la cola en blanco o pintar sus almohadillas de rosa suave le dará un aspecto extra adorable que encantará a los más pequeños.</p>
  <h4>Fomento de la serenidad</h4>
  <p>Pintar escenas de descanso tiene un efecto calmante probado. Esta lámina es perfecta para sesiones de coloreado relajantes antes de la siesta o para momentos en los que se busca reducir la hiperactividad infantil a través del arte.</p>', 'perro para colorear, cachorro durmiendo, mascotas para pintar, dibujo de perrito fácil, colorear animales domésticos.', 'dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear', 1, NULL, '2026-02-24T00:45:19.417Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280081/coloring-web/animales/dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear.webp', 'coloring-web/animales/dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
