INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (476, 'Princesa en la playa para colorear | Dibujo veraniego infantil con mar', 'princesa-en-la-playa-para-colorear-or-dibujo-veraniego-infantil-con-mar', 'Princesa en la playa con arena y mar de fondo, dibujo lineal para colorear.', '<h3>Una princesa en un entorno diferente</h3> <p>Esta escena lleva a la princesa fuera del castillo y la sitúa en la playa, rodeada de arena y mar. Es una propuesta fresca que combina fantasía con un ambiente cotidiano y cercano.</p> <h3>Explorando paisajes naturales</h3> <p>El mar, las olas y la arena ofrecen una oportunidad ideal para trabajar elementos de la naturaleza en un contexto simple pero atractivo.</p> <h3>Colores del verano</h3> <p>Los tonos azules del agua, el beige de la arena y los colores cálidos del sol permiten crear una composición alegre y luminosa.</p> <h3>Relajación y creatividad</h3> <p>Este dibujo transmite tranquilidad, siendo perfecto para momentos de descanso mientras se estimula la imaginación.</p>', 'princesa playa, verano infantil, mar, arena, dibujo relajante, vacaciones, fantasía, princesa exterior, sol, ilustración niños, paisaje marino, actividad creativa, dibujo simple, naturaleza, colorear', 'princesa-en-la-playa-para-colorear-or-dibujo-veraniego-infantil-con-mar', 8, NULL, '2026-04-01T18:09:05.975Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056145/coloring-web/princesas/princesa-en-la-playa-para-colorear-or-dibujo-veraniego-infantil-con-mar.webp', 'coloring-web/princesas/princesa-en-la-playa-para-colorear-or-dibujo-veraniego-infantil-con-mar') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
