INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (477, 'Princesa en ciudad medieval para colorear | Dibujo detallado de época', 'princesa-en-ciudad-medieval-para-colorear-or-dibujo-detallado-de-epoca', 'Princesa en una ciudad medieval con edificios antiguos, ilustración para colorear.', '<h3>Un recorrido por la historia</h3> <p>La princesa se encuentra en una ciudad medieval rodeada de construcciones antiguas, lo que permite introducir a los niños en un contexto histórico de forma visual y entretenida.</p> <h3>Detalles arquitectónicos</h3> <p>Las casas, torres y calles aportan complejidad al dibujo, ideal para quienes buscan un desafío mayor al colorear.</p> <h3>Paleta inspirada en la época</h3> <p>Se pueden utilizar tonos tierra, grises y marrones para representar los materiales típicos de la época.</p> <h3>Aprendizaje a través del arte</h3> <p>Este tipo de ilustraciones combina creatividad con conocimiento histórico básico.</p>', 'princesa medieval, ciudad antigua, arquitectura medieval, fantasía histórica, castillos, dibujo detallado, ilustración infantil, época medieval, arte educativo, edificios antiguos, colorear historia, creatividad, reino, escena urbana, niños', 'princesa-en-ciudad-medieval-para-colorear-or-dibujo-detallado-de-epoca', 4, NULL, '2026-04-01T18:09:46.541Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056185/coloring-web/profesiones-oficios/princesa-en-ciudad-medieval-para-colorear-or-dibujo-detallado-de-epoca.webp', 'coloring-web/profesiones-oficios/princesa-en-ciudad-medieval-para-colorear-or-dibujo-detallado-de-epoca') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinar