INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (95, 'Dibujo para colorear castillo protegido por dragón guardián', 'dibujo-para-colorear-castillo-protegido-por-dragon-guardian', 'Dragón vigilando un castillo medieval para colorear.', '<p>La aventura épica cobra vida con este dragón que custodia las murallas del castillo. No siempre son villanos; en esta escena, el dragón actúa como un guardián poderoso que protege el reino de cualquier peligro externo.</p>
  <h4>Escamas y texturas de fantasía</h4>
  <p>El cuerpo del dragón ofrece una oportunidad única para practicar texturas. Los niños pueden colorear sus escamas con verdes, rojos o incluso colores dorados, mientras usan grises sólidos para las murallas de piedra del castillo.</p>
  <h4>Contraste de escalas</h4>
  <p>Al ver el tamaño del dragón comparado con las puertas del castillo, los niños desarrollan la noción de proporción. Es un dibujo emocionante que mantiene la atención gracias a la mezcla de elementos vivos y estructuras arquitectónicas.</p>', 'dragón guardián, castillo medieval, criatura fantástica, alas grandes, fuego, fantasía épica, reino mágico', 'dibujo-para-colorear-castillo-protegido-por-dragon-guardian', 2, NULL, '2026-02-27T01:51:38.031Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280162/coloring-web/fantasia/dibujo-para-colorear-castillo-protegido-por-dragon-guardian.webp', 'coloring-web/fantasia/dibujo-para-colorear-castillo-protegido-por-dragon-guardian') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
