INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (118, 'Dibujo para colorear unicornio tierno con hada amiga', 'dibujo-para-colorear-unicornio-tierno-con-hada-amiga', 'Unicornio acompañado por un hada en una escena mágica para colorear.', 'Un dibujo detallado de Dibujo para colorear unicornio tierno con hada amiga, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'unicornio, hada, amistad mágica, fantasía infantil, criaturas mágicas, arcoíris, bosque encantado', 'dibujo-para-colorear-unicornio-tierno-con-hada-amiga', 2, NULL, '2026-02-27T02:11:30.601Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280189/coloring-web/fantasia/dibujo-para-colorear-unicornio-tierno-con-hada-amiga.webp', 'coloring-web/fantasia/dibujo-para-colorear-unicornio-tierno-con-hada-amiga') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (130, 'Dibujo para colorear astronauta sentado en la Luna', 'dibujo-para-colorear-astronauta-sentado-en-la-luna', 'Astronauta sentado sobre una roca lunar para colorear.', '<p>Incluso en la Luna hay tiempo para descansar. Esta pacífica ilustración muestra al astronauta sentado tranquilamente en una roca, observando el vasto paisaje lunar antes de continuar con su misión de exploración.</p>
  <h4>Momentos de calma y paz</h4>
  <p>A diferencia de los dibujos de acción, esta escena transmite serenidad. Es perfecta para sesiones de coloreado relajantes antes de dormir o para momentos en los que se busca reducir la hiperactividad a través del arte.</p>
  <h4>Tips de sombreado lunar</h4>
  <p>Al ser una pose estática, es el momento ideal para practicar las sombras. Sugerimos pintar una sombra ovalada oscura bajo el astronauta para darle peso y volumen a la figura, evitando que parezca que está "flotando".</p>
  <h4>Auto-reflexión creativa</h4>
  <p>Pintar un personaje en reposo invita al niño a calmar su propio ritmo. Ayuda a desarrollar la introspección y permite que el proceso artístico sea una forma de meditación guiada por la forma y el color.</p>', 'astronauta, luna, descanso espacial, cráter, espacio', 'dibujo-para-colorear-astronauta-sentado-en-la-luna', 3, NULL, '2026-03-04T02:29:59.350Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280196/coloring-web/espacio/dibujo-para-colorear-astronauta-sentado-en-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-sentado-en-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (281, 'Dibujo para colorear rover espacial explorando la Luna', 'dibujo-para-colorear-rover-espacial-explorando-la-luna', 'Dibujo para colorear rover espacial explorando la Luna', 'Un dibujo detallado de Dibujo para colorear rover espacial explorando la Luna, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'rover espacial, vehículo espacial, exploración lunar, luna, espacio, robot espacial, exploración del espacio, vehículo de ciencia', 'dibujo-para-colorear-rover-espacial-explorando-la-luna', 5, NULL, '2026-03-12T02:11:18.751Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280389/coloring-web/vehiculos/dibujo-para-colorear-rover-espacial-explorando-la-luna.webp', 'coloring-web/vehiculos/dibujo-para-colorear-rover-espacial-explorando-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (124, 'Dibujo para colorear astronauta mirando el horizonte en la Luna', 'dibujo-para-colorear-astronauta-mirando-el-horizonte-en-la-luna', 'Astronauta observando el horizonte lunar para colorear.', '<p>Esta es una de nuestras láminas más contemplativas. El astronauta se detiene en el borde de un gran cráter para observar el horizonte lunar, un paisaje vasto y silencioso donde nuestro planeta azul brilla con fuerza en la distancia.</p>
  <h4>Perspectiva y profundidad lunar</h4>
  <p>El dibujo juega con la escala: la inmensidad del cráter frente a la figura humana. Ayuda a los niños a entender la profundidad, coloreando las paredes del cráter con diferentes intensidades de gris para crear volumen.</p>
  <h4>Sugerencias de textura y luz</h4>
  <p>Para las colinas lunares, el uso de trazos irregulares y sombras marcadas simulará el relieve escarpado. Dejar la cima de algunas rocas en blanco dará sensación de luz solar intensa sobre la superficie polvorienta.</p>
  <h4>Asombro ante el universo</h4>
  <p>Este dibujo celebra el sentido de la maravilla. Fomenta en los niños la capacidad de asombro ante la belleza del cosmos y la importancia de proteger nuestro frágil hogar, la Tierra, vista desde fuera.</p>', 'astronauta, luna, horizonte lunar, espacio, traje espacial, exploración espacial, estrellas', 'dibujo-para-colorear-astronauta-mirando-el-horizonte-en-la-luna', 3, NULL, '2026-03-03T03:19:08.334Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280208/coloring-web/espacio/dibujo-para-colorear-astronauta-mirando-el-horizonte-en-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-mirando-el-horizonte-en-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
