INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (478, 'Princesa con vestido simple para colorear | Dibujo fácil y limpio', 'princesa-con-vestido-simple-para-colorear-or-dibujo-facil-y-limpio', 'Princesa con vestido simple y pocos detalles, ilustración infantil para colorear.', '<h3>Simplicidad que facilita el aprendizaje</h3> <p>El diseño presenta una princesa con un vestido sin demasiados detalles, ideal para quienes están comenzando a colorear.</p> <h3>Enfoque en las formas principales</h3> <p>Permite identificar fácilmente cada parte del dibujo, ayudando al desarrollo de habilidades básicas.</p> <h3>Libertad creativa total</h3> <p>Al no tener muchos detalles, los niños pueden agregar sus propios diseños.</p> <h3>Actividad accesible</h3> <p>Perfecto para edades tempranas o momentos de práctica.</p>', 'princesa simple, vestido básico, dibujo fácil, infantil, colorear niños, arte simple, fantasía, ilustración clara, creatividad, actividad básica, princesa sencilla, aprendizaje, dibujo limpio, fácil, niños pequeños', 'princesa-con-vestido-simple-para-colorear-or-dibujo-facil-y-limpio', 8, NULL, '2026-04-01T18:10:16.435Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056215/coloring-web/princesas/princesa-con-vestido-simple-para-colorear-or-dibujo-facil-y-limpio.webp', 'coloring-web/princesas/princesa-con-vestido-simple-para-colorear-or-dibujo-facil-y-limpio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (133, 'Dibujo para colorear cohete lanzándose hacia la Luna', 'dibujo-para-colorear-cohete-lanzandose-hacia-la-luna', 'Cohete despegando rumbo al espacio con humo.', '<p>Esta dinámica ilustración captura el momento exacto del despegue, donde la fuerza de los motores impulsa a la nave fuera de la atmósfera terrestre. Con la Luna esperando en el horizonte, este dibujo representa el espíritu de exploración y el deseo humano de alcanzar las estrellas.</p>
  <h4>Fuego y propulsión</h4>
  <p>La base del cohete muestra grandes nubes de fuego y humo. Es una oportunidad fantástica para que los niños experimenten con degradados de rojo, naranja y amarillo vibrante, creando un efecto de luz y calor que resalte sobre el fondo oscuro del espacio.</p>
  <h4>Velocidad hacia el satélite</h4>
  <p>Sugerimos pintar la Luna con tonos grises y cráteres detallados, mientras que el cuerpo del cohete puede llevar colores metálicos. Este dibujo ayuda a comprender conceptos de física básica, como el empuje y la dirección necesaria para viajar por el cosmos.</p>', 'cohete, lanzamiento, luna, humo, plataforma espacial', 'dibujo-para-colorear-cohete-lanzandose-hacia-la-luna', 3, NULL, '2026-03-04T02:31:07.959Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280214/coloring-web/espacio/dibujo-para-colorear-cohete-lanzandose-hacia-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-cohete-lanzandose-hacia-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
