INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (479, 'Princesa con pastel para colorear | Dibujo dulce y divertido infantil', 'princesa-con-pastel-para-colorear-or-dibujo-dulce-y-divertido-infantil', 'Princesa sosteniendo un pastel decorado, ilustración en blanco y negro para colorear.', '<h3>Una escena llena de dulzura</h3> <p>La princesa aparece con un pastel, creando una imagen asociada a celebraciones y momentos felices como cumpleaños o fiestas.</p> <h3>Detalles decorativos atractivos</h3> <p>El pastel permite trabajar elementos como capas, decoraciones y formas.</p> <h3>Colores apetitosos</h3> <p>Se pueden usar tonos como rosa, chocolate o crema para dar vida al dibujo.</p> <h3>Conexión con experiencias reales</h3> <p>Los niños pueden relacionar la escena con sus propias celebraciones.</p>', 'princesa pastel, comida dulce, dibujo infantil, torta, celebración, fantasía, cumpleaños, arte para colorear, ilustración divertida, niños, dulce, creatividad, cocina, princesa feliz, actividad', 'princesa-con-pastel-para-colorear-or-dibujo-dulce-y-divertido-infantil', 8, NULL, '2026-04-01T18:10:59.813Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056258/coloring-web/princesas/princesa-con-pastel-para-colorear-or-dibujo-dulce-y-divertido-infantil.webp', 'coloring-web/princesas/princesa-con-pastel-para-colorear-or-dibujo-dulce-y-divertido-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
