INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (155, 'Dibujo para colorear arquitecto civil en obra', 'dibujo-para-colorear-arquitecto-civil-en-obra', 'Dibujo para colorear arquitecto civil en obra', '<p>En esta lámina vemos al arquitecto en plena acción, trabajando directamente en el lugar de la construcción. Equipado con su casco de seguridad y chaleco reflectante, es la figura clave para que los planos se conviertan en realidad.</p>
  <h4>Seguridad y detalle laboral</h4>
  <p>El dibujo incluye elementos de protección personal (EPP), lo que permite enseñar a los niños la importancia de la seguridad en el trabajo. El fondo con vigas y estructuras en proceso añade un nivel de detalle fascinante.</p>
  <h4>Guía de colores de seguridad</h4>
  <p>Recomendamos pintar el casco de blanco o amarillo y el chaleco con un naranja o verde neón. Estos colores de alta visibilidad son fundamentales en una obra y hacen que la figura del arquitecto destaque sobre el fondo grisáceo de la construcción.</p>
  <h4>Visión de futuro</h4>
  <p>Este dibujo ayuda a los niños a visualizar cómo es el día a día de un arquitecto civil. Fomenta el respeto por las carreras técnicas y la importancia de la supervisión y el trabajo bien hecho en la creación de edificios.</p>', 'Arquitecto civil con casco en sitio de construcción', 'dibujo-para-colorear-arquitecto-civil-en-obra', 4, NULL, '2026-03-07T00:26:27.803Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280242/coloring-web/profesiones-oficios/dibujo-para-colorear-arquitecto-civil-en-obra.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-arquitecto-civil-en-obra') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (159, 'Dibujo para colorear bailarina clásica', 'dibujo-para-colorear-bailarina-clasica', 'Bailarina de ballet en pose elegante', '<p>La elegancia y la disciplina del ballet se resumen en esta delicada figura. Con su tutú, sus zapatillas de punta y una pose grácil, esta bailarina es un homenaje a la expresión artística a través del cuerpo y el movimiento.</p>
  <h4>Texturas de tul y satén</h4>
  <p>El tutú ofrece una oportunidad fantástica para practicar trazos suaves y ligeros. Los niños pueden usar colores pastel como el rosa, lavanda o blanco, dejando zonas con menos presión para simular la transparencia de la tela.</p>
  <h4>Expresión y postura</h4>
  <p>Al colorear los brazos y piernas en extensión, los niños aprenden sobre la anatomía y el equilibrio. Es un dibujo que fomenta la sensibilidad estética y el respeto por las artes escénicas tradicionales.</p>', 'bailarina, ballet, danza, arte, profesión artística', 'dibujo-para-colorear-bailarina-clasica', 4, NULL, '2026-03-07T00:29:35.676Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280245/coloring-web/profesiones-oficios/dibujo-para-colorear-bailarina-clasica.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-bailarina-clasica') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (158, 'Ilustración infantil de una azafata saludando a los pasajeros dentro de un avión.', 'ilustracion-infantil-de-una-azafata-saludando-a-los-pasajeros-dentro-de-un-avion', 'Azafata sonriendo con avión de fondo', 'Un dibujo detallado de Ilustración infantil de una azafata saludando a los pasajeros dentro de un avión., diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'azafata, vuelo, avión, tripulación, profesión, transporte aéreo', 'ilustracion-infantil-de-una-azafata-saludando-a-los-pasajeros-dentro-de-un-avion', 4, NULL, '2026-03-07T00:29:15.681Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280244/coloring-web/profesiones-oficios/ilustracion-infantil-de-una-azafata-saludando-a-los-pasajeros-dentro-de-un-avion.webp', 'coloring-web/profesiones-oficios/ilustracion-infantil-de-una-azafata-saludando-a-los-pasajeros-dentro-de-un-avion') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (480, 'Princesa con osito de peluche para colorear | Dibujo tierno infantil', 'princesa-con-osito-de-peluche-para-colorear-or-dibujo-tierno-infantil', 'Princesa abrazando un osito de peluche, ilustración simple para colorear.', '<h3>Compañía y ternura</h3> <p>El osito de peluche acompaña a la princesa, generando una escena cálida y afectiva.</p> <h3>Elemento familiar</h3> <p>Los juguetes son parte del mundo cotidiano de los niños.</p> <h3>Colores suaves</h3> <p>Se recomiendan tonos cálidos para transmitir ternura.</p> <h3>Vínculo emocional</h3> <p>Fomenta la conexión afectiva y la imaginación.</p>', 'princesa peluche, osito, dibujo tierno, infancia, juguete, fantasía, arte infantil, ilustración adorable, niños, cariño, creatividad, dibujo simple, ternura, actividad, colorear', 'princesa-con-osito-de-peluche-para-colorear-or-dibujo-tierno-infantil', 8, NULL, '2026-04-01T18:11:30.824Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056289/coloring-web/princesas/princesa-con-osito-de-peluche-para-colorear-or-dibujo-tierno-infantil.webp', 'coloring-web/princesas/princesa-con-osito-de-peluche-para-colorear-or-dibujo-tierno-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (176, 'Dibujo para colorear cocinero con gorro alto', 'dibujo-para-colorear-cocinero-con-gorro-alto', 'Cocinero profesional con gorro alto sonriendo', '<p>La figura clásica del chef aparece en esta ilustración con su icónico gorro de pliegues. Esta vestimenta no es solo tradición; representa la limpieza y el rango dentro de una cocina profesional, inspirando el respeto por el arte culinario.</p>
  <h4>Higiene y profesión</h4>
  <p>Este dibujo es una base excelente para hablar sobre la importancia de la higiene al manipular alimentos. El cocinero luce su delantal impecable, invitando a los niños a valorar el esfuerzo que hay detrás de cada plato que llega a la mesa.</p>
  <h4>Sombras y volumen blanco</h4>
  <p>Colorear una figura mayoritariamente blanca es un reto de dibujo avanzado. Se pueden usar grises muy claros o violetas pálidos para marcar las arrugas de la chaqueta y los pliegues del gorro, dándole tridimensionalidad al personaje.</p>', 'cocinero, gorro de chef, cocina, profesión culinaria', 'dibujo-para-colorear-cocinero-con-gorro-alto', 4, NULL, '2026-03-07T00:47:24.966Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280265/coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-con-gorro-alto.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-con-gorro-alto') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (175, 'Dibujo para colorear cocinero en cocina profesional', 'dibujo-para-colorear-cocinero-en-cocina-profesional', 'Cocinero trabajando en cocina con utensilios', '<p>Esta lámina nos introduce en el corazón de un restaurante. Entre fogones, campanas extractoras y ollas humeantes, el cocinero dirige la creación de recetas deliciosas en un entorno lleno de ritmo y sabor.</p>
  <h4>Maquinaria de hostelería</h4>
  <p>El dibujo incluye elementos de acero inoxidable como estufas y hornos. Los niños pueden practicar el coloreado de superficies metálicas usando reflejos grises y blancos, entendiendo cómo se equipa una cocina industrial moderna.</p>
  <h4>Ambiente y vapor</h4>
  <p>Las líneas de vapor saliendo de las ollas permiten usar trazos suaves y ondulados. Es un dibujo rico en detalles que mantiene entretenidos a los niños mientras exploran la complejidad de una de las profesiones más queridas del mundo.</p>', 'cocinero, cocina profesional, utensilios, gastronomía', 'dibujo-para-colorear-cocinero-en-cocina-profesional', 4, NULL, '2026-03-07T00:47:02.719Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280264/coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-en-cocina-profesional.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-en-cocina-profesional') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (169, 'Dibujo para colorear cartero entregando cartas', 'dibujo-para-colorear-cartero-entregando-cartas', 'Cartero con bolsa de cartas repartiendo correspondencia', '<p>El cartero es un vínculo vital en nuestra comunidad, encargado de llevar mensajes, paquetes y noticias a cada hogar. Este dibujo captura la amabilidad de un servicio que recorre las calles cada día, haga sol o llueva.</p>
  <h4>Comunicación y servicio público</h4>
  <p>La ilustración muestra al cartero junto a un buzón o la puerta de una casa. Es ideal para que los niños aprendan sobre el sistema postal y valoren a los trabajadores que mantienen conectadas a las personas mediante el papel.</p>
  <h4>Colores de uniforme</h4>
  <p>Dependiendo del país, los uniformes varían entre azul, amarillo o rojo. Los niños pueden elegir el color que ven en su propia ciudad, personalizando el dibujo y sintiéndose parte de su entorno cotidiano.</p>', 'cartero, cartas, correo, profesión, dibujo infantil', 'dibujo-para-colorear-cartero-entregando-cartas', 4, NULL, '2026-03-07T00:39:14.051Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280258/coloring-web/profesiones-oficios/dibujo-para-colorear-cartero-entregando-cartas.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cartero-entregando-cartas') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
