INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (239, 'Dibujo para colorear veterinario con mascota', 'dibujo-para-colorear-veterinario-con-mascota', 'Veterinario revisando un perro', 'Un dibujo detallado de Dibujo para colorear veterinario con mascota, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'veterinario, animales, mascota, doctor de animales, profesión', 'dibujo-para-colorear-veterinario-con-mascota', 4, NULL, '2026-03-07T01:27:25.194Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280336/coloring-web/profesiones-oficios/dibujo-para-colorear-veterinario-con-mascota.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-veterinario-con-mascota') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (242, 'Dibujo para colorear apisonadora de rodillo', 'dibujo-para-colorear-apisonadora-de-rodillo', 'Apisonadora de rodillo trabajando', '<p>Esta ilustración se centra en la función principal de esta máquina: aplanar y compactar el suelo. El gran rodillo delantero es el protagonista, mostrando la potencia necesaria para preparar el terreno donde luego caminaremos.</p>
  <h4>Texturas de asfalto y tierra</h4>
  <p>El dibujo permite practicar texturas rugosas. Los niños pueden colorear la parte del suelo que ya ha sido pisada por el rodillo con un gris liso, y la parte delantera con motas marrones para simular la tierra suelta antes de ser compactada.</p>
  <h4>Tips para la maquinaria</h4>
  <p>Las apisonadoras suelen ser amarillas o naranjas para ser visibles en las obras. Recomendamos usar un color muy saturado para el cuerpo y un gris acero para el rodillo, creando un contraste de materiales muy interesante.</p>
  <h4>Coordinación y trazo curvo</h4>
  <p>El gran cilindro delantero requiere un trazo circular firme y controlado. Colorear superficies curvas de gran tamaño ayuda a mejorar la fluidez del movimiento del brazo y la muñeca en los pequeños artistas.</p>', 'pisonadora, rodillo compactador, maquinaria pesada, construcción, obra, pavimento, ingeniería civil, maquinaria de obra, vehículo de construcción', 'dibujo-para-colorear-apisonadora-de-rodillo', 5, NULL, '2026-03-12T00:49:25.263Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280339/coloring-web/vehiculos/dibujo-para-colorear-apisonadora-de-rodillo.webp', 'coloring-web/vehiculos/dibujo-para-colorear-apisonadora-de-rodillo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (292, 'Dibujo para colorear tren de vapor pasando por la granja', 'dibujo-para-colorear-tren-de-vapor-pasando-por-la-granja', 'Tren de vapor pasando por un paisaje rural', 'Un dibujo detallado de Dibujo para colorear tren de vapor pasando por la granja, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'tren de vapor, tren antiguo, locomotora clásica, granja, campo, ferrocarril', 'dibujo-para-colorear-tren-de-vapor-pasando-por-la-granja', 5, NULL, '2026-03-12T02:27:08.443Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280403/coloring-web/vehiculos/dibujo-para-colorear-tren-de-vapor-pasando-por-la-granja.webp', 'coloring-web/vehiculos/dibujo-para-colorear-tren-de-vapor-pasando-por-la-granja') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (249, 'Dibujo para colorear avioneta sobre la granja', 'dibujo-para-colorear-avioneta-sobre-la-granja', 'Avioneta volando sobre una granja en el campo', '<p>Una estampa rural clásica donde una pequeña avioneta sobrevuela un paisaje de granero, animales y cultivos. Es una mezcla perfecta entre maquinaria aérea y vida en el campo, ideal para trabajar diferentes temáticas en una sola página.</p>
  <h4>Contraste entre aire y tierra</h4>
  <p>Esta lámina ofrece la oportunidad de usar colores tierra (marrones y ocres) para la granja y colores vibrantes para la avioneta. Ayuda a los niños a diferenciar planos visuales: lo que está arriba volando y lo que está abajo en el suelo.</p>
  <h4>Creatividad en los cultivos</h4>
  <p>Los campos de cultivo se pueden pintar con patrones de líneas verdes y amarillas, simulando filas de maíz o trigo. Esto añade una textura rítmica al dibujo que resulta muy relajante y visualmente atractiva.</p>', 'avioneta, avión pequeño, granja, campo, aviación ligera, vuelo, aeronave, transporte aéreo pequeño', 'dibujo-para-colorear-avioneta-sobre-la-granja', 5, NULL, '2026-03-12T00:52:27.939Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280348/coloring-web/vehiculos/dibujo-para-colorear-avioneta-sobre-la-granja.webp', 'coloring-web/vehiculos/dibujo-para-colorear-avioneta-sobre-la-granja') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (250, 'Dibujo para colorear avión volando sobre la costa', 'dibujo-para-colorear-avion-volando-sobre-la-costa', 'Avión volando sobre el mar cerca de la costa', '<p>La libertad del vuelo se aprecia en esta vista costera donde un avión atraviesa el cielo sobre el mar y la playa. Es una composición refrescante que invita a soñar con las vacaciones y la naturaleza marina.</p>
  <h4>Mezcla de paisajes naturales</h4>
  <p>El reto aquí es combinar el azul del océano con el turquesa de la orilla y el dorado de la arena. Colorear el agua salpicando contra la costa ayuda a practicar trazos curvos y fluidos, contrastando con las líneas rectas del avión.</p>
  <h4>Efectos de altitud</h4>
  <p>Sugerimos usar colores más suaves para la costa para simular que el avión está a mucha altura. Este efecto de "lejanía" es un excelente ejercicio de percepción espacial para los pequeños artistas en crecimiento.</p>', 'avión, costa, mar, aviación, transporte aéreo, vuelo, paisaje costero, aeronave', 'dibujo-para-colorear-avion-volando-sobre-la-costa', 5, NULL, '2026-03-12T00:52:54.147Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280349/coloring-web/vehiculos/dibujo-para-colorear-avion-volando-sobre-la-costa.webp', 'coloring-web/vehiculos/dibujo-para-colorear-avion-volando-sobre-la-costa') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (253, 'Dibujo para colorear bulldozer en obra de construcción', 'dibujo-para-colorear-bulldozer-en-obra-de-construccion', 'Bulldozer moviendo tierra en una obra de construcción', '<p>La fuerza bruta de la ingeniería civil se muestra en este potente bulldozer o niveladora. Con su gran pala frontal, esta máquina es la encargada de mover grandes cantidades de tierra para preparar los cimientos de nuevos edificios.</p>
  <h4>Geometría de maquinaria pesada</h4>
  <p>El bulldozer está compuesto por formas cuadradas y líneas rectas muy marcadas. Es una oportunidad fantástica para que los niños practiquen la rectitud en el trazo y comprendan cómo las máquinas usan palancas para multiplicar su fuerza.</p>
  <h4>Sugerencia de texturas rugosas</h4>
  <p>Anima a los niños a usar marrones oscuros y grises para la zona de tierra y orugas de la máquina. Un amarillo industrial para la carrocería hará que la máquina destaque como la reina de la obra de construcción.</p>', 'bulldozer, maquinaria pesada, construcción, obra, excavación, ingeniería civil, máquina de construcción, movimiento de tierra', 'dibujo-para-colorear-bulldozer-en-obra-de-construccion', 5, NULL, '2026-03-12T00:54:08.099Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280353/coloring-web/vehiculos/dibujo-para-colorear-bulldozer-en-obra-de-construccion.webp', 'coloring-web/vehiculos/dibujo-para-colorear-bulldozer-en-obra-de-construccion') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (256, 'Dibujo para colorear camión de bomberos en la ciudad', 'dibujo-para-colorear-camion-de-bomberos-en-la-ciudad', 'Camión de bomberos circulando por una calle de la ciudad', '<p>El camión recorre las avenidas entre edificios y semáforos. Esta escena urbana pone al vehículo en movimiento, recreando la urgencia y el sonido de las sirenas que resuenan entre las calles de una gran metrópoli.</p>
  <h4>Entorno urbano detallado</h4>
  <p>El fondo con edificios permite practicar la perspectiva lineal. Los niños pueden colorear las ventanas de los rascacielos y el asfalto de la calle, creando un contexto realista para la misión de los bomberos.</p>
  <h4>Dinamismo y velocidad</h4>
  <p>Sugerimos usar trazos horizontales rápidos en el fondo para simular que el camión va a gran velocidad. El contraste entre el rojo del vehículo y el gris de la ciudad hace que la imagen sea vibrante y llena de energía.</p>', 'camión de bomberos, ciudad, emergencia, incendio, rescate, sirena, bomberos, vehículo de rescate', 'dibujo-para-colorear-camion-de-bomberos-en-la-ciudad', 5, NULL, '2026-03-12T01:56:10.559Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280357/coloring-web/vehiculos/dibujo-para-colorear-camion-de-bomberos-en-la-ciudad.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-de-bomberos-en-la-ciudad') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (264, 'Dibujo para colorear coche de policía en la ciudad', 'dibujo-para-colorear-coche-de-policia-en-la-ciudad', 'Auto de policía patrullando una calle de la ciudad', '<p>El coche de policía recorre las calles de la metrópoli garantizando la seguridad de todos los ciudadanos. Rodeado de edificios, semáforos y pasos de cebra, este vehículo es un símbolo de orden y protección en el entorno urbano cotidiano.</p>
  <h4>Educación vial y entorno</h4>
  <p>El fondo detallado de la ciudad permite practicar la perspectiva. Es una lámina ideal para conversar con los niños sobre las normas de tráfico y el papel de los agentes de policía como figuras de ayuda en la comunidad.</p>
  <h4>Luces de emergencia</h4>
  <p>Las sirenas del techo son el elemento clave. Un truco artístico es pintar haces de luz azules y rojos que salgan del coche, haciendo que la escena parezca estar en plena acción de patrullaje nocturno o diurno.</p>', 'coche de policía, patrulla policial, ciudad, seguridad, policía, vehículo de emergencia', 'dibujo-para-colorear-coche-de-policia-en-la-ciudad', 5, NULL, '2026-03-12T02:00:10.485Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280368/coloring-web/vehiculos/dibujo-para-colorear-coche-de-policia-en-la-ciudad.webp', 'coloring-web/vehiculos/dibujo-para-colorear-coche-de-policia-en-la-ciudad') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
