INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (274, 'Dibujo para colorear metro subterráneo en estación', 'dibujo-para-colorear-metro-subterraneo-en-estacion', 'Tren de metro detenido en una estación', 'Un dibujo detallado de Dibujo para colorear metro subterráneo en estación, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'metro, tren subterráneo, transporte público, estación de metro, ciudad, transporte urbano, tren', 'dibujo-para-colorear-metro-subterraneo-en-estacion', 5, NULL, '2026-03-12T02:04:54.936Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280380/coloring-web/vehiculos/dibujo-para-colorear-metro-subterraneo-en-estacion.webp', 'coloring-web/vehiculos/dibujo-para-colorear-metro-subterraneo-en-estacion') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (261, 'Dibujo para colorear camión mezclador de cemento', 'dibujo-para-colorear-camion-mezclador-de-cemento', 'Camión hormigonera mezclando cemento en una obra', '<p>Ninguna gran construcción estaría completa sin este vehículo. El camión mezclador posee un enorme tambor giratorio que mantiene el hormigón fresco y en movimiento hasta que llega a la obra para formar suelos y paredes resistentes.</p>
  <h4>Movimiento y volumen</h4>
  <p>El tambor central es el protagonista de esta lámina. Al ser una forma cilíndrica grande, es ideal para que los niños practiquen el sombreado curvo, usando un gris más oscuro en la base para darle volumen y realismo a la máquina.</p>
  <h4>Detalles de construcción</h4>
  <p>Recomendamos colorear la cabina de un color brillante y el tambor de un color neutro. Añadir pequeñas salpicaduras de gris claro alrededor de la tolva trasera simulará que el camión está trabajando activamente en una obra.</p>', 'camión mezclador, hormigonera, cemento, construcción, obra, maquinaria pesada, ingeniería civil', 'dibujo-para-colorear-camion-mezclador-de-cemento', 5, NULL, '2026-03-12T01:59:00.636Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280363/coloring-web/vehiculos/dibujo-para-colorear-camion-mezclador-de-cemento.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-mezclador-de-cemento') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
