INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (92, 'Dibujo para colorear castillo mágico en la colina', 'dibujo-para-colorear-castillo-magico-en-la-colina', 'Dibujo de un castillo en lo alto de una colina con camino para colorear.', '<p>Elevándose sobre las nubes, este castillo de altas torres y banderas ondeantes es el escenario de mil leyendas. Situado en lo alto de una colina, representa el refugio de reyes, reinas y personajes de cuentos de hadas.</p>
  <h4>Fantasía y arquitectura épica</h4>
  <p>Este dibujo permite trabajar con muchas cúpulas y ventanas. Los niños pueden imaginar que cada torre tiene una función mágica diferente, usando colores poco comunes como el lila o el azul cielo para las piedras del castillo.</p>
  <h4>Detalles del paisaje</h4>
  <p>Recomendamos pintar el camino que sube por la colina con tonos piedra y el césped de un verde intenso. Añadir un arcoíris o nubes coloridas alrededor de las torres potenciará el efecto de "lugar fantástico" y mágico.</p>', 'castillo, torre medieval, reino mágico, princesa, cuento de hadas, paisaje fantástico, arquitectura antigua, fantasía infantil', 'dibujo-para-colorear-castillo-magico-en-la-colina', 2, NULL, '2026-02-27T00:23:00.445Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280161/coloring-web/fantasia/dibujo-para-colorear-castillo-magico-en-la-colina.webp', 'coloring-web/fantasia/dibujo-para-colorear-castillo-magico-en-la-colina') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
