INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (116, 'Dibujo para colorear torre mágica con luna sonriente', 'dibujo-para-colorear-torre-magica-con-luna-sonriente', 'Torre encantada iluminada por una luna sonriente para colorear.', 'Un dibujo detallado de Dibujo para colorear torre mágica con luna sonriente, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'torre mágica, luna sonriente, castillo, noche, fantasía infantil, cielo estrellado', 'dibujo-para-colorear-torre-magica-con-luna-sonriente', 2, NULL, '2026-02-27T02:10:44.909Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280187/coloring-web/fantasia/dibujo-para-colorear-torre-magica-con-luna-sonriente.webp', 'coloring-web/fantasia/dibujo-para-colorear-torre-magica-con-luna-sonriente') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (129, 'Dibujo para colorear astronauta saludando desde la Luna', 'dibujo-para-colorear-astronauta-saludando-desde-la-luna', 'Astronauta saludando sobre la superficie lunar para colorear.', '<p>¡Hola desde el espacio! En esta amigable ilustración, el astronauta nos saluda con entusiasmo con su mano en alto, posando en la superficie lunar antes de continuar con su misión de descubrimiento.</p>
  <h4>Conexión y alegría espacial</h4>
  <p>Al tener al personaje saludando, el dibujo humaniza la figura del explorador. Invita a los niños a imaginar que están recibiendo un mensaje de texto o video directo desde la Luna, creando un vínculo emocional con la ciencia.</p>
  <h4>Sugerencias de color</h4>
  <p>Recomendamos usar un blanco brillante para el traje y un tono gris suave para el suelo. Un pequeño detalle de color en el casco, como un reflejo amarillo suave, le dará un aspecto tierno y amigable que encantará a los más pequeños.</p>
  <h4>Iniciación a la astronomía</h4>
  <p>Este tipo de dibujos simplificados son la puerta de entrada perfecta al mundo del espacio. Fomentan la confianza del niño al permitirle terminar una obra completa de forma rápida y con un resultado muy satisfactorio.</p>', 'astronauta, luna, saludo, misión espacial, exploración', 'dibujo-para-colorear-astronauta-saludando-desde-la-luna', 3, NULL, '2026-03-04T02:29:35.477Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280195/coloring-web/espacio/dibujo-para-colorear-astronauta-saludando-desde-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-saludando-desde-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (481, 'Princesa con globos para colorear | Dibujo festivo y alegre', 'princesa-con-globos-para-colorear-or-dibujo-festivo-y-alegre', 'Princesa sosteniendo varios globos flotando a su alrededor, ilustración infantil en blanco y negro para colorear.', '<h3>Una escena llena de alegría y movimiento</h3> <p>La presencia de globos transforma este dibujo en una representación clara de celebración y diversión. La princesa aparece rodeada de elementos que transmiten ligereza y dinamismo, generando una imagen visualmente atractiva que conecta rápidamente con situaciones felices como cumpleaños, fiestas o eventos especiales.</p> <h3>Exploración de formas y volúmenes</h3> <p>Los globos permiten trabajar formas redondeadas y repetitivas, ideales para mejorar el control del coloreado. Además, las cuerdas y su disposición en el aire aportan un leve desafío que enriquece la experiencia sin volverla compleja.</p> <h3>Uso creativo del color</h3> <p>Cada globo puede pintarse con un color diferente, lo que abre la posibilidad de experimentar combinaciones, contrastes y patrones. Esto favorece la toma de decisiones creativas y el desarrollo del sentido estético.</p> <h3>Una actividad que transmite emociones positivas</h3> <p>Más allá del dibujo en sí, esta ilustración invita a asociar el arte con momentos de felicidad, reforzando el vínculo entre creatividad y emociones agradables en los niños.</p>', 'princesa globos, fiesta infantil, celebración, dibujo alegre, globos colores, fantasía, arte niños, ilustración divertida, cumpleaños, actividad creativa, felicidad infantil, dibujo festivo, princesa feliz, colorear niños, globos aire', 'princesa-con-globos-para-colorear-or-dibujo-festivo-y-alegre', 8, NULL, '2026-04-01T18:12:28.305Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056347/coloring-web/princesas/princesa-con-globos-para-colorear-or-dibujo-festivo-y-alegre.webp', 'coloring-web/princesas/princesa-con-globos-para-colorear-or-dibujo-festivo-y-alegre') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (131, 'Dibujo para colorear base lunar con módulos espaciales', 'dibujo-para-colorear-base-lunar-con-modulos-espaciales', 'Base espacial construida sobre la Luna para colorear.', '<p>Imagina el futuro con esta colonia establecida en la Luna. Con cúpulas, laboratorios y vehículos de exploración, esta lámina es un disparador de ideas sobre la ciencia ficción y la vida en otros planetas.</p>
  <h4>Arquitectura futurista</h4>
  <p>Los módulos circulares y las antenas de comunicación permiten practicar formas tecnológicas. Se pueden usar colores metalizados, grises y detalles en luces neón (rojo o verde) para que la base parezca estar en pleno funcionamiento.</p>
  <h4>Ambiente espacial</h4>
  <p>Para el suelo lunar, recomendamos un gris ceniza con sombras marcadas en los cráteres. Pintar el cielo de negro absoluto alrededor de la base hará que la tecnología de los módulos resalte como si fuera una foto real del espacio.</p>', 'base lunar, módulos espaciales, colonia lunar, exploración espacial', 'dibujo-para-colorear-base-lunar-con-modulos-espaciales', 3, NULL, '2026-03-04T02:30:24.068Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280212/coloring-web/espacio/dibujo-para-colorear-base-lunar-con-modulos-espaciales.webp', 'coloring-web/espacio/dibujo-para-colorear-base-lunar-con-modulos-espaciales') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (135, 'Dibujo para colorear estación espacial orbitando la Tierra', 'dibujo-para-colorear-estacion-espacial-orbitando-la-tierra', 'Estación espacial flotando alrededor del planeta Tierra.', 'Un dibujo detallado de Dibujo para colorear estación espacial orbitando la Tierra, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'estación espacial, órbita, tierra, astronautas, ciencia', 'dibujo-para-colorear-estacion-espacial-orbitando-la-tierra', 3, NULL, '2026-03-04T02:32:27.849Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280216/coloring-web/espacio/dibujo-para-colorear-estacion-espacial-orbitando-la-tierra.webp', 'coloring-web/espacio/dibujo-para-colorear-estacion-espacial-orbitando-la-tierra') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (138, 'Dibujo para colorear planeta Tierra desde el espacio', 'dibujo-para-colorear-planeta-tierra-desde-el-espacio', 'Planeta Tierra visto desde el espacio para colorear.', '¡Despega hacia la diversión con este dibujo de Dibujo para colorear planeta Tierra desde el espacio! Perfecto para pequeños astronautas con mucha imaginación.', 'planeta tierra, continentes, océanos, espacio, ciencia', 'dibujo-para-colorear-planeta-tierra-desde-el-espacio', 3, NULL, '2026-03-04T02:34:37.214Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280220/coloring-web/espacio/dibujo-para-colorear-planeta-tierra-desde-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-planeta-tierra-desde-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (144, 'Dibujo para colorear platillo volador OVNI en el espacio', 'dibujo-para-colorear-platillo-volador-ovni-en-el-espacio', 'Platillo volador flotando entre estrellas y planetas para colorear.', '¡Despega hacia la diversión con este dibujo de Dibujo para colorear platillo volador OVNI en el espacio! Perfecto para pequeños astronautas con mucha imaginación.', 'ovni, platillo volador, espacio, extraterrestre, estrellas, ciencia ficción infantil', 'dibujo-para-colorear-platillo-volador-ovni-en-el-espacio', 3, NULL, '2026-03-04T02:39:28.338Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280228/coloring-web/espacio/dibujo-para-colorear-platillo-volador-ovni-en-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-platillo-volador-ovni-en-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (148, 'Dibujo para colorear sistema solar en inglés', 'dibujo-para-colorear-sistema-solar-en-ingles', 'Sistema solar con nombres de los planetas en inglés para colorear.', 'Un dibujo detallado de Dibujo para colorear sistema solar en inglés, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'solar system, planets in English, astronomy for kids, educational coloring, space learning', 'dibujo-para-colorear-sistema-solar-en-ingles', 3, NULL, '2026-03-04T02:41:02.902Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280233/coloring-web/espacio/dibujo-para-colorear-sistema-solar-en-ingles.webp', 'coloring-web/espacio/dibujo-para-colorear-sistema-solar-en-ingles') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (123, 'Dibujo para colorear astronauta flotando en el espacio', 'dibujo-para-colorear-astronauta-flotando-en-el-espacio', 'Astronauta flotando entre estrellas y planetas para colorear.', '<p>Esta icónica imagen nos transporta a la inmensidad del cosmos. El astronauta flota libremente en el vacío, unido a su nave solo por un cable de seguridad, mientras observa nuestro planeta azul suspendido en la oscuridad.</p>
  <h4>La sensación de ingravidez</h4>
  <p>El dibujo captura la libertad del movimiento en gravedad cero. Al no tener un suelo firme, la pose del astronauta es relajada y fluida, lo que permite a los niños imaginar cómo sería no sentir el peso de su propio cuerpo.</p>
  <h4>Sugerencias de contraste espacial</h4>
  <p>En el espacio no hay atmósfera, por lo que el fondo es un negro profundo. Los niños pueden practicar el contraste fuerte pintando el espacio de negro y dejando el traje del astronauta en un blanco brillante, resaltando los detalles tecnológicos.</p>
  <h4>Asombro científico y exploración</h4>
  <p>Este dibujo motiva a los niños a preguntar sobre la física del espacio y las misiones de la NASA. Es un disparador de curiosidad sobre el universo, fomentando el interés por la ciencia y la exploración tecnológica.</p>', 'astronauta, gravedad cero, espacio, estrellas, planeta, ciencia infantil', 'dibujo-para-colorear-astronauta-flotando-en-el-espacio', 3, NULL, '2026-03-03T03:04:35.359Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280207/coloring-web/espacio/dibujo-para-colorear-astronauta-flotando-en-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-flotando-en-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (171, 'Dibujo para colorear científica con microscopio', 'dibujo-para-colorear-cientifica-con-microscopio', 'Científica observando muestras en microscopio', '<p>Esta lámina celebra el papel fundamental de las mujeres en la ciencia. La investigadora aparece concentrada analizando muestras a través de un microscopio, recordándonos que la curiosidad y la observación son las herramientas más poderosas para descubrir los secretos del mundo invisible.</p>
  <h4>Ciencia y precisión</h4>
  <p>La ilustración permite a los niños familiarizarse con el equipamiento de un laboratorio biológico. Es una oportunidad excelente para hablar sobre las células, las bacterias y cómo la tecnología nos permite ver cosas que el ojo humano no puede percibir a simple vista.</p>
  <h4>Consejos artísticos</h4>
  <p>Recomendamos usar colores claros para la bata de laboratorio, añadiendo sombras celestes suaves en los pliegues para dar volumen. El microscopio puede pintarse con tonos metálicos o negros brillantes para que destaque como la herramienta principal de la escena.</p>', 'científica, microscopio, laboratorio, ciencia, profesión científica', 'dibujo-para-colorear-cientifica-con-microscopio', 4, NULL, '2026-03-07T00:43:05.552Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280260/coloring-web/profesiones-oficios/dibujo-para-colorear-cientifica-con-microscopio.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cientifica-con-microscopio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (160, 'Dibujo para colorear bibliotecaria ordenando libros', 'dibujo-para-colorear-bibliotecaria-ordenando-libros', 'Bibliotecaria colocando libros en estantería', '<p>Esta escena celebra el amor por la lectura y el orden. En una estantería llena de historias, la bibliotecaria organiza cuidadosamente los libros, recordándonos la importancia de los libros en nuestra educación y cultura.</p>
  <h4>Patrones de colores en los lomos</h4>
  <p>Cada libro en la estantería es un lienzo diferente. Los niños pueden divertirse dándole un color distinto a cada lomo, creando un arcoíris literario que hace que la ilustración sea visualmente muy rica y alegre.</p>
  <h4>Fomento de la lectura</h4>
  <p>Mientras colorean, se puede invitar a los niños a inventar títulos para los libros de la estantería. Esto une la actividad artística con el desarrollo del lenguaje y el respeto por los espacios de aprendizaje silencioso.</p>', 'bibliotecaria, libros, biblioteca, lectura, profesión educativa', 'dibujo-para-colorear-bibliotecaria-ordenando-libros', 4, NULL, '2026-03-07T00:30:06.317Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280246/coloring-web/profesiones-oficios/dibujo-para-colorear-bibliotecaria-ordenando-libros.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-bibliotecaria-ordenando-libros') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (164, 'Dibujo para colorear bombero con manguera frente a camión de bomberos', 'dibujo-para-colorear-bombero-con-manguera-frente-a-camion-de-bomberos', 'Bombero sosteniendo una manguera frente a un camión de bomberos', '<p>En esta completa composición, vemos al bombero trabajando en conjunto con su vehículo de transporte. El camión al fondo añade un nivel de detalle técnico que fascina a los pequeños entusiastas de la maquinaria de rescate.</p>
  <h4>Perspectiva y profundidad</h4>
  <p>Al tener al personaje en primer plano y el camión detrás, los niños aprenden sobre la profundidad de campo. Sugerimos usar colores más intensos para el bombero y tonos ligeramente más suaves para el camión, creando un efecto de relieve profesional.</p>
  <h4>Detalles del equipo</h4>
  <p>Las escaleras, mangueras enrolladas y luces del camión son excelentes para trabajar la paciencia. Colorear cada compartimento del vehículo ayuda a mejorar la precisión manual y la concentración sostenida.</p>', 'Bombero sosteniendo una manguera frente a un camión de bomberos', 'dibujo-para-colorear-bombero-con-manguera-frente-a-camion-de-bomberos', 4, NULL, '2026-03-07T00:32:35.219Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280251/coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-con-manguera-frente-a-camion-de-bomberos.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-con-manguera-frente-a-camion-de-bomberos') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
