INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (236, 'Dibujo para colorear técnico reparador', 'dibujo-para-colorear-tecnico-reparador', 'Técnico usando herramientas para reparar', 'Un dibujo detallado de Dibujo para colorear técnico reparador, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'técnico, reparador, herramientas, mantenimiento, profesión', 'dibujo-para-colorear-tecnico-reparador', 4, NULL, '2026-03-07T01:26:02.593Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280332/coloring-web/profesiones-oficios/dibujo-para-colorear-tecnico-reparador.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-tecnico-reparador') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (8, 'Dibujo de bisonte americano en el campo para colorear', 'dibujo-de-bisonte-americano-en-el-campo-para-colorear', 'Dibujo lineal de un bisonte adulto de perfil parado frente a una cerca de madera en una pradera.', '<p>El bisonte americano, símbolo de las grandes llanuras, aparece en este dibujo con toda su fuerza. Su cuerpo robusto y su pelaje denso destacan en un horizonte abierto, invitando a colorear un pedazo de la historia natural de América.</p>
  <h4>Textura de pelaje denso</h4>
  <p>La cabeza y los hombros del bisonte tienen un pelaje mucho más grueso. Recomendamos usar trazos cortos, casi como pequeños garabatos controlados, para simular esa lana pesada y oscura característica de la especie.</p>
  <h4>Composición de pradera</h4>
  <p>El paisaje de llanura permite practicar la línea del horizonte. Los niños pueden pintar un cielo muy amplio, lo que da una sensación de libertad y espacio, típica de los hábitats naturales donde vive el bisonte.</p>
  <h4>Fuerza y resistencia</h4>
  <p>Este animal representa la resistencia y el poder. Colorearlo ayuda a los niños a apreciar la robustez de la fauna salvaje y a entender cómo los animales se adaptan a vivir en espacios abiertos y expuestos.</p>', 'bisonte americano, dibujo de búfalo, animales de la pradera, naturaleza para colorear, dibujo de campo, animales salvajes.', 'dibujo-de-bisonte-americano-en-el-campo-para-colorear', 1, NULL, '2026-02-24T00:44:08.193Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280077/coloring-web/animales/dibujo-de-bisonte-americano-en-el-campo-para-colorear.webp', 'coloring-web/animales/dibujo-de-bisonte-americano-en-el-campo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (482, 'Princesa con flor en mano para colorear | Dibujo delicado y natural infantil', 'princesa-con-flor-en-mano-para-colorear-or-dibujo-delicado-y-natural-infantil', 'Princesa sosteniendo una flor en la mano, ilustración simple con estilo delicado para colorear.', '<h3>Un símbolo de calma y conexión natural</h3> <p>La princesa sostiene una flor con suavidad, generando una escena que transmite tranquilidad y equilibrio. Este tipo de ilustración invita a bajar el ritmo y a disfrutar de una actividad más pausada, ideal para momentos de concentración.</p> <h3>Observación de elementos naturales</h3> <p>La flor permite identificar partes básicas como pétalos, tallo y hojas, introduciendo conceptos simples de la naturaleza de forma visual. Es una buena oportunidad para hablar sobre plantas y su importancia.</p> <h3>Colores armónicos y suaves</h3> <p>Se recomienda trabajar con paletas equilibradas, utilizando verdes, rosas o amarillos para mantener una estética delicada. También se pueden probar combinaciones más creativas para personalizar la flor.</p> <h3>Fomento de la atención al detalle</h3> <p>Aunque el dibujo es simple, invita a prestar atención en pequeños elementos, favoreciendo la precisión y el cuidado en cada trazo.</p>', 'princesa flor, naturaleza infantil, dibujo delicado, flores para colorear, fantasía suave, arte infantil, primavera, ilustración tranquila, creatividad niños, dibujo natural, princesa calma, actividad relajante, colorear fácil, naturaleza, princesa', 'princesa-con-flor-en-mano-para-colorear-or-dibujo-delicado-y-natural-infantil', 8, NULL, '2026-04-01T18:12:52.343Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056371/coloring-web/princesas/princesa-con-flor-en-mano-para-colorear-or-dibujo-delicado-y-natural-infantil.webp', 'coloring-web/princesas/princesa-con-flor-en-mano-para-colorear-or-dibujo-delicado-y-natural-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (326, 'Conejo en el campo con mariposas, pajaritos y huevos de Pascua para colorear', 'conejo-en-campo-con-huevos-de-pascua-y-rio-para-colorear', 'Dibujo para colorear de un conejo sentado en un campo de flores, mirando mariposas y pajaritos rodeado de huevos de Pascua decorados, arte de línea negra fácil para niños.', '<p>Esta vibrante escena captura la esencia de la primavera en un solo lugar. Un curioso conejo disfruta de un día soleado en el campo, observando el vuelo de las mariposas y el canto de los pajaritos, mientras descubre huevos de Pascua escondidos entre la hierba alta y las flores.</p>

  <h4>Naturaleza y vida en movimiento</h4>
  <p>La ilustración destaca por la interacción entre diferentes especies, lo que permite a los niños aprender sobre los animales del jardín y los insectos polinizadores. Es una composición rica en detalles que invita a imaginar los sonidos y aromas de un prado florecido.</p>

  <h4>Consejos para colorear</h4>
  <p>Para las mariposas, recomendamos usar colores simétricos y brillantes como el azul turquesa o el naranja intenso. Los pajaritos se ven muy bien con tonos amarillos o rojos, mientras que para el fondo del campo, el uso de diferentes gamas de verde dará una sensación de frescura y profundidad al paisaje.</p>

  <h4>Beneficios de la observación detallada</h4>
  <p>Al tener elementos pequeños y variados, este dibujo fomenta la agudeza visual. Los niños deben diferenciar entre las alas de los insectos, las plumas de las aves y el pelaje del conejo, lo que fortalece su capacidad de concentración y su destreza con los lápices de colores.</p>', 'conejo de pascua, mariposas, pajaritos, primavera, huevos decorados, naturaleza, animales del campo, dibujo educativo, infantil, imprimir gratis', 'conejo-en-campo-con-huevos-de-pascua-y-rio-para-colorear', 6, NULL, '2026-03-16T18:48:09.531Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676088/coloring-web/pascuas/conejo-en-campo-con-huevos-de-pascua-y-rio-para-colorear.webp', 'coloring-web/pascuas/conejo-en-campo-con-huevos-de-pascua-y-rio-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
