INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (483, 'Princesa con dulces para colorear | Dibujo infantil divertido con golosinas', 'princesa-con-dulces-para-colorear-or-dibujo-infantil-divertido-con-golosinas', 'Princesa rodeada de dulces, caramelos y golosinas, ilustración en blanco y negro para colorear.', '<h3>Una escena llena de diversión y fantasía</h3> <p>Los dulces que rodean a la princesa crean un entorno visual atractivo y lleno de estímulos. Es una ilustración que conecta con el mundo de la imaginación infantil, donde los elementos cotidianos se vuelven mágicos y exagerados.</p> <h3>Diversidad de formas y elementos</h3> <p>Caramelos, tortas o golosinas aportan variedad al dibujo, permitiendo trabajar distintas figuras y estilos dentro de una misma escena. Esto mantiene el interés durante toda la actividad.</p> <h3>Colores intensos y llamativos</h3> <p>Los dulces invitan a usar tonos vibrantes como rojo, amarillo, verde o violeta, generando un resultado visual muy atractivo. Es ideal para experimentar sin restricciones.</p> <h3>Estimulación de la imaginación creativa</h3> <p>Este tipo de ilustraciones fomenta la creación de mundos imaginarios donde todo es posible, fortaleciendo la creatividad y el disfrute del proceso artístico.</p>', 'princesa dulces, golosinas, caramelos, dibujo infantil, fantasía dulce, arte niños, ilustración divertida, comida dulce, creatividad, actividad infantil, colores llamativos, princesa feliz, dibujo entretenido, colorear, dulces niños', 'princesa-con-dulces-para-colorear-or-dibujo-infantil-divertido-con-golosinas', 8, NULL, '2026-04-01T18:13:26.456Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056405/coloring-web/princesas/princesa-con-dulces-para-colorear-or-dibujo-infantil-divertido-con-golosinas.webp', 'coloring-web/princesas/princesa-con-dulces-para-colorear-or-dibujo-infantil-divertido-con-golosinas') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
