INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (188, 'Dibujo para colorear fontanero con herramientas', 'dibujo-para-colorear-fontanero-con-herramientas', 'Fontanero sosteniendo llave inglesa', 'Un dibujo detallado de Dibujo para colorear fontanero con herramientas, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'fontanero, plomería, herramientas, profesión técnica', 'dibujo-para-colorear-fontanero-con-herramientas', 4, NULL, '2026-03-07T00:56:11.418Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280279/coloring-web/profesiones-oficios/dibujo-para-colorear-fontanero-con-herramientas.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-fontanero-con-herramientas') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (163, 'Dibujo para colorear bombero con manguera', 'dibujo-para-colorear-bombero-con-manguera', 'Dibujo para colorear bombero con manguera', '<p>Esta valiente escena presenta a un bombero en plena acción, sujetando una manguera de alta presión para extinguir un incendio. Es una ilustración fundamental para que los niños comprendan la importancia de los servicios de emergencia y el heroísmo de quienes protegen nuestra comunidad.</p>
  <h4>El agua y el movimiento</h4>
  <p>El chorro de agua que sale de la manguera permite practicar trazos fluidos y dinámicos. Recomendamos usar un azul celeste muy claro, dejando espacios en blanco para simular la espuma y la fuerza del agua al chocar contra el fuego.</p>
  <h4>Colores de seguridad</h4>
  <p>Para el uniforme de bombero, el uso del amarillo neón o el naranja para las bandas reflectantes es clave. Esto ayuda a los niños a entender cómo la ropa de seguridad está diseñada para ser visible incluso en condiciones de mucho humo.</p>', 'Bombero usando manguera para apagar incendio', 'dibujo-para-colorear-bombero-con-manguera', 4, NULL, '2026-03-07T00:31:46.077Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280250/coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-con-manguera.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-con-manguera') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
