INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (168, 'Dibujo para colorear carpintero trabajando', 'dibujo-para-colorear-carpintero-trabajando', 'Carpintero usando un martillo', '<p>Este dibujo rinde homenaje al noble oficio de la madera. El carpintero aparece en su taller, rodeado de herramientas como el martillo y el serrucho, transformando troncos naturales en muebles útiles y hermosos para nuestro hogar.</p>
  <h4>Herramientas y precisión</h4>
  <p>La lámina incluye detalles de vetas de madera y virutas en el suelo. Colorear estos pequeños elementos ayuda a desarrollar la motricidad fina y permite hablar con los niños sobre de dónde vienen los objetos de nuestra casa.</p>
  <h4>Paleta de colores tierra</h4>
  <p>Recomendamos una gama de marrones, ocres y tonos madera. El contraste con el metal plateado de las herramientas y el color del overol del carpintero crea una escena acogedora que transmite calma y concentración laboral.</p>', 'carpintero, madera, herramientas, profesión, construcción', 'dibujo-para-colorear-carpintero-trabajando', 4, NULL, '2026-03-07T00:38:17.700Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280257/coloring-web/profesiones-oficios/dibujo-para-colorear-carpintero-trabajando.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-carpintero-trabajando') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
