INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (291, 'Dibujo para colorear tren de vapor en la ciudad', 'dibujo-para-colorear-tren-de-vapor-en-la-ciudad', 'Tren antiguo de vapor pasando por la ciudad', 'Un dibujo detallado de Dibujo para colorear tren de vapor en la ciudad, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'tren de vapor, locomotora antigua, tren clásico, transporte ferroviario, tren histórico', 'dibujo-para-colorear-tren-de-vapor-en-la-ciudad', 5, NULL, '2026-03-12T02:26:31.300Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280402/coloring-web/vehiculos/dibujo-para-colorear-tren-de-vapor-en-la-ciudad.webp', 'coloring-web/vehiculos/dibujo-para-colorear-tren-de-vapor-en-la-ciudad') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (329, 'Conejo saltando sobre huevos de Pascua para colorear', 'conejo-saltando-sobre-huevos-de-pascua-para-colorear', 'conejo saltando sobre huevos de pascua dibujo para colorear', '<p>La acción y el dinamismo definen esta lámina. El conejo está capturado en pleno salto sobre una hilera de huevos decorados, transmitiendo una sensación de energía, velocidad y juego típica de la mañana de Pascua.</p>
  <h4>Representación del movimiento</h4>
  <p>Las líneas de acción y las orejas hacia atrás ayudan a los niños a entender cómo se dibuja el movimiento. Es una excelente lección de dibujo dinámico, donde el cuerpo del personaje no es estático sino que fluye con la acción.</p>
  <h4>Guía de color dinámica</h4>
  <p>Recomendamos usar colores que transmitan energía, como amarillos, naranjas y rojos. Para el suelo, unas líneas rápidas de color verde pueden simular la velocidad del salto, dándole un acabado muy profesional a la obra.</p>
  <h4>Desarrollo de la vitalidad</h4>
  <p>Pintar escenas de acción ayuda a los niños a canalizar su propia energía. Es un dibujo que motiva y alegra, ideal para despertar la creatividad en momentos donde se necesita un impulso de ánimo y diversión.</p>', 'conejo de pascua, huevos de pascua, saltando, pascua infantil, dibujos para colorear', 'conejo-saltando-sobre-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:50:39.049Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676238/coloring-web/pascuas/conejo-saltando-sobre-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-saltando-sobre-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
