INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (407, 'Dinosaurio explorando terreno prehistórico para colorear', 'dinosaurio-explorando-terreno-prehistorico-para-colorear', 'dinosaurio explorando el terreno dibujo para colorear', 'Un increíble dibujo de Dinosaurio explorando terreno prehistórico para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'dinosaurio explorador, dinosaurio caminando, dinosaurio aventura, dinosaurio terreno, dibujos para colorear dinosaurios', 'dinosaurio-explorando-terreno-prehistorico-para-colorear', 7, NULL, '2026-03-20T02:52:45.422Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773964364/coloring-web/dinosaurios/dinosaurio-explorando-terreno-prehistorico-para-colorear.webp', 'coloring-web/dinosaurios/dinosaurio-explorando-terreno-prehistorico-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (355, 'Bosque mágico con hongos gigantes para colorear', 'bosque-magico-con-hongos-gigantes-para-colorear', 'bosque mágico con hongos gigantes dibujo para colorear', '<p>¿Qué pasaría si las plantas fueran mucho más grandes que nosotros? Este bosque encantado desafía las leyes de la física con sus hongos gigantes, creando un ecosistema de fantasía que invita a la exploración visual y sensorial.</p>

  <h4>Naturaleza fuera de escala</h4>
  <p>El diseño está lleno de curvas y formas orgánicas que fluyen por toda la página, creando una composición armoniosa. Es un escenario donde el artista puede decidir qué secretos se esconden bajo las grandes copas de los hongos.</p>

  <h4>Recomendaciones de color</h4>
  <p>En este mundo mágico todo es posible. Los hongos pueden tener sombreros rojos con puntos blancos, o ser de colores neón. Un consejo para el fondo es usar colores muy suaves para dar la sensación de una atmósfera mística y relajante.</p>

  <h4>Relajación y mindfulness</h4>
  <p>Pintar formas orgánicas y repetitivas tiene un efecto calmante. Este dibujo actúa como un ejercicio de meditación activa, ayudando a los niños a centrarse en el presente mientras llenan de vida este paisaje de ensueño con su creatividad.</p>', 'bosque mágico, fantasía, hongos gigantes, naturaleza fantástica, dibujos para colorear', 'bosque-magico-con-hongos-gigantes-para-colorear', 2, NULL, '2026-03-18T00:48:47.561Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773784126/coloring-web/fantasia/bosque-magico-con-hongos-gigantes-para-colorear.webp', 'coloring-web/fantasia/bosque-magico-con-hongos-gigantes-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
