INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (271, 'Dibujo para colorear globo aerostático volando sobre un paisaje', 'dibujo-para-colorear-globo-aerostatico-volando-sobre-un-paisaje', 'Globo aerostático flotando en el cielo sobre un paisaje', 'Un dibujo detallado de Dibujo para colorear globo aerostático volando sobre un paisaje, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'globo aerostático, transporte aéreo, viaje en globo, cielo, paisaje, aventura, vuelo, turismo', 'dibujo-para-colorear-globo-aerostatico-volando-sobre-un-paisaje', 5, NULL, '2026-03-12T02:03:45.911Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280376/coloring-web/vehiculos/dibujo-para-colorear-globo-aerostatico-volando-sobre-un-paisaje.webp', 'coloring-web/vehiculos/dibujo-para-colorear-globo-aerostatico-volando-sobre-un-paisaje') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (245, 'Dibujo para colorear autobús escolar animado', 'dibujo-para-colorear-autobus-escolar-animado', 'Autobús escolar estilo caricatura transportando estudiantes', '<p>La máxima ternura se captura en este dibujo. Un pequeño autobús escolar amarillo sonríe profundamente con sus grandes ojos expresivos, creando una imagen llena de calidez y bienestar hogareño.</p>
  <h4>Simplificación de formas y líneas</h4>
  <p>A diferencia del autobús escolar realista, este diseño utiliza formas más redondeadas. Es mucho más fácil de colorear para niños pequeños, permitiéndoles practicar el relleno de superficies sin la complicación de texturas excesivas.</p>
  <h4>Sugerencias de coloración</h4>
  <p>Recomendamos usar colores primarios para la carrocería, como amarillo brillante. Al ser un autobús infantil, los colores suelen ser más claros que en los autobuses realistas. Un fondo de flores pequeñas hará que la escena se vea todavía más adorable.</p>
  <h4>Fomento de la serenidad</h4>
  <p>Pintar escenas de descanso tiene un efecto calmante probado. Esta lámina es perfecta para sesiones de coloreado relajantes antes de la siesta o para momentos en los que se busca reducir la hiperactividad infantil.</p>', 'autobús escolar, bus escolar, transporte escolar, escuela, estudiantes, vehículo escolar, transporte infantil, bus de escuela', 'dibujo-para-colorear-autobus-escolar-animado', 5, NULL, '2026-03-12T00:50:57.451Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280343/coloring-web/vehiculos/dibujo-para-colorear-autobus-escolar-animado.webp', 'coloring-web/vehiculos/dibujo-para-colorear-autobus-escolar-animado') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (434, 'Ceratosaurus en paisaje prehistórico completo para colorear', 'ceratosaurus-en-paisaje-prehistorico-completo-para-colorear', 'ceratosaurus en paisaje con lago cascada volcán y montañas dibujo para colorear', '<p>Viaja al período Jurásico con este impresionante Ceratosaurus, conocido por el cuerno distintivo sobre su nariz. La ilustración lo sitúa en un paisaje dinámico con volcanes lejanos, lagos y una vegetación primitiva exuberante.</p>

  <h4>Explorando la anatomía de los depredadores</h4>
  <p>El Ceratosaurus es un dinosaurio fascinante para estudiar la evolución. Los niños pueden notar sus poderosas mandíbulas y su postura atlética, lo que abre la puerta a conversaciones sobre la cadena alimenticia en la era de los dinosaurios.</p>

  <h4>Técnicas para un paisaje antiguo</h4>
  <p>Para el volcán de fondo, se pueden usar rojos y naranjas brillantes para simular lava. Para la piel del dinosaurio, sugerimos colores más oscuros y texturizados, como el gris azulado o el marrón rojizo, añadiendo sombras en la zona inferior del cuerpo.</p>

  <h4>Conocimiento científico</h4>
  <p>Este dibujo combina la pasión por los dinosaurios con el aprendizaje geográfico de la Tierra primitiva. Ayuda a los niños a visualizar cómo era el mundo hace millones de años, fomentando el interés por la paleontología y las ciencias naturales.</p>', 'ceratosaurus, dinosaurio volcán, dinosaurio lago, dinosaurio paisaje completo, dibujos para colorear dinosaurios', 'ceratosaurus-en-paisaje-prehistorico-completo-para-colorear', 7, NULL, '2026-03-21T05:30:18.790Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774060217/coloring-web/dinosaurios/ceratosaurus-en-paisaje-prehistorico-completo-para-colorear.webp', 'coloring-web/dinosaurios/ceratosaurus-en-paisaje-prehistorico-completo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
