INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (305, 'Conejo pequeño con tres huevos de Pascua para colorear', 'conejo-pequeno-con-tres-huevos-de-pascua-para-colorear', 'conejo pequeño con tres huevos de pascua dibujo para colorear', '<p>Esta ilustración muestra a un conejito bebé junto a una pequeña colección de tres huevos de Pascua. La simplicidad de la escena la hace perfecta para los más pequeños que están empezando a explorar el mundo del color y las formas.</p>
  <h4>Iniciación al conteo</h4>
  <p>Este dibujo puede usarse como una herramienta pedagógica para practicar los números del 1 al 3. Los padres pueden invitar al niño a colorear cada huevo de un color diferente mientras cuentan en voz alta, uniendo juego y aprendizaje.</p>
  <h4>Técnicas sugeridas</h4>
  <p>Recomendamos el uso de ceras o lápices de colores gruesos. Al tener líneas bien definidas y espacios claros, los niños ganan confianza al ver que pueden mantenerse dentro de los límites del dibujo con facilidad.</p>
  <h4>Desarrollo de la autoestima</h4>
  <p>Completar un dibujo de principio a fin de forma exitosa genera una gran satisfacción en los niños pequeños. Esta lámina está diseñada para garantizar un resultado visualmente agradable con poco esfuerzo.</p>', 'conejo de pascua, huevos de pascua, dibujos para colorear, pascua infantil', 'conejo-pequeno-con-tres-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:36:24.370Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675383/coloring-web/pascuas/conejo-pequeno-con-tres-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-pequeno-con-tres-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
