INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (409, 'Dinosaurios cruzando juntos para colorear', 'dinosaurios-cruzando-juntos-para-colorear', 'grupo de dinosaurios cruzando juntos dibujo para colorear', 'Un increíble dibujo de Dinosaurios cruzando juntos para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'grupo de dinosaurios cruzando juntos dibujo para colorear', 'dinosaurios-cruzando-juntos-para-colorear', 7, NULL, '2026-03-20T02:54:54.735Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773964493/coloring-web/dinosaurios/dinosaurios-cruzando-juntos-para-colorear.webp', 'coloring-web/dinosaurios/dinosaurios-cruzando-juntos-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (484, 'Princesa con castillo gigante para colorear | Dibujo detallado y complejo de fantasía', 'princesa-con-castillo-gigante-para-colorear-or-dibujo-detallado-y-complejo-de-fantasia', 'Princesa frente a un castillo grande con múltiples torres y detalles arquitectónicos, ilustración compleja para colorear.', '<h3>Un escenario imponente y lleno de detalles</h3> <p>El castillo gigante se convierte en el protagonista visual de esta escena, con múltiples torres, ventanas y estructuras que aportan riqueza y profundidad. La princesa aparece integrada en este entorno, reforzando la idea de un mundo fantástico de gran escala.</p> <h3>Un desafío ideal para mayor concentración</h3> <p>A diferencia de ilustraciones más simples, este dibujo requiere más tiempo y atención, siendo perfecto para niños con mayor experiencia o para quienes disfrutan de desafíos más complejos.</p> <h3>Trabajo de precisión y paciencia</h3> <p>Los pequeños detalles arquitectónicos ayudan a desarrollar la motricidad fina, ya que requieren un mayor control al momento de colorear zonas reducidas.</p> <h3>Resultado final visualmente impactante</h3> <p>Una vez terminado, este tipo de dibujo ofrece una sensación de logro más marcada, ya que el nivel de detalle permite obtener una imagen rica, completa y muy atractiva visualmente.</p>', 'princesa castillo grande, dibujo detallado, castillo gigante, fantasía medieval, arquitectura castillo, ilustración compleja, arte infantil avanzado, colorear detallado, torres, reino mágico, creatividad, niños mayores, dibujo desafiante, fantasía clásica, actividad artística', 'princesa-con-castillo-gigante-para-colorear-or-dibujo-detallado-y-complejo-de-fantasia', 8, NULL, '2026-04-01T18:14:03.141Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1775056442/coloring-web/princesas/princesa-con-castillo-gigante-para-colorear-or-dibujo-detallado-y-complejo-de-fantasia.webp', 'coloring-web/princesas/princesa-con-castillo-gigante-para-colorear-or-dibujo-detallado-y-complejo-de-fantasia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (332, 'Conejo y osito en canasta en jardín con cascada para colorear', 'conejo-y-osito-en-canasta-en-jardin-con-cascada-para-colorear', 'conejo y osito dentro de una canasta en un jardín con cascada dibujo para colorear', '<p>Esta es una de nuestras escenas más mágicas. Un conejo y un osito comparten una gran canasta en medio de un jardín paradisíaco, con una impresionante cascada que cae al fondo, uniendo la ternura animal con la fuerza de la naturaleza.</p>
  <h4>Elementos naturales y agua</h4>
  <p>La cascada introduce el desafío de colorear agua en movimiento. Es una excelente oportunidad para enseñar a los niños a usar trazos verticales y espacios en blanco para simular la espuma y la caída del agua entre las rocas.</p>
  <h4>Tips de coloración</h4>
  <p>Sugerimos usar azules y turquesas para el agua, y tonos tierra para las rocas de la cascada. Los personajes, el conejo y el osito, pueden pintarse con colores cálidos para que resalten frente al fondo fresco y natural del jardín.</p>
  <h4>Estímulo de la imaginación</h4>
  <p>Este dibujo transporta a los niños a un mundo de cuentos de hadas. Fomenta el pensamiento creativo y la capacidad de soñar con lugares lejanos y aventuras compartidas entre amigos de diferentes especies.</p>', 'conejo de pascua, osito, canasta, jardín, dibujos para colorear', 'conejo-y-osito-en-canasta-en-jardin-con-cascada-para-colorear', 6, NULL, '2026-03-16T18:52:03.919Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676323/coloring-web/pascuas/conejo-y-osito-en-canasta-en-jardin-con-cascada-para-colorear.webp', 'coloring-web/pascuas/conejo-y-osito-en-canasta-en-jardin-con-cascada-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
