INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (468, 'Princesa cuidando animales para colorear | Dibujo tierno de naturaleza', 'princesa-cuidando-animales-para-colorear-or-dibujo-tierno-de-naturaleza', 'Princesa rodeada de pequeños animales como conejos o pájaros, dibujo para colorear.', '<h3>Amor por los animales</h3> <p>Este dibujo muestra a una princesa interactuando con animales, promoviendo valores de cuidado y respeto por la naturaleza.</p> <h3>Reconocimiento de especies</h3> <p>Permite identificar distintos animales y sus características.</p> <h3>Colores naturales</h3> <p>Se pueden usar tonos realistas o фантаásticos para los animales.</p> <h3>Educación emocional</h3> <p>Fomenta la empatía y el vínculo con los seres vivos.</p>', 'princesa animales, cuidado animal, dibujo tierno, naturaleza infantil, mascotas, fantasía, animales para colorear, princesa amable, arte educativo, respeto naturaleza, ilustración niños, dibujo simple, campo, animales pequeños, creatividad', 'princesa-cuidando-animales-para-colorear-or-dibujo-tierno-de-naturaleza', 8, NULL, '2026-04-01T02:10:47.917Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998647/coloring-web/princesas/princesa-cuidando-animales-para-colorear-or-dibujo-tierno-de-naturaleza.webp', 'coloring-web/princesas/princesa-cuidando-animales-para-colorear-or-dibujo-tierno-de-naturaleza') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (173, 'Dibujo para colorear científico en laboratorio', 'dibujo-para-colorear-cientifico-en-laboratorio', 'Científico con tubos de ensayo en laboratorio', '<p>El laboratorio es el lugar donde nace el conocimiento. En este dibujo, un científico trabaja rodeado de probetas, tubos de ensayo y matraces, realizando experimentos que buscan soluciones para la salud, la energía o el medio ambiente.</p>
  <h4>Elementos químicos y color</h4>
  <p>Lo más divertido de esta lámina son los líquidos dentro de los recipientes de cristal. Los niños pueden usar colores vibrantes y neón (verde, rosa, naranja) para simular reacciones químicas mágicas, fomentando la imaginación y el interés por la química básica.</p>
  <h4>Orden y seguridad</h4>
  <p>El dibujo muestra un entorno de trabajo organizado, lo que refuerza en los niños la importancia del orden y el uso de equipo de protección, como las gafas de seguridad, mientras exploran el mundo de las carreras STEM.</p>', 'científico, laboratorio, experimentos, ciencia para niños', 'dibujo-para-colorear-cientifico-en-laboratorio', 4, NULL, '2026-03-07T00:45:23.802Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280262/coloring-web/profesiones-oficios/dibujo-para-colorear-cientifico-en-laboratorio.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cientifico-en-laboratorio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
