INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (208, 'Dibujo para colorear mecánico con herramientas', 'dibujo-para-colorear-mecanico-con-herramientas', 'Mecánico sosteniendo herramientas en el taller', 'Un dibujo detallado de Dibujo para colorear mecánico con herramientas, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'mecánico, herramientas, reparación, taller, oficio', 'dibujo-para-colorear-mecanico-con-herramientas', 4, NULL, '2026-03-07T01:09:34.697Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280304/coloring-web/profesiones-oficios/dibujo-para-colorear-mecanico-con-herramientas.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-mecanico-con-herramientas') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (166, 'Dibujo infantil de una cantante realizando un concierto. Perfecto para colorear y explorar el mundo de la música.', 'dibujo-infantil-de-una-cantante-realizando-un-concierto-perfecto-para-colorear-y-explorar-el-mundo-de-la-musica', 'Cantante sosteniendo micrófono en el escenario', '<p>Esta vibrante escena presenta a una cantante infantil entregada a su público en un gran escenario. Con el micrófono en la mano y rodeada de luces, este dibujo nos sumerge en el emocionante mundo de la música en vivo y la expresión artística.</p>
  <h4>Elementos técnicos del escenario</h4>
  <p>Al tener luces de concierto y amplificadores, este dibujo introduce elementos técnicos complejos. Los niños pueden usar colores neón o metalizados para simular el brillo de los focos y la estructura metálica del escenario, dándole un acabado muy profesional a la obra.</p>
  <h4>Tips de vestuario y color</h4>
  <p>Recomendamos usar colores muy llamativos para el vestuario de la cantante, como fucsia, turquesa o morado. Para las luces de fondo, un degradado suave de amarillos y naranjas simulará que el escenario está encendido y vibrante.</p>
  <h4>Desarrollo de la narrativa musical</h4>
  <p>Al pintar esta escena, se anima a los niños a imaginar la canción que está interpretando la cantante. Esto fortalece las habilidades lingüísticas y la capacidad de estructurar relatos de ficción relacionados con el mundo del espectáculo.</p>', 'cantante, música, micrófono, escenario, profesión artística, dibujo para colorear', 'dibujo-infantil-de-una-cantante-realizando-un-concierto-perfecto-para-colorear-y-explorar-el-mundo-de-la-musica', 4, NULL, '2026-03-07T00:37:18.007Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280255/coloring-web/profesiones-oficios/dibujo-infantil-de-una-cantante-realizando-un-concierto-perfecto-para-colorear-y-explorar-el-mundo-de-la-musica.webp', 'coloring-web/profesiones-oficios/dibujo-infantil-de-una-cantante-realizando-un-concierto-perfecto-para-colorear-y-explorar-el-mundo-de-la-musica') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
