INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (438, 'Princesa con caballo en el campo para colorear', 'princesa-con-caballo-en-el-campo-para-colorear', 'princesa con caballo en campo abierto dibujo para colorear', 'Un dibujo detallado de Princesa con caballo en el campo para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'princesa con caballo, princesa campo, princesa animales, princesa naturaleza, dibujos para colorear princesas', 'princesa-con-caballo-en-el-campo-para-colorear', 8, NULL, '2026-03-21T23:50:41.822Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774126240/coloring-web/princesas/princesa-con-caballo-en-el-campo-para-colorear.webp', 'coloring-web/princesas/princesa-con-caballo-en-el-campo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (172, 'Dibujo para colorear científico usando microscopio', 'dibujo-para-colorear-cientifico-usando-microscopio', 'Científico analizando muestras con microscopio', '<p>Esta ilustración se enfoca en el momento exacto del descubrimiento. El científico ajusta las lentes de su microscopio para observar una muestra con total nitidez, representando la paciencia y la dedicación necesarias para la investigación científica profesional.</p>
  <h4>Motricidad y detalle</h4>
  <p>Debido a las piezas pequeñas del microscopio (objetivos, platina y tornillos), los niños pueden practicar la motricidad fina. Colorear cada parte del equipo ayuda a mejorar la coordinación y la concentración en tareas que requieren minuciosidad.</p>
  <h4>Narrativa de investigación</h4>
  <p>Anima al niño a imaginar qué está viendo el científico: ¿es una hoja de planta, una gota de agua o un mineral lunar? Este ejercicio mental une el arte con la narrativa científica, convirtiendo el dibujo en una experiencia de aprendizaje completa.</p>', 'científico, laboratorio, microscopio, ciencia, investigación', 'dibujo-para-colorear-cientifico-usando-microscopio', 4, NULL, '2026-03-07T00:44:42.905Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280261/coloring-web/profesiones-oficios/dibujo-para-colorear-cientifico-usando-microscopio.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cientifico-usando-microscopio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
