INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (263, 'Dibujo para colorear coche de carreras en pista', 'dibujo-para-colorear-coche-de-carreras-en-pista', 'Coche de carreras número 88 corriendo en una pista', '<p>¡Velocidad pura en la palma de tu mano! Este bólido aerodinámico está capturado en plena competición sobre el asfalto. Con sus alerones y neumáticos anchos, representa la tecnología de punta diseñada para ganar segundos en cada vuelta al circuito.</p>
  <h4>Dinamismo y velocidad</h4>
  <p>La escena permite trabajar el concepto de movimiento. Los niños pueden usar trazos horizontales rápidos en el fondo para simular la velocidad del coche. Es un dibujo lleno de energía que motiva a usar colores audaces y saturados.</p>
  <h4>Diseño de competición</h4>
  <p>Recomendamos usar colores "racing" como el rojo fuego, el amarillo eléctrico o el azul Francia. Dejar espacios para añadir "pegatinas" o números personalizados en la carrocería fomenta la creatividad y el diseño gráfico infantil.</p>', 'coche de carreras, auto de carrera, pista de carreras, deporte motor, velocidad, competición', 'dibujo-para-colorear-coche-de-carreras-en-pista', 5, NULL, '2026-03-12T01:59:49.447Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280366/coloring-web/vehiculos/dibujo-para-colorear-coche-de-carreras-en-pista.webp', 'coloring-web/vehiculos/dibujo-para-colorear-coche-de-carreras-en-pista') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
