INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (440, 'Princesa con perro para colorear', 'princesa-con-perro-para-colorear', 'princesa con perro dibujo para colorear', 'Un tierno dibujo de Princesa con perro para colorear para que los amantes de los animales disfruten pintando y desarrollando su creatividad.', 'princesa con perro, princesa mascota, princesa infantil, dibujos para colorear princesas', 'princesa-con-perro-para-colorear', 8, NULL, '2026-03-21T23:52:44.858Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774126364/coloring-web/princesas/princesa-con-perro-para-colorear.webp', 'coloring-web/princesas/princesa-con-perro-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (308, 'Conejo empujando mini carretilla con huevos de Pascua para colorear', 'conejo-empujando-mini-carretilla-con-huevos-de-pascua-para-colorear', 'conejo empujando una mini carretilla con huevos de pascua dibujo para colorear', '<p>La escala cambia en esta ilustración, donde un conejo pequeño utiliza una mini carretilla para transportar sus tesoros. Es una imagen simpática que juega con las proporciones y la ternura de los objetos en miniatura.</p>

  <h4>Pequeños detalles, grandes historias</h4>
  <p>Los objetos pequeños suelen atraer mucho la atención de los niños. Esta escena invita a imaginar que el conejo es un aprendiz o un ayudante que está dando sus primeros pasos en la organización de la Pascua.</p>

  <h4>Técnicas de precisión</h4>
  <p>Debido a que la carretilla es pequeña, los espacios para colorear son más reducidos. Aconsejamos usar lápices con la punta bien afilada para no salirse de los bordes y lograr que los huevos minúsculos se vean nítidos y coloridos.</p>

  <h4>Control del trazo</h4>
  <p>Trabajar en formatos "mini" dentro de la página entrena la motricidad fina extrema. Es un ejercicio de control muscular muy beneficioso para mejorar la legibilidad de la letra y la destreza manual en general.</p>', 'conejo de pascua, huevos de pascua, carretilla, pascua infantil, colorear', 'conejo-empujando-mini-carretilla-con-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:38:27.111Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675506/coloring-web/pascuas/conejo-empujando-mini-carretilla-con-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-empujando-mini-carretilla-con-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (177, 'Dibujo para colorear cocinero cortando ingredientes con cuchillo', 'dibujo-para-colorear-cocinero-cortando-ingredientes-con-cuchillo', 'Cocinero usando un cuchillo para cortar alimentos en la cocina', '<p>La técnica y la precisión se muestran en esta escena donde el cocinero prepara vegetales frescos. Cortar ingredientes es uno de los pasos más importantes en la cocina, requiriendo concentración y habilidad manual para lograr el tamaño perfecto.</p>
  <h4>Alimentación saludable</h4>
  <p>En la tabla de cortar suelen aparecer zanahorias, tomates o pimientos. Es una oportunidad pedagógica para incentivar el consumo de verduras mientras los niños eligen colores vibrantes y naturales para cada hortaliza.</p>
  <h4>Coordinación ojo-mano</h4>
  <p>Al colorear las manos del cocinero y el cuchillo, los niños refuerzan su propia coordinación. La ilustración destaca la importancia de realizar las tareas con cuidado y atención, valores transferibles a sus actividades diarias.</p>', 'cocinero, chef, cocina, cuchillo, cocinar, preparación de alimentos, profesión, chef en cocina, comida', 'dibujo-para-colorear-cocinero-cortando-ingredientes-con-cuchillo', 4, NULL, '2026-03-07T00:48:18.357Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280266/coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-cortando-ingredientes-con-cuchillo.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cocinero-cortando-ingredientes-con-cuchillo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (310, 'Conejo escondiendo huevos detrás de un árbol para colorear', 'conejo-escondiendo-huevos-detras-de-un-arbol-para-colorear', 'Dibujo de un conejo escondiendo huevos de Pascua detrás de un árbol grueso, lámina infantil para colorear e imprimir.', '<p>Esta ilustración captura el momento previo a la gran búsqueda de Pascua. Un conejo cauteloso se asoma detrás del tronco de un árbol antiguo mientras coloca cuidadosamente los huevos decorados, creando una escena llena de misterio y diversión.</p>
  <h4>El arte de la perspectiva</h4>
  <p>El dibujo juega con los planos: el árbol en primer plano y el conejo asomándose. Es una excelente oportunidad para que los niños aprendan a colorear elementos que se solapan, entendiendo cómo un objeto puede ocultar parcialmente a otro.</p>
  <h4>Sugerencias de color</h4>
  <p>Para el tronco del árbol, recomendamos usar marrones con trazos verticales para simular la corteza. Los huevos, al estar "escondidos", pueden tener colores muy llamativos para que el niño sienta la satisfacción de haberlos encontrado en la página.</p>
  <h4>Fomento de la imaginación</h4>
  <p>Esta escena invita a los pequeños a crear su propia historia: ¿A quién está intentando sorprender el conejo? ¿Cuántos huevos faltan por esconder? Es un disparador creativo ideal para el desarrollo del lenguaje y la narrativa.</p>', 'conejo, árbol, huevos escondidos, juego de pascua, naturaleza, jardín, dibujo lineal, infantil, gratis.', 'conejo-escondiendo-huevos-detras-de-un-arbol-para-colorear', 6, NULL, '2026-03-16T18:39:25.588Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675564/coloring-web/pascuas/conejo-escondiendo-huevos-detras-de-un-arbol-para-colorear.webp', 'coloring-web/pascuas/conejo-escondiendo-huevos-detras-de-un-arbol-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
