INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (441, 'Princesa rodeada de flores para colorear', 'princesa-rodeada-de-flores-para-colorear', 'princesa rodeada de muchas flores dibujo para colorear', 'Un dibujo detallado de Princesa rodeada de flores para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'princesa flores, princesa jardín, princesa naturaleza, princesa detallada, dibujos para colorear princesas', 'princesa-rodeada-de-flores-para-colorear', 8, NULL, '2026-03-21T23:54:13.059Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774126451/coloring-web/princesas/princesa-rodeada-de-flores-para-colorear.webp', 'coloring-web/princesas/princesa-rodeada-de-flores-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (312, 'Conejo pintando huevos de Pascua con casa de fondo para colorear', 'conejo-pintando-huevos-de-pascua-con-casa-de-fondo-para-colorear', 'conejo pintando huevos de pascua con una casa de fondo dibujo para colorear', '<p>Esta escena nos lleva al hogar del conejo de Pascua. Lo vemos trabajando en sus creaciones artísticas en el patio de su casa, lo que añade un contexto de vida cotidiana y calidez hogareña a la festividad.</p>
  <h4>Arquitectura y naturaleza</h4>
  <p>La inclusión de la casa al fondo permite trabajar con líneas rectas y estructuras. Es una oportunidad para colorear techos de tejas, ventanas y puertas, contrastando con las formas orgánicas de los árboles y el propio conejo.</p>
  <h4>Tips para el artista</h4>
  <p>Sugerimos pintar la casa con colores cálidos como el naranja o el beige para dar sensación de acogida. El conejo puede tener un pequeño pincel en la pata, lo que invita a usar colores "manchados" alrededor para simular un taller real.</p>
  <h4>Narrativa espacial</h4>
  <p>Este dibujo ayuda a los niños a entender el concepto de "hogar". Pueden proyectar sus propias experiencias familiares mientras dan color a la casa y al jardín, fortaleciendo su sentido de identidad y pertenencia.</p>', 'conejo de pascua, pintar huevos, casa, pascua infantil, dibujos para colorear', 'conejo-pintando-huevos-de-pascua-con-casa-de-fondo-para-colorear', 6, NULL, '2026-03-16T18:40:13.535Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675612/coloring-web/pascuas/conejo-pintando-huevos-de-pascua-con-casa-de-fondo-para-colorear.webp', 'coloring-web/pascuas/conejo-pintando-huevos-de-pascua-con-casa-de-fondo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (140, 'Dibujo para colorear cohete en plataforma de lanzamiento', 'dibujo-para-colorear-cohete-en-plataforma-de-lanzamiento', 'Cohete listo en la plataforma de lanzamiento para colorear.', '<p>La cuenta atrás ha comenzado. En la torre de lanzamiento, el gigantesco cohete espera el encendido de sus motores para vencer la gravedad y llevar a los astronautas hacia una nueva frontera en el espacio exterior.</p>
  <h4>Ingeniería aeroespacial</h4>
  <p>La estructura de la plataforma (brazos de servicio, cables y andamios) ofrece un nivel de detalle técnico fascinante. Ayuda a los niños a valorar la planificación y la infraestructura necesaria para los viajes espaciales.</p>
  <h4>Poder y expectación</h4>
  <p>Recomendamos usar colores metálicos para el cuerpo del cohete y dejar el cielo de fondo listo para un amanecer espectacular. Es una escena que transmite emoción y esperanza por el descubrimiento científico y el futuro de la humanidad.</p>', 'cohete, plataforma de lanzamiento, nave espacial, despegue, espacio, misión espacial, ciencia infantil', 'dibujo-para-colorear-cohete-en-plataforma-de-lanzamiento', 3, NULL, '2026-03-04T02:37:48.473Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280222/coloring-web/espacio/dibujo-para-colorear-cohete-en-plataforma-de-lanzamiento.webp', 'coloring-web/espacio/dibujo-para-colorear-cohete-en-plataforma-de-lanzamiento') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
