INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (213, 'Dibujo para colorear minero trabajando', 'dibujo-para-colorear-minero-trabajando', 'Minero con casco y pico en la mina', 'Un dibujo detallado de Dibujo para colorear minero trabajando, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'minero, mina, casco, trabajo, minería', 'dibujo-para-colorear-minero-trabajando', 4, NULL, '2026-03-07T01:12:31.663Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280309/coloring-web/profesiones-oficios/dibujo-para-colorear-minero-trabajando.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-minero-trabajando') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (178, 'Dibujo para colorear constructor con casco', 'dibujo-para-colorear-constructor-con-casco', 'Constructor con casco y herramientas en obra', '<p>El constructor es el profesional encargado de dar forma a nuestras ciudades. Equipado con su equipo de seguridad y herramientas manuales, este trabajador simboliza el esfuerzo físico y la planificación necesaria para levantar casas, puentes y grandes monumentos.</p>
  <h4>Seguridad en el trabajo</h4>
  <p>El casco es el elemento central de esta lámina. Colorearlo de amarillo brillante o blanco ayuda a los niños a identificar las normas de seguridad en las obras. Es una excelente forma de introducir el respeto por las profesiones técnicas y el cuidado personal.</p>
  <h4>Detalles de herramientas</h4>
  <p>La ilustración suele incluir martillos o cinturones de herramientas. Pintar cada utensilio con precisión mejora la coordinación motriz y permite hablar sobre cómo cada herramienta tiene una función específica en el proceso de construcción.</p>', 'constructor, obra, casco, herramientas, profesión', 'dibujo-para-colorear-constructor-con-casco', 4, NULL, '2026-03-07T00:48:50.502Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280268/coloring-web/profesiones-oficios/dibujo-para-colorear-constructor-con-casco.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-constructor-con-casco') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (425, 'Bebé T-Rex saliendo del huevo con paisaje prehistórico para colorear', 'bebe-t-rex-saliendo-del-huevo-con-paisaje-prehistorico-para-colorear', 'Bebé T-Rex saliendo del huevo con paisaje prehistórico para colorear', '<p>Incluso el temido Tyrannosaurus Rex fue una vez un pequeño bebé vulnerable. Esta tierna ilustración muestra el momento exacto de la eclosión en un nido protegido, ofreciendo una visión amable de la vida en la prehistoria.</p>

  <h4>El milagro de la vida prehistórica</h4>
  <p>Es una escena perfecta para los más pequeños, ya que suaviza la imagen de los dinosaurios y los presenta de una forma amigable. Es ideal para aprender sobre los animales ovíparos y los ciclos de vida de forma sencilla y divertida.</p>

  <h4>Ideas para colorear</h4>
  <p>Para el cascarón del huevo, se pueden usar tonos crema o beige con pequeñas manchas marrones para dar realismo. El bebé dinosaurio puede ser de un verde brillante o tener patrones de colores imaginativos, ya que no existen límites en la fantasía.</p>

  <h4>Vínculo afectivo</h4>
  <p>Este dibujo es excelente para iniciar conversaciones sobre el crecimiento y el cuidado de los seres vivos. Permite que los niños conecten emocionalmente con el personaje, facilitando que retengan información histórica mientras se divierten.</p>', 'bebé t rex saliendo del huevo con volcán y palmeras dibujo para colorear', 'bebe-t-rex-saliendo-del-huevo-con-paisaje-prehistorico-para-colorear', 7, NULL, '2026-03-21T02:21:11.772Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774048870/coloring-web/dinosaurios/bebe-t-rex-saliendo-del-huevo-con-paisaje-prehistorico-para-colorear.webp', 'coloring-web/dinosaurios/bebe-t-rex-saliendo-del-huevo-con-paisaje-prehistorico-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (339, 'Huevo de Pascua con líneas en zigzag para colorear', 'huevo-de-pascua-con-lineas-en-zigzag-para-colorear', 'huevo de pascua con líneas en zigzag dibujo para colorear', 'Un dibujo detallado de Huevo de Pascua con líneas en zigzag para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'huevo de pascua, zigzag, dibujos para colorear, pascua infantil', 'huevo-de-pascua-con-lineas-en-zigzag-para-colorear', 6, NULL, '2026-03-17T00:52:48.805Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773697967/coloring-web/pascuas/huevo-de-pascua-con-lineas-en-zigzag-para-colorear.webp', 'coloring-web/pascuas/huevo-de-pascua-con-lineas-en-zigzag-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (321, 'Conejo con pollitos y huevos grandes de Pascua para colorear', 'conejo-con-pollitos-y-huevos-grandes-de-pascua-para-colorear', 'conejo con pollitos y huevos grandes de pascua dibujo para colorear', '<p>Esta encantadora escena reúne a los tres grandes símbolos de la Pascua en una sola composición. Un conejo de orejas suaves comparte el espacio con pequeños pollitos que exploran huevos de tamaño gigante, creando una imagen llena de ternura y detalle.</p>

  <h4>Amistad y cooperación en la naturaleza</h4>
  <p>La ilustración destaca la interacción entre diferentes animales, lo que permite a los niños imaginar diálogos y situaciones divertidas. Es un dibujo ideal para trabajar la narrativa visual mientras se eligen los colores para cada personaje.</p>

  <h4>Consejos para colorear</h4>
  <p>Dado que hay elementos de diferentes tamaños, sugerimos usar colores vibrantes para los huevos grandes para que actúen como marcos de color, y tonos más suaves para el conejo y los pollitos, logrando un equilibrio visual armonioso.</p>

  <h4>Beneficios del dibujo compartido</h4>
  <p>Al tener varios personajes, este dibujo es excelente para identificar jerarquías visuales. Ayuda a los niños a entender qué elementos están en primer plano y cuáles detrás, reforzando su capacidad de observación espacial.</p>', 'conejo de pascua, pollitos, huevos grandes, pascua infantil, dibujos para colorear', 'conejo-con-pollitos-y-huevos-grandes-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:45:42.207Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675941/coloring-web/pascuas/conejo-con-pollitos-y-huevos-grandes-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-con-pollitos-y-huevos-grandes-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
