INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (443, 'Princesa con flores y castillo elegante de fondo para colorear', 'princesa-sentada-con-castillo-y-flores-para-colorear', 'princesa con flores y castillo elegante de fondo dibujo para colorear', 'Un dibujo detallado de Princesa con flores y castillo elegante de fondo para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'princesa flores, princesa castillo, princesa elegante, princesa paisaje, dibujos para colorear princesas', 'princesa-sentada-con-castillo-y-flores-para-colorear', 8, NULL, '2026-03-21T23:55:54.593Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774126553/coloring-web/princesas/princesa-sentada-con-castillo-y-flores-para-colorear.webp', 'coloring-web/princesas/princesa-sentada-con-castillo-y-flores-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (314, 'Conejo pintando huevos de Pascua en un taller para colorear', 'conejo-pintando-huevos-de-pascua-en-un-taller-para-colorear', 'conejo pintando huevos de pascua en un taller dibujo para colorear', '<p>Entramos en el lugar secreto donde ocurre la magia: el taller del conejo de Pascua. Rodeado de estanterías llenas de huevos terminados y herramientas de artesano, el conejo se concentra en su próxima gran obra maestra.</p>
  <h4>Detalle y complejidad</h4>
  <p>Es uno de los dibujos más ricos en detalles de la colección. Las estanterías ofrecen múltiples compartimentos que permiten al niño jugar con la repetición de colores y la organización de los elementos en un espacio cerrado.</p>
  <h4>Técnicas avanzadas</h4>
  <p>Al ser un taller interior, se puede practicar la iluminación. Se puede imaginar que la luz viene de una ventana invisible, dejando algunas zonas de las estanterías más oscuras que otras, lo que añade un nivel de profundidad increíble.</p>
  <h4>Valor del oficio</h4>
  <p>Esta lámina celebra el trabajo artesanal. Es ideal para conversar sobre los oficios y la importancia de dedicar tiempo y cuidado a lo que hacemos con las manos, fomentando el respeto por el trabajo bien hecho.</p>', 'conejo de pascua, pintar huevos, taller, pascua infantil, dibujos para colorear', 'conejo-pintando-huevos-de-pascua-en-un-taller-para-colorear', 6, NULL, '2026-03-16T18:41:08.621Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675667/coloring-web/pascuas/conejo-pintando-huevos-de-pascua-en-un-taller-para-colorear.webp', 'coloring-web/pascuas/conejo-pintando-huevos-de-pascua-en-un-taller-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (266, 'Dibujo para colorear crucero de vacaciones en el mar', 'dibujo-para-colorear-crucero-de-vacaciones-en-el-mar', 'Gran barco crucero navegando por el mar', '<p>Esta gigantesca ciudad flotante representa el ocio y la aventura en alta mar. Con múltiples cubiertas, ventanas de camarotes y chimeneas modernas, el crucero invita a soñar con viajes transatlánticos y la relajación de navegar bajo el sol.</p>
  <h4>Ingeniería naval y recreo</h4>
  <p>El dibujo permite trabajar con la repetición de formas, como las filas de ventanas y botes salvavidas. Ayuda a los niños a entender la escala de los barcos modernos y a practicar la paciencia mientras colorean cada detalle de la estructura.</p>
  <h4>Reflejos en el agua</h4>
  <p>Recomendamos usar azules profundos para el océano y un turquesa suave cerca del casco del barco. Pintar el cielo con un sol radiante completa una escena veraniega que transmite alegría y ganas de explorar el mundo.</p>', 'crucero, barco de vacaciones, barco grande, mar, océano, turismo, viaje en barco', 'dibujo-para-colorear-crucero-de-vacaciones-en-el-mar', 5, NULL, '2026-03-12T02:00:55.172Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280370/coloring-web/vehiculos/dibujo-para-colorear-crucero-de-vacaciones-en-el-mar.webp', 'coloring-web/vehiculos/dibujo-para-colorear-crucero-de-vacaciones-en-el-mar') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
