INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (152, 'Dibujo para colorear de árbitro silbando', 'dibujo-para-colorear-de-arbitro-silbando', 'Árbitro silbando en partido de fútbol', '<p>En el corazón de cada competición deportiva está el árbitro, la figura encargada de velar por el juego limpio y el cumplimiento de las reglas. Con su silbato y sus tarjetas, este dibujo representa la autoridad, la justicia y el orden dentro del deporte.</p>
  <h4>Justicia y reglas del juego</h4>
  <p>Esta lámina es ideal para conversar con los niños sobre el respeto y la honestidad en el juego. El árbitro, en plena acción de pitar una falta, captura un momento de gran tensión y responsabilidad en el campo de fútbol o baloncesto.</p>
  <h4>Colores de uniforme</h4>
  <p>Aunque tradicionalmente visten de negro, hoy los árbitros usan colores neón como el verde o el amarillo para no confundirse con los equipos. Los niños pueden elegir estos tonos modernos para que el personaje resalte en su lámina deportiva.</p>', 'árbitro, silbando, silbato, fútbol, deporte infantil, dibujo deportivo', 'dibujo-para-colorear-de-arbitro-silbando', 4, NULL, '2026-03-07T00:24:27.401Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280238/coloring-web/profesiones-oficios/dibujo-para-colorear-de-arbitro-silbando.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-de-arbitro-silbando') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (469, 'Princesa corriendo en el jardín para colorear | Dibujo dinámico infantil', 'princesa-corriendo-en-el-jardin-para-colorear-or-dibujo-dinamico-infantil', 'Princesa corriendo en un jardín con flores y césped, dibujo lineal para pintar.', '<h3>Movimiento y energía</h3> <p>La escena captura a la princesa en acción, transmitiendo dinamismo y alegría.</p> <h3>Interpretación del movimiento</h3> <p>Los niños pueden experimentar con líneas y colores para dar sensación de velocidad.</p> <h3>Colores vivos</h3> <p>El jardín permite usar verdes intensos y flores coloridas.</p> <h3>Expresión corporal</h3> <p>Ayuda a entender el cuerpo en movimiento.</p>', 'princesa corriendo, jardín, movimiento, dibujo dinámico, naturaleza infantil, diversión, princesa activa, arte niños, ejercicio, fantasía, dibujo animado, actividad, energía, escena exterior, creatividad', 'princesa-corriendo-en-el-jardin-para-colorear-or-dibujo-dinamico-infantil', 8, NULL, '2026-04-01T02:11:20.411Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998679/coloring-web/princesas/princesa-corriendo-en-el-jardin-para-colorear-or-dibujo-dinamico-infantil.webp', 'coloring-web/princesas/princesa-corriendo-en-el-jardin-para-colorear-or-dibujo-dinamico-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
