INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (252, 'Dibujo para colorear bicicleta de montaña', 'dibujo-para-colorear-bicicleta-de-montana', 'Bicicleta de montaña con ruedas grandes para caminos difíciles', '<p>Para los amantes de la aventura y el deporte, esta bicicleta de montaña con ruedas de tacos y suspensión está lista para cualquier terreno. Es un dibujo dinámico que invita a pensar en rutas por el bosque y aire libre.</p>
  <h4>Detalles mecánicos y ruedas</h4>
  <p>Los radios de las ruedas y la cadena requieren un pulso firme y atención. Es un excelente ejercicio de coordinación. Recomendamos colores flúor para el cuadro de la bicicleta, típicos del equipamiento deportivo moderno.</p>
  <h4>Textura de terreno difícil</h4>
  <p>Se puede añadir "barro" a las ruedas usando tonos marrones, simulando que la bicicleta acaba de terminar una ruta difícil. Esto le da un toque realista y aventurero que motiva a los niños a ser activos.</p>', 'bicicleta de montaña, bicicleta, ciclismo, deporte, ruedas grandes, bicicleta deportiva, vehículo sin motor', 'dibujo-para-colorear-bicicleta-de-montana', 5, NULL, '2026-03-12T00:53:44.645Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280352/coloring-web/vehiculos/dibujo-para-colorear-bicicleta-de-montana.webp', 'coloring-web/vehiculos/dibujo-para-colorear-bicicleta-de-montana') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (451, 'Princesa caminando en el bosque para colorear', 'princesa-caminando-en-el-bosque-para-colorear', 'princesa caminando en un bosque dibujo para colorear', 'Dibujo de una princesa caminando por un bosque rodeado de árboles y naturaleza. Es una escena ideal para imprimir y colorear, ya que permite usar distintos tonos en el entorno y el vestuario. Perfecta para que los niños imaginen una aventura en un paisaje natural.', 'princesa bosque, princesa naturaleza, princesa caminando, princesa paisaje, dibujos para colorear princesas', 'princesa-caminando-en-el-bosque-para-colorear', 8, NULL, '2026-03-26T18:29:47.219Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774538986/coloring-web/princesas/princesa-caminando-en-el-bosque-para-colorear.webp', 'coloring-web/princesas/princesa-caminando-en-el-bosque-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
