INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (284, 'Dibujo para colorear tranvía recorriendo la ciudad', 'dibujo-para-colorear-tranvia-recorriendo-la-ciudad', 'Tranvía circulando por una calle de la ciudad', 'Un dibujo detallado de Dibujo para colorear tranvía recorriendo la ciudad, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'tranvía, transporte público, ciudad, transporte urbano, tren ligero, vehículo urbano', 'dibujo-para-colorear-tranvia-recorriendo-la-ciudad', 5, NULL, '2026-03-12T02:23:27.130Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280392/coloring-web/vehiculos/dibujo-para-colorear-tranvia-recorriendo-la-ciudad.webp', 'coloring-web/vehiculos/dibujo-para-colorear-tranvia-recorriendo-la-ciudad') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (372, 'Astronauta recogiendo piedras lunares para colorear', 'astronauta-recogiendo-piedras-lunares-para-colorear', 'astronauta juntando rocas en la luna dibujo para colorear', '<p>La ciencia no se detiene en el espacio exterior. En esta ilustración, vemos a un astronauta realizando tareas de geología lunar, una labor fundamental para entender la composición de los cuerpos celestes y el origen de nuestro sistema solar.</p>

  <h4>Misión científica en la Luna</h4>
  <p>Este dibujo es una herramienta pedagógica ideal para explicar que los astronautas no solo viajan, sino que también son científicos que trabajan en condiciones extremas. Despierta el interés por la investigación y el descubrimiento de nuevos mundos.</p>

  <h4>Cómo pintar el espacio</h4>
  <p>Para que el astronauta resalte, aconsejamos dejar el traje mayormente blanco, aplicando sombras muy suaves en azul claro. Para el suelo lunar, usa diferentes tonos de gris. Un truco especial es dejar pequeños puntos blancos en el cielo para representar estrellas.</p>

  <h4>Despertando la curiosidad</h4>
  <p>Este dibujo motiva a los niños a preguntar sobre la astronomía, los trajes espaciales y la vida fuera de la Tierra. Fomenta el pensamiento crítico y el interés por las materias de ciencia y tecnología desde una edad temprana.</p>', 'astronauta, luna, rocas lunares, espacio, dibujos para colorear', 'astronauta-recogiendo-piedras-lunares-para-colorear', 3, NULL, '2026-03-19T00:52:56.882Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773870775/coloring-web/espacio/astronauta-recogiendo-piedras-lunares-para-colorear.webp', 'coloring-web/espacio/astronauta-recogiendo-piedras-lunares-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (470, 'Princesa feliz con gran sonrisa para colorear | Dibujo infantil de emociones positivas', 'princesa-feliz-con-gran-sonrisa-para-colorear-or-dibujo-infantil-de-emociones-positivas', 'Dibujo de una princesa con una gran sonrisa y expresión alegre, ilustración en blanco y negro lista para colorear.', '<h3>Una expresión que transmite felicidad</h3> <p>Este dibujo destaca una de las emociones más importantes en la infancia: la alegría. La gran sonrisa de la princesa no solo aporta ternura a la ilustración, sino que también invita a los niños a reconocer y expresar sus propias emociones de manera positiva. Es una imagen ideal para trabajar el desarrollo emocional mientras se disfruta de una actividad creativa.</p> <h3>Aprendiendo a identificar emociones</h3> <p>La expresión facial es clara y fácil de interpretar, lo que convierte a este dibujo en una herramienta útil para enseñar a los más pequeños a reconocer gestos de felicidad. A través del coloreado, se puede conversar sobre momentos que generan alegría, fortaleciendo la inteligencia emocional.</p> <h3>Colores que reflejan el estado de ánimo</h3> <p>Se recomienda utilizar colores brillantes y cálidos como amarillo, rosa o celeste para reforzar la sensación de felicidad. También se pueden agregar detalles creativos en el fondo, como corazones o estrellas, para enriquecer la escena.</p> <h3>Una actividad simple pero significativa</h3> <p>Aunque el diseño es sencillo, su valor está en el mensaje que transmite. Este tipo de ilustraciones ayuda a generar un vínculo positivo con el arte, promoviendo el bienestar y la expresión personal desde edades tempranas.</p>', 'princesa feliz, sonrisa grande, emociones infantiles, dibujo de alegría, expresión facial niños, princesa contenta, felicidad infantil, arte para colorear, emociones positivas, dibujo educativo, creatividad niños, princesa sonriente, actividad emocional, ilustración simple, bienestar infantil', 'princesa-feliz-con-gran-sonrisa-para-colorear-or-dibujo-infantil-de-emociones-positivas', 8, NULL, '2026-04-01T02:13:04.159Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998783/coloring-web/princesas/princesa-feliz-con-gran-sonrisa-para-colorear-or-dibujo-infantil-de-emociones-positivas.webp', 'coloring-web/princesas/princesa-feliz-con-gran-sonrisa-para-colorear-or-dibujo-infantil-de-emociones-positivas') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
