INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (373, 'Astronauta saludando a la Tierra desde la luna para colorear', 'astronauta-saludando-a-la-tierra-desde-la-luna-para-colorear', 'astronauta saludando a la tierra desde la luna dibujo para colorear', '<p>No hay vista más hermosa que nuestro planeta visto desde la superficie lunar. Esta ilustración captura la conexión emocional entre el explorador y su hogar, mostrando la belleza de la Tierra suspendida en la inmensidad del espacio.</p>

  <h4>Nuestra casa desde lejos</h4>
  <p>El astronauta saluda a la canica azul, lo que permite a los niños reflexionar sobre la fragilidad de nuestro planeta y la importancia de protegerlo. Es una imagen poderosa que invita a valorar el medio ambiente de manera global.</p>

  <h4>Consejos de aplicación de color</h4>
  <p>La Tierra es la protagonista aquí. Anima a los niños a usar azules intensos para los océanos y verdes vibrantes para los continentes. Para la superficie lunar, se pueden usar trazos circulares en los cráteres para practicar la presión del lápiz y crear texturas.</p>

  <h4>Conciencia global</h4>
  <p>Este ejercicio visual promueve la empatía y la conciencia ecológica. Al pintar el mundo entero en una esquina del dibujo, los niños comprenden que todos compartimos el mismo hogar, reforzando valores de unidad y respeto mutuo.</p>', 'astronauta, tierra, luna, espacio, dibujos para colorear', 'astronauta-saludando-a-la-tierra-desde-la-luna-para-colorear', 3, NULL, '2026-03-19T00:53:36.145Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773870815/coloring-web/espacio/astronauta-saludando-a-la-tierra-desde-la-luna-para-colorear.webp', 'coloring-web/espacio/astronauta-saludando-a-la-tierra-desde-la-luna-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
