INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (370, 'Telescopio observando el cielo estrellado para colorear', 'telescopio-observando-el-cielo-estrellado-para-colorear', 'telescopio apuntando al cielo con estrellas dibujo para colorear', 'Un dibujo detallado de Telescopio observando el cielo estrellado para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'telescopio, estrellas, cielo nocturno, espacio, dibujos para colorear', 'telescopio-observando-el-cielo-estrellado-para-colorear', 3, NULL, '2026-03-19T00:51:00.456Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773870659/coloring-web/espacio/telescopio-observando-el-cielo-estrellado-para-colorear.webp', 'coloring-web/espacio/telescopio-observando-el-cielo-estrellado-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
