INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (450, 'Triceratops en valle con río y montañas para colorear', 'triceratops-en-valle-con-rio-y-montanas-para-colorear', 'triceratops en valle con río y montañas dibujo para colorear', 'Un increíble dibujo de Triceratops en valle con río y montañas para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'triceratops valle, dinosaurio montañas, dinosaurio río, dinosaurio paisaje amplio, dibujos para colorear dinosaurios', 'triceratops-en-valle-con-rio-y-montanas-para-colorear', 7, NULL, '2026-03-24T02:17:28.444Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774307847/coloring-web/dinosaurios/triceratops-en-valle-con-rio-y-montanas-para-colorear.webp', 'coloring-web/dinosaurios/triceratops-en-valle-con-rio-y-montanas-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (435, 'Arquitecto con planos y edificios de fondo para colorear', 'arquitecto-con-planos-y-edificios-de-fondo-para-colorear', 'arquitecto sosteniendo planos con edificios de fondo dibujo para colorear', '<p>Esta escena educativa presenta la figura del arquitecto, el profesional encargado de imaginar y diseñar los espacios donde vivimos. Es una forma visual de acercar a los niños al mundo del diseño urbano y la construcción de ciudades modernas.</p>

  <h4>Construyendo el futuro</h4>
  <p>Al fondo, se observa una ciudad con edificios de diferentes alturas, lo que permite a los niños entender la relación entre un dibujo técnico y la realidad final. Es una excelente manera de fomentar el respeto por las profesiones y el trabajo en equipo.</p>

  <h4>Guía para el artista</h4>
  <p>Aquí la clave es la geometría. Recomendamos usar colores sobrios para los edificios, como grises o azules acero, y resaltar los planos con un azul cian intenso. Para el cielo urbano, un degradado suave dará una sensación de realismo y amplitud.</p>

  <h4>Habilidades cognitivas</h4>
  <p>Colorear estructuras arquitectónicas ayuda a los niños a comprender conceptos de perspectiva, tamaño y proporción. Además, trabajar con líneas rectas y ángulos refuerza la coordinación ojo-mano de una manera muy estructurada.</p>', 'arquitecto, planos, edificios, construcción, profesión arquitecto, ciudad, dibujos para colorear profesiones', 'arquitecto-con-planos-y-edificios-de-fondo-para-colorear', 4, NULL, '2026-03-21T05:33:35.130Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774060414/coloring-web/dinosaurios/arquitecto-con-planos-y-edificios-de-fondo-para-colorear.webp', 'coloring-web/dinosaurios/arquitecto-con-planos-y-edificios-de-fondo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
