INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (347, 'Pollito con flores de primavera para colorear', 'pollito-con-flores-de-primavera-para-colorear', 'pollito rodeado de flores dibujo para colorear', 'Un dibujo detallado de Pollito con flores de primavera para colorear, diseñado con amor para que disfrutes coloreando y pases un momento mágico y creativo.', 'pollito, flores, primavera, pascua infantil, dibujos para colorear', 'pollito-con-flores-de-primavera-para-colorear', 6, NULL, '2026-03-17T00:56:37.822Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773698196/coloring-web/pascuas/pollito-con-flores-de-primavera-para-colorear.webp', 'coloring-web/pascuas/pollito-con-flores-de-primavera-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (10, 'Dibujo de búho realista en una rama para colorear', 'dibujo-de-buho-realista-en-una-rama-para-colorear', 'Ilustración detallada de un búho o lechuza con grandes ojos y plumaje marcado, posado sobre una rama de árbol.', '<p>Cambiamos el estilo por uno más técnico con este impresionante búho. Capturado en una pose estática sobre una rama de árbol, este dibujo destaca por la precisión de sus plumas y la intensidad de su mirada, ideal para los amantes de la ornitología.</p>
  <h4>Desafío de sombreado y textura</h4>
  <p>Al ser un dibujo realista, el reto es simular el volumen de las plumas. Sugerimos usar trazos muy finos y superpuestos, combinando marrones, grises y ocres. Para los ojos, un amarillo brillante con una pupila muy oscura creará un efecto hipnótico.</p>
  <h4>Tips para la rama</h4>
  <p>Recomendamos pintar la rama con tonos madera oscuro y añadir pequeñas manchas verdes para simular musgo o liquen. Esto le da autenticidad a la escena nocturna, demostrando un nivel de detalle avanzado en la obra.</p>
  <h4>Concentración extrema</h4>
  <p>Debido a la gran cantidad de líneas repetitivas en el plumaje, este dibujo requiere mucha paciencia. Ayuda a los niños más grandes o adultos a trabajar la atención sostenida, convirtiendo el coloreado en una forma de meditación activa.</p>', 'búho para colorear, lechuza para pintar, aves nocturnas, dibujo de búho realista, naturaleza, dibujo para adultos y niños.', 'dibujo-de-buho-realista-en-una-rama-para-colorear', 1, NULL, '2026-02-24T00:44:56.557Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280080/coloring-web/animales/dibujo-de-buho-realista-en-una-rama-para-colorear.webp', 'coloring-web/animales/dibujo-de-buho-realista-en-una-rama-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
