INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (121, 'Dibujo para colorear astronauta en cráter lunar', 'dibujo-para-colorear-astronauta-en-crater-lunar', 'Astronauta observando un cráter en la Luna para colorear.', '<p>La geología lunar es la protagonista en esta escena. El astronauta se encuentra dentro de un gran cráter, rodeado de paredes rocosas y formaciones únicas que solo existen en la Luna, listo para recoger muestras científicas.</p>
  <h4>Relieve y geografía espacial</h4>
  <p>Las paredes del cráter ofrecen una oportunidad para trabajar con sombras proyectadas. Los niños pueden imaginar de dónde viene la luz del sol y sombrear un lado de las rocas mientras dejan el otro claro, creando un efecto 3D.</p>
  <h4>Sugerencias de textura</h4>
  <p>Para las rocas lunares, el uso de trazos irregulares y puntos (punteado) con el lápiz gris ayudará a simular la superficie porosa y volcánica de la Luna, diferenciándola del traje liso y tecnológico del astronauta.</p>
  <h4>Espíritu de descubrimiento</h4>
  <p>Este dibujo celebra el valor de la exploración. Fomenta en los niños el deseo de descubrir nuevos lugares y la importancia de la investigación científica para entender el mundo (y los mundos) que nos rodea.</p>', 'astronauta, cráter lunar, luna, espacio, ciencia, superficie lunar, exploración', 'dibujo-para-colorear-astronauta-en-crater-lunar', 3, NULL, '2026-03-03T03:02:44.995Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280193/coloring-web/espacio/dibujo-para-colorear-astronauta-en-crater-lunar.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-en-crater-lunar') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
