INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (376, 'Dinosaurio en paisaje con horizonte amplio para colorear', 'dinosaurio-en-paisaje-con-horizonte-amplio-para-colorear', 'dinosaurio en un paisaje abierto con horizonte amplio dibujo para colorear', 'Un increíble dibujo de Dinosaurio en paisaje con horizonte amplio para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'dinosaurio en un paisaje abierto con horizonte amplio dibujo para colorear', 'dinosaurio-en-paisaje-con-horizonte-amplio-para-colorear', 7, NULL, '2026-03-20T00:49:01.702Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773956940/coloring-web/dinosaurios/dinosaurio-en-paisaje-con-horizonte-amplio-para-colorear.webp', 'coloring-web/dinosaurios/dinosaurio-en-paisaje-con-horizonte-amplio-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (402, 'Dinosaurio en selva con rocas para colorear', 'dinosaurio-en-selva-con-rocas-para-colorear', 'Dinosaurio en selva con rocas para colorear', 'Un increíble dibujo de Dinosaurio en selva con rocas para colorear para que los niños exploren el mundo prehistórico con sus colores favoritos.', 'dinosaurio en selva con rocas dibujo para colorear', 'dinosaurio-en-selva-con-rocas-para-colorear', 7, NULL, '2026-03-20T02:50:02.491Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773964201/coloring-web/dinosaurios/dinosaurio-en-selva-con-rocas-para-colorear.webp', 'coloring-web/dinosaurios/dinosaurio-en-selva-con-rocas-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (246, 'Dibujo para colorear autobús urbano simple', 'dibujo-para-colorear-autobus-urbano-simple', 'Autobús urbano circulando por una calle de la ciudad', 'Un dibujo detallado de Dibujo para colorear autobús urbano <p>Este diseño presenta un transporte público clásico de ciudad con líneas rectas y grandes ventanales. Es una ilustración ideal para que los niños reconozcan el vehículo que ven a diario en las calles, fomentando el interés por la movilidad urbana.</p>
  <h4>Formas geométricas básicas</h4>
  <p>Al ser un diseño "simple", permite trabajar la precisión en rectángulos y cuadrados. Los niños pueden colorear cada ventana de forma individual e incluso dibujar a los pasajeros dentro, personalizando el viaje a su gusto.</p>
  <h4>Sugerencias de color</h4>
  <p>Recomendamos usar colores llamativos como el rojo, azul o verde para la carrocería, típicos de las flotas urbanas. Dejar los faros en blanco o amarillo brillante le dará un toque de realismo y dinamismo al vehículo.</p>', 'autobús urbano, bus de ciudad, transporte público, ciudad, colectivo, transporte urbano, vehículo de pasajeros, movilidad urbana', 'dibujo-para-colorear-autobus-urbano-simple', 5, NULL, '2026-03-12T00:51:19.074Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280344/coloring-web/vehiculos/dibujo-para-colorear-autobus-urbano-simple.webp', 'coloring-web/vehiculos/dibujo-para-colorear-autobus-urbano-simple') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (248, 'Dibujo para colorear avión comercial en el aeropuerto', 'dibujo-para-colorear-avion-comercial-en-el-aeropuerto', 'Avión comercial de pasajeros estacionado en el aeropuerto', '<p>Esta escena captura el momento previo al despegue de un gran avión de pasajeros en la terminal. Rodeado de la pista y señales aeroportuarias, transmite la emoción de viajar y descubrir nuevos destinos alrededor del mundo.</p>
  <h4>Perspectiva y escala</h4>
  <p>El dibujo permite trabajar la amplitud del aeropuerto. Al colorear el fuselaje largo y las turbinas, los niños desarrollan la noción de proporción y escala, comparando el tamaño del avión con los elementos de la pista.</p>
  <h4>Tips para el cielo y la pista</h4>
  <p>Recomendamos un cielo azul despejado y una pista en gris asfalto con líneas amarillas de seguridad. Para el avión, colores blancos o plateados con franjas coloridas en la cola le darán el aspecto de una aerolínea real.</p>', 'avión comercial, avión de pasajeros, aeropuerto, transporte aéreo, aviación, viaje en avión, aerolínea, aeronave', 'dibujo-para-colorear-avion-comercial-en-el-aeropuerto', 5, NULL, '2026-03-12T00:52:08.024Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280346/coloring-web/vehiculos/dibujo-para-colorear-avion-comercial-en-el-aeropuerto.webp', 'coloring-web/vehiculos/dibujo-para-colorear-avion-comercial-en-el-aeropuerto') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (255, 'Dibujo para colorear camión de bomberos de rescate', 'dibujo-para-colorear-camion-de-bomberos-de-rescate', 'Camión de bomberos listo para atender una emergencia', '<p>A diferencia de los camiones de extinción, el vehículo de rescate lleva equipos especiales como cizallas, cuerdas y sistemas de iluminación. Es el "hospital móvil" y la caja de herramientas gigante que llega primero a los accidentes.</p>
  <h4>Diseño de vehículos de emergencia</h4>
  <p>La ilustración cuenta con múltiples compartimentos laterales. Los niños pueden imaginar qué hay dentro de cada uno mientras eligen colores. Las luces de emergencia (sirenas) se ven geniales si se pintan con un degradado de azul y blanco.</p>
  <h4>Valor de la ayuda rápida</h4>
  <p>Colorear este vehículo fomenta la seguridad vial y el respeto por los conductores de emergencia. Es un dibujo que transmite protección y orden, ideal para trabajar la confianza infantil en las instituciones.</p>', 'camión de bomberos, bomberos, rescate, emergencia, vehículo de emergencia, incendio, sirena, servicio de rescate', 'dibujo-para-colorear-camion-de-bomberos-de-rescate', 5, NULL, '2026-03-12T01:55:49.071Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280355/coloring-web/vehiculos/dibujo-para-colorear-camion-de-bomberos-de-rescate.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-de-bomberos-de-rescate') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (371, 'Astronauta saludando desde una nave espacial para colorear', 'astronauta-saludando-desde-una-nave-espacial-para-colorear', 'astronauta saludando desde una nave espacial dibujo para colorear', '<p>La tecnología espacial cobra vida en este dibujo que muestra el interior de una cabina de mando. Los niños pueden observar escotillas, paneles de control y antenas, elementos técnicos que definen a las naves modernas de exploración.</p>

  <h4>Viajeros intergalácticos</h4>
  <p>Es una invitación a soñar con el turismo espacial y con la posibilidad de que, en el futuro, viajar entre planetas sea una actividad cotidiana. Esta escena fomenta la visión de un futuro lleno de descubrimientos y nuevas fronteras por cruzar.</p>

  <h4>Tips de diseño y color</h4>
  <p>Las naves suelen tener muchos detalles pequeños y metálicos. Un buen consejo es usar colores como plata o cobre si tienen lápices especiales. Para las luces de control, se pueden usar puntos de colores brillantes para que parezca que la nave está activa.</p>

  <h4>Precisión y enfoque</h4>
  <p>Debido a la cantidad de botones y piezas mecánicas, este dibujo es un reto de concentración. Ayuda a los niños a trabajar en áreas pequeñas sin salirse del contorno, lo que mejora drásticamente la motricidad fina y la atención sostenida.</p>', 'astronauta, nave espacial, espacio, exploración, dibujos para colorear', 'astronauta-saludando-desde-una-nave-espacial-para-colorear', 3, NULL, '2026-03-19T00:52:11.783Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773870727/coloring-web/espacio/astronauta-saludando-desde-una-nave-espacial-para-colorear.webp', 'coloring-web/espacio/astronauta-saludando-desde-una-nave-espacial-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (356, 'Bruja buena volando en su escoba para colorear', 'bruja-buena-volando-en-su-escoba-para-colorear', 'bruja buena volando en una escoba dibujo para colorear', '<p>Rompiendo con los mitos tradicionales, esta brujita es un símbolo de sabiduría y bondad. Vuela feliz sobre su escoba mágica, mostrándonos que la magia puede ser una fuerza positiva y llena de alegría para ayudar a los demás.</p>

  <h4>Magia en el cielo nocturno</h4>
  <p>Los elementos decorativos como las estrellas y las nubes completan una escena llena de paz. Es una ilustración ideal para trabajar temas de fantasía de una forma segura y amigable, perfecta para decorar espacios infantiles.</p>

  <h4>Guía de estilo</h4>
  <p>Para la ropa de la bruja, el violeta y el negro son combinaciones clásicas. Para el rastro que deja al volar, se pueden hacer pequeñas líneas amarillas para simular polvo de estrellas. Esto le da dinamismo al dibujo y una sensación de vuelo real.</p>

  <h4>Desarrollo de la narrativa</h4>
  <p>Al pintar este personaje, se anima a los niños a imaginar una historia de fondo. ¿A dónde se dirige? ¿Qué tipo de hechizos bondadosos realiza? Esto fortalece las habilidades lingüísticas y la capacidad de crear relatos coherentes.</p>', 'bruja buena, magia, fantasía, escoba voladora, dibujos para colorear', 'bruja-buena-volando-en-su-escoba-para-colorear', 2, NULL, '2026-03-18T00:49:13.374Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773784152/coloring-web/fantasia/bruja-buena-volando-en-su-escoba-para-colorear.webp', 'coloring-web/fantasia/bruja-buena-volando-en-su-escoba-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (365, 'Caballero luchando con un dragón para colorear', 'caballero-luchando-con-un-dragon-para-colorear', 'caballero luchando contra un dragón dibujo para colorear', '<p>El caballero y el dragón representan el clásico conflicto de las leyendas medievales. En este dibujo, la acción es la protagonista absoluta, capturando el choque entre la valentía humana y el poder de una criatura mitológica.</p>

  <h4>Una leyenda de valor</h4>
  <p>Es una oportunidad para hablar sobre las virtudes de los antiguos caballeros, como el coraje y la nobleza. La ilustración sumerge a los niños en un mundo de castillos y aventuras épicas que han perdurado a través de los siglos.</p>

  <h4>Técnicas de sombreado</h4>
  <p>Este es el dibujo perfecto para practicar contrastes. Sugerimos pintar el fuego del dragón con colores cálidos intensos. Para la armadura, dejar espacios en blanco creará un efecto de brillo metálico muy realista ante el fuego.</p>

  <h4>Emoción y adrenalina</h4>
  <p>La naturaleza dinámica de esta imagen mantiene el interés de principio a fin. Permite a los pequeños artistas canalizar su energía y experimentar la satisfacción de completar una escena compleja llena de detalles heroicos.</p>', 'caballero, dragón, fantasía, aventuras, dibujos para colorear', 'caballero-luchando-con-un-dragon-para-colorear', 2, NULL, '2026-03-18T00:54:04.315Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773784443/coloring-web/fantasia/caballero-luchando-con-un-dragon-para-colorear.webp', 'coloring-web/fantasia/caballero-luchando-con-un-dragon-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (298, 'Canasta con huevos de Pascua decorados para colorear', 'canasta-con-huevos-de-pascua-decorados-para-colorear', 'canasta con huevos de pascua decorados dibujo para colorear', '<p>Esta ilustración presenta una elegante canasta de mimbre tejida a mano, repleta de huevos de Pascua que exhiben diversos patrones geométricos. Es una escena clásica que celebra la creatividad y las tradiciones familiares durante la temporada de primavera.</p>

  <h4>Diseños y patrones creativos</h4>
  <p>Cada huevo en la canasta ofrece un diseño único, desde rayas horizontales hasta flores intrincadas. Esto permite a los niños explorar diferentes combinaciones de colores y patrones, convirtiendo cada huevo en una pequeña obra de arte individual dentro del conjunto.</p>

  <h4>Consejos para colorear</h4>
  <p>Sugerimos usar una paleta de colores pastel como el lavanda, el verde menta y el amarillo pálido. Para la canasta, el uso de trazos cruzados en tonos marrones ayudará a dar una textura de mimbre muy realista y profundidad a la base del dibujo.</p>

  <h4>Desarrollo de la motricidad</h4>
  <p>Al tener tantos detalles pequeños en cada huevo, esta actividad es excelente para mejorar el control del lápiz. Fomenta la paciencia y la atención al detalle, ayudando a los niños a concentrarse en completar una composición armoniosa y colorida.</p>', 'huevos de pascua, canasta de pascua, dibujos de pascua, pascua infantil', 'canasta-con-huevos-de-pascua-decorados-para-colorear', 6, NULL, '2026-03-16T18:32:19.317Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675138/coloring-web/pascuas/canasta-con-huevos-de-pascua-decorados-para-colorear.webp', 'coloring-web/pascuas/canasta-con-huevos-de-pascua-decorados-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (459, 'Princesa y Cielo Estrellado para Colorear | Dibujo de Noche y Astronomía', 'princesa-y-cielo-estrellado-para-colorear-or-dibujo-de-noche-y-astronomia', 'Dibujo lineal de una princesa observando el cielo nocturno con estrellas y una luna creciente, fondo blanco para pintar.', '<h3>Descubriendo los misterios del cosmos</h3>
<p>Esta ilustración nos muestra a una princesa en un momento de profunda admiración ante la inmensidad del universo. Mirando hacia el cielo estrellado, la escena invita a los niños a hacerse preguntas sobre el espacio y los astros. Es un dibujo que combina la fantasía de la realeza con la curiosidad científica, ideal para una actividad educativa nocturna.</p>

<h3>Elementos del firmamento nocturno</h3>
<p>En la composición destacan estrellas de diferentes tamaños y una luna creciente que corona la escena. La mirada hacia arriba de la princesa crea una línea de acción que guía el ojo del espectador hacia el cielo. Al ser un diseño de fondo blanco, ofrece total libertad para decidir si se quiere representar una noche de verano clara o un cielo lleno de nubes mágicas.</p>

<h3>Técnicas de contraste y luminosidad</h3>
<p>Para lograr un efecto de "brillo", sugerimos pintar el cielo con un color azul muy oscuro o negro, dejando los bordes de las estrellas y la luna totalmente blancos o en amarillo muy pálido. Esta técnica de contraste hace que los elementos lumínicos resalten con fuerza. La princesa puede llevar colores fríos como el lila o el plateado para armonizar con la temática de la noche.</p>

<h3>Fomento de la calma y la curiosidad</h3>
<p>Colorear escenas nocturnas tiene un efecto relajante comprobado en los niños, lo que la convierte en la actividad perfecta para realizar antes de dormir. Mientras pintan las constelaciones, los padres pueden aprovechar para enseñar los nombres de las estrellas o hablar sobre la importancia de la luz en la oscuridad, estimulando tanto la imaginación como el conocimiento básico de astronomía.</p>', 'princesa estrellas, cielo nocturno, astronomía infantil, luna creciente, constelaciones, noche para colorear, dibujo de fantasía, estrellas brillantes, mirar al cielo, cosmos para niños, tranquilidad nocturna, cuento de buenas noches, dibujo lineal noche, arte espacial, relajación infantil.', 'princesa-y-cielo-estrellado-para-colorear-or-dibujo-de-noche-y-astronomia', 8, NULL, '2026-04-01T01:59:17.200Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774997956/coloring-web/princesas/princesa-y-cielo-estrellado-para-colorear-or-dibujo-de-noche-y-astronomia.webp', 'coloring-web/princesas/princesa-y-cielo-estrellado-para-colorear-or-dibujo-de-noche-y-astronomia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (300, 'Canasta de huevos de Pascua con pollito para colorear', 'canasta-de-huevos-de-pascua-con-pollito-para-colorear', 'pollito junto a una canasta con huevos de pascua para colorear', '<p>En este tierno dibujo, un pequeño pollito recién nacido se asoma curiosamente desde el interior de una canasta de Pascua. La combinación de la vida animal con los elementos decorativos crea una escena llena de dulzura y vitalidad primaveral.</p>

  <h4>Simbolismo de la vida nueva</h4>
  <p>La imagen captura el momento exacto en que la naturaleza despierta. Es una oportunidad ideal para que los padres expliquen a los niños el significado del nacimiento y el renacimiento, temas centrales en muchas festividades alrededor del mundo durante esta época.</p>

  <h4>Guía para el artista</h4>
  <p>Para el pollito, recomendamos usar un amarillo vibrante y suave. Para resaltar su plumaje, se pueden hacer trazos muy cortos y finos. Los huevos que lo rodean pueden pintarse de colores contrastantes para que la figura central del pollito sea el foco de atención.</p>

  <h4>Habilidades emocionales</h4>
  <p>Colorear animales bebés suele generar una respuesta de ternura y calma en los niños. Esta actividad promueve la empatía y el afecto por los seres vivos, proporcionando un momento de relajación y disfrute creativo en casa o en el aula.</p>', 'pollito de pascua, huevos de pascua, canasta de pascua, dibujos de pascua, colorear', 'canasta-de-huevos-de-pascua-con-pollito-para-colorear', 6, NULL, '2026-03-16T18:33:34.421Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675213/coloring-web/pascuas/canasta-de-huevos-de-pascua-con-pollito-para-colorear.webp', 'coloring-web/pascuas/canasta-de-huevos-de-pascua-con-pollito-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (299, 'Canasta grande de huevos de Pascua con flores para colorear', 'canasta-grande-de-huevos-de-pascua-con-flores-para-colorear', 'canasta grande con huevos de pascua y flores para colorear', '<p>Esta composición destaca por su abundancia, mostrando una canasta de gran tamaño rodeada de flores silvestres. Es un diseño que integra la decoración tradicional de Pascua con la belleza botánica de un jardín en pleno florecimiento.</p>

  <h4>Armonía entre naturaleza y tradición</h4>
  <p>La presencia de margaritas y tulipanes alrededor de la canasta añade una capa de complejidad al dibujo. Los niños no solo colorean objetos, sino un entorno natural completo, lo que les ayuda a comprender la relación entre las festividades y las estaciones del año.</p>

  <h4>Sugerencias de aplicación de color</h4>
  <p>Animamos a usar colores muy vivos para las flores, como el magenta o el violeta intenso. Para los huevos dentro de la canasta, un consejo técnico es aplicar brillos blancos en la parte superior para que parezcan tener una superficie lisa y pulida.</p>

  <h4>Beneficios de la observación</h4>
  <p>Este dibujo requiere que el niño identifique diferentes tipos de elementos vegetales y decorativos. Mejora la agudeza visual y la capacidad de organizar una paleta de colores extensa sin que la imagen se vea sobrecargada, buscando siempre el equilibrio.</p>', 'pascua, huevos de pascua, flores, canasta de pascua, dibujos para colorear, primavera', 'canasta-grande-de-huevos-de-pascua-con-flores-para-colorear', 6, NULL, '2026-03-16T18:33:05.885Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675185/coloring-web/pascuas/canasta-grande-de-huevos-de-pascua-con-flores-para-colorear.webp', 'coloring-web/pascuas/canasta-grande-de-huevos-de-pascua-con-flores-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (297, 'Canasta llena de huevos de Pascua para colorear', 'canasta-llena-de-huevos-de-pascua-para-colorear', 'canasta llena de huevos de pascua dibujo para colorear', '<p>Esta ilustración se enfoca en la generosidad de la cosecha de Pascua, con una canasta desbordante de huevos listos para ser escondidos. Es un dibujo con líneas claras y espacios amplios, ideal para los artistas que disfrutan rellenando grandes áreas de color.</p>

  <h4>Un desafío de repetición y estilo</h4>
  <p>Al haber tantos huevos similares, los niños pueden experimentar repitiendo patrones o creando un arcoíris de colores. Es un ejercicio fantástico para entender cómo el color puede cambiar la percepción de una misma forma repetida varias veces.</p>

  <h4>Tips de pintura</h4>
  <p>Un truco interesante es asignar un "tema" a la canasta: por ejemplo, huevos de colores cálidos (rojos, naranjas) y una canasta de color frío (azul oscuro). Esto crea un contraste visual muy potente que hace que el dibujo destaque inmediatamente.</p>

  <h4>Fomento de la concentración</h4>
  <p>Completar una canasta con tantos elementos individuales ayuda a los niños a mantener la atención en una tarea larga. La satisfacción de ver la canasta "llena" de color al final refuerza su autoestima y su persistencia en proyectos creativos.</p>', 'pascua, huevos de pascua, canasta de pascua, dibujos de pascua, colorear, imprimir, actividades infantiles', 'canasta-llena-de-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:31:38.540Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675097/coloring-web/pascuas/canasta-llena-de-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/canasta-llena-de-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (304, 'Conejito feliz con zanahoria para colorear', 'conejito-feliz-con-zanahoria-para-colorear', 'conejo de pascua feliz con una zanahoria dibujo para colorear', '<p>Este simpático conejito sostiene su comida favorita en una escena llena de alegría y simplicidad. Con orejas largas y una expresión amigable, es un diseño perfecto para introducir a los niños más pequeños en el mundo del coloreado de animales.</p>

  <h4>Nutrición y naturaleza</h4>
  <p>La zanahoria no es solo un elemento decorativo, sino una forma de enseñar a los niños sobre los hábitos alimenticios saludables de los animales. Es un dibujo que transmite bienestar y satisfacción a través de un personaje muy querido.</p>

  <h4>Consejos de estilo</h4>
  <p>Para que el conejo se vea esponjoso, se pueden usar colores muy claros y suaves. Para la zanahoria, un naranja vibrante con hojas verdes intensas creará un contraste excelente que hará que el dibujo se sienta vivo y lleno de energía.</p>

  <h4>Logros tempranos</h4>
  <p>Al tener formas grandes y definidas, este dibujo permite que los niños con menos experiencia logren un resultado excelente rápidamente. Esto motiva su interés por seguir dibujando y mejora su confianza en sus propias capacidades artísticas.</p>', 'conejo de pascua, zanahoria, dibujos de pascua, colorear, pascua infantil', 'conejito-feliz-con-zanahoria-para-colorear', 6, NULL, '2026-03-16T18:36:03.636Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675362/coloring-web/pascuas/conejito-feliz-con-zanahoria-para-colorear.webp', 'coloring-web/pascuas/conejito-feliz-con-zanahoria-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (317, 'Conejo bajo un árbol con huevos de Pascua escondidos para colorear', 'conejo-bajo-un-arbol-con-huevos-de-pascua-escondidos-para-colorear', 'conejo debajo de un árbol con huevos de pascua escondidos dibujo para colorear', '<p>Esta ilustración captura el clásico juego de la búsqueda de huevos de Pascua. Un conejo descansa bajo la sombra de un gran roble, mientras varios huevos se asoman discretamente entre las raíces y los arbustos cercanos.</p>

  <h4>El misterio de la búsqueda</h4>
  <p>El dibujo invita a los niños a jugar antes de empezar a pintar: ¿puedes encontrar todos los huevos escondidos? Esta interacción previa hace que la actividad sea mucho más que un simple ejercicio de coloreado, convirtiéndola en un pequeño reto visual.</p>

  <h4>Guía de color para exteriores</h4>
  <p>Sugerimos usar diferentes tonos de marrón para el tronco del árbol y verdes variados para el follaje. Para los huevos escondidos, el uso de colores brillantes ayudará a que "resalten" entre la naturaleza, tal como ocurriría en una búsqueda real.</p>

  <h4>Percepción y espacio</h4>
  <p>Al trabajar con diferentes planos (el conejo al frente, el árbol detrás y los huevos entre medias), los niños practican la percepción de profundidad. Es una lección básica de composición que ayuda a organizar mejor los elementos en una página.</p>', 'conejo de pascua, esconder huevos, árbol, pascua infantil, dibujos para colorear', 'conejo-bajo-un-arbol-con-huevos-de-pascua-escondidos-para-colorear', 6, NULL, '2026-03-16T18:42:47.952Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675767/coloring-web/pascuas/conejo-bajo-un-arbol-con-huevos-de-pascua-escondidos-para-colorear.webp', 'coloring-web/pascuas/conejo-bajo-un-arbol-con-huevos-de-pascua-escondidos-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (318, 'Conejo caminando con canasta de huevos de Pascua para colorear', 'conejo-caminando-con-canasta-de-huevos-de-pascua-para-colorear', 'conejo caminando con una canasta llena de huevos de pascua dibujo para colorear', '<p>En este dibujo vemos a un conejo emprendedor en pleno movimiento, transportando su canasta de huevos por un sendero. La postura dinámica sugiere que está en camino a entregar los regalos de Pascua a los niños de todo el mundo.</p>

  <h4>Narrativa en movimiento</h4>
  <p>La imagen cuenta una historia de responsabilidad y esfuerzo. Los niños pueden imaginar hacia dónde se dirige el conejo y qué aventuras encontrará en su camino, lo que estimula enormemente su capacidad de crear cuentos e historias fantásticas.</p>

  <h4>Consejos para dar dinamismo</h4>
  <p>Un consejo es colorear el sendero con tonos claros y dejar el fondo un poco más suave para que la figura del conejo caminando destaque. El uso de líneas de color suaves en la dirección del movimiento puede ayudar a que la escena se sienta más real.</p>

  <h4>Coordinación rítmica</h4>
  <p>Colorear una figura en movimiento requiere que el niño adapte sus trazos a las curvas de las patas y las orejas inclinadas. Esto mejora la fluidez del movimiento de la mano y la precisión técnica en dibujos que no son estáticos.</p>', 'conejo de pascua, canasta de huevos, esconder huevos, pascua infantil, dibujos para colorear', 'conejo-caminando-con-canasta-de-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:43:12.451Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675791/coloring-web/pascuas/conejo-caminando-con-canasta-de-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-caminando-con-canasta-de-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (350, 'Conejo de Pascua con canasta de huevos de Pascua para colorear', 'conejo-de-pascua-con-canasta-de-huevos-de-pascua-para-colorear', 'conejo junto a una canasta con huevos de pascua dibujo para colorear', '<p>En este diseño, el conejo de Pascua se presenta en su rol más tradicional: el repartidor de alegría. Sostiene con orgullo una canasta de mimbre repleta de huevos decorados, listo para iniciar su jornada de entregas por todo el mundo.</p>

  <h4>Tradiciones que cobran vida</h4>
  <p>Esta figura icónica ayuda a los niños a conectar con las celebraciones culturales. La canasta está diseñada con un entramado claro que invita a practicar la paciencia al colorear cada sección del tejido de madera de forma individual.</p>

  <h4>Guía para el artista</h4>
  <p>Recomendamos usar un marrón cálido para la canasta y dejar que los huevos aporten el contraste. Para el pelaje del conejo, el uso de trazos muy suaves con la punta del lápiz puede simular la textura del algodón, dándole un acabado más profesional.</p>

  <h4>Enfoque y perseverancia</h4>
  <p>Completar un dibujo con tantos elementos repetidos (como los huevos dentro de la canasta) entrena la capacidad de los niños para terminar tareas que requieren esfuerzo sostenido, fortaleciendo su disciplina creativa.</p>', 'conejo, canasta de huevos, huevos de pascua, dibujos para colorear', 'conejo-de-pascua-con-canasta-de-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-17T00:58:58.015Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773698337/coloring-web/pascuas/conejo-de-pascua-con-canasta-de-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-de-pascua-con-canasta-de-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (306, 'Conejo de Pascua con flores para colorear', 'conejo-de-pascua-con-flores-para-colorear', 'conejo de pascua rodeado de flores dibujo para colorear', '<p>La primavera se hace presente en este dibujo donde un conejo de Pascua aparece rodeado de una exuberante variedad de flores silvestres. Es una oda a la naturaleza y al florecimiento que acompaña a esta época del año.</p>

  <h4>El despertar del jardín</h4>
  <p>La combinación de la fauna con la flora permite a los niños explorar una paleta de colores mucho más amplia. Los tulipanes, margaritas y hojas verdes crean un marco natural que realza la figura central del conejo.</p>

  <h4>Sugerencias de aplicación de color</h4>
  <p>Animamos a utilizar colores "eléctricos" para las flores, como el fucsia o el violeta, mientras que para el conejo se puede optar por un blanco puro con sombras grises o un café claro, para que no compita con el colorido fondo floral.</p>

  <h4>Apreciación estética</h4>
  <p>Este dibujo fomenta la sensibilidad hacia la belleza de los detalles naturales. Al distinguir entre pétalos, tallos y estambres, los niños agudizan su visión y aprenden a valorar la complejidad de los seres vivos.</p>', 'conejo de pascua, flores, primavera, dibujos para colorear, pascua infantil', 'conejo-de-pascua-con-flores-para-colorear', 6, NULL, '2026-03-16T18:36:46.973Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675405/coloring-web/pascuas/conejo-de-pascua-con-flores-para-colorear.webp', 'coloring-web/pascuas/conejo-de-pascua-con-flores-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (322, 'Conejo de Pascua sentado para colorear', 'conejo-de-pascua-sentado-para-colorear', 'conejo de pascua sentado dibujo para colorear', '<p>A veces, incluso el conejo de Pascua necesita un descanso. Esta ilustración muestra al personaje en una pose tranquila y contemplativa, sentado pacíficamente mientras observa el entorno antes de continuar con sus labores.</p>

  <h4>Momentos de calma y paz</h4>
  <p>A diferencia de los dibujos de acción, esta escena transmite serenidad. Es perfecta para sesiones de coloreado relajantes antes de dormir o para momentos en los que se busca reducir la hiperactividad a través del arte.</p>

  <h4>Tips de sombreado</h4>
  <p>Al ser una pose estática, es el momento ideal para practicar las sombras en el suelo. Sugerimos pintar una mancha ovalada oscura bajo el conejo para darle peso y volumen a la figura, evitando que parezca que está "flotando" en la página.</p>

  <h4>Auto-reflexión creativa</h4>
  <p>Pintar un personaje en reposo invita al niño a calmar su propio ritmo. Ayuda a desarrollar la introspección y permite que el proceso artístico sea una forma de meditación guiada por la forma y el color.</p>', 'conejo de pascua, dibujos para colorear, pascua infantil', 'conejo-de-pascua-sentado-para-colorear', 6, NULL, '2026-03-16T18:46:04.713Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675963/coloring-web/pascuas/conejo-de-pascua-sentado-para-colorear.webp', 'coloring-web/pascuas/conejo-de-pascua-sentado-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (307, 'Conejo empujando carretilla con huevos de Pascua para colorear', 'conejo-empujando-carretilla-con-huevos-de-pascua-para-colorear', 'conejo empujando una carretilla llena de huevos de pascua dibujo para colorear', '<p>La laboriosidad es el tema central de esta imagen. El conejo realiza el esfuerzo físico de empujar una carretilla cargada, lo que añade un elemento de movimiento y propósito a la ilustración de Pascua tradicional.</p>

  <h4>El valor del esfuerzo</h4>
  <p>Esta escena permite hablar con los niños sobre la importancia del trabajo y la satisfacción de completar una tarea difícil. La carretilla, con su rueda y estructura, añade un toque de mecánica que fascina a muchos pequeños artistas.</p>

  <h4>Consejos técnicos</h4>
  <p>Para la carretilla, sugerimos colores metálicos o madera oscura. Es importante usar un color fuerte para la rueda para que se note que es la base del movimiento. Los huevos deben pintarse con colores muy distintos entre sí para simular variedad.</p>

  <h4>Coordinación motora</h4>
  <p>Seguir las líneas de los brazos del conejo y los mangos de la carretilla requiere una coordinación mano-ojo muy precisa. Este dibujo es excelente para fortalecer los músculos de la mano encargados de la escritura.</p>', 'conejo de pascua, huevos de pascua, carretilla, pascua infantil, colorear', 'conejo-empujando-carretilla-con-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:38:01.092Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675480/coloring-web/pascuas/conejo-empujando-carretilla-con-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-empujando-carretilla-con-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (323, 'Conejo empujando carretilla con huevos en el jardín para colorear', 'conejo-empujando-carretilla-con-huevos-en-el-jardin-para-colorear', 'conejo empujando carretilla con huevos en un jardín dibujo para colorear', '<p>En esta versión de la carretilla, el escenario cobra protagonismo. El conejo recorre un jardín detallado con piedras, césped y pequeños insectos que lo observan pasar, creando una atmósfera de campo muy completa.</p>

  <h4>Un ecosistema en miniatura</h4>
  <p>Al añadir elementos de jardín como piedritas o briznas de hierba, el dibujo se convierte en un reto de texturas. Los niños aprenden que el suelo no es solo una línea plana, sino un conjunto de elementos orgánicos diversos.</p>

  <h4>Guía de paisajes</h4>
  <p>Recomendamos pintar el césped con trazos verticales cortos de abajo hacia arriba para simular el crecimiento de la hierba. Para el camino, un tono grisáceo o arena ayudará a que los elementos del jardín se vean integrados y realistas.</p>

  <h4>Observación del entorno</h4>
  <p>Este dibujo fomenta que los niños se fijen en los pequeños detalles que solemos pasar por alto. Al colorear un jardín, desarrollan una mayor conciencia sobre el mundo exterior y los pequeños seres que lo habitan.</p>', 'conejo de pascua, carretilla, jardín, huevos de pascua, dibujos para colorear', 'conejo-empujando-carretilla-con-huevos-en-el-jardin-para-colorear', 6, NULL, '2026-03-16T18:46:27.568Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675986/coloring-web/pascuas/conejo-empujando-carretilla-con-huevos-en-el-jardin-para-colorear.webp', 'coloring-web/pascuas/conejo-empujando-carretilla-con-huevos-en-el-jardin-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (325, 'Conejo en campo con huevos de Pascua y casa para colorear', 'conejo-en-campo-con-huevos-de-pascua-y-casa-para-colorear', 'conejo en un campo lleno de huevos de pascua con una casa de fondo dibujo para colorear', '<p>Esta ilustración nos ofrece una vista panorámica que incluye una pequeña casa de campo al fondo. El conejo se encuentra en el jardín delantero, rodeado de huevos, creando una sensación de hogar y calidez familiar.</p>

  <h4>El concepto de hogar y pertenencia</h4>
  <p>La inclusión de una casa permite a los niños trabajar con colores arquitectónicos (techos, ventanas, paredes) mezclados con colores naturales. Es una escena que evoca seguridad y la alegría de celebrar las fiestas en casa.</p>

  <h4>Efectos de profundidad</h4>
  <p>Un buen consejo es pintar la casa con colores más suaves o tenues que el conejo que está al frente. Esto crea un efecto de "lejanía" que ayuda a los niños a entender cómo funciona la profundidad en un paisaje real.</p>

  <h4>Planificación visual</h4>
  <p>Al ser un dibujo con muchos elementos grandes (casa, cielo, campo, personaje), requiere que el niño planee su trabajo para que los colores no se mezclen de forma desordenada, fomentando el pensamiento lógico.</p>', 'conejo de pascua, campo, huevos de pascua, casa, dibujos para colorear', 'conejo-en-campo-con-huevos-de-pascua-y-casa-para-colorear', 6, NULL, '2026-03-16T18:47:43.221Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676062/coloring-web/pascuas/conejo-en-campo-con-huevos-de-pascua-y-casa-para-colorear.webp', 'coloring-web/pascuas/conejo-en-campo-con-huevos-de-pascua-y-casa-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (462, 'Princesa mágica lanzando hechizos para colorear | Dibujo de fantasía', 'princesa-magica-lanzando-hechizos-para-colorear-or-dibujo-de-fantasia', 'Princesa con varita mágica lanzando destellos y chispas en un dibujo lineal para colorear.', '<h3>Un mundo lleno de magia</h3> <p>La princesa usa su varita para crear destellos mágicos, una escena que despierta la imaginación y el gusto por la fantasía.</p> <h3>Jugando con efectos brillantes</h3> <p>Las chispas y estrellas permiten experimentar con colores llamativos como amarillo, violeta y azul.</p> <h3>Creatividad sin límites</h3> <p>Los niños pueden inventar nuevos poderes y efectos mientras colorean.</p> <h3>Ideal para historias mágicas</h3> <p>Perfecto para complementar cuentos y juegos de rol.</p>', 'princesa magia, varita mágica, hechizos, fantasía infantil, magia para colorear, estrellas mágicas, cuento de hadas, poderes mágicos, dibujo creativo, imaginación, brillo, magia divertida, arte infantil, princesa hechicera, ilusión', 'princesa-magica-lanzando-hechizos-para-colorear-or-dibujo-de-fantasia', 8, NULL, '2026-04-01T02:06:46.119Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998405/coloring-web/princesas/princesa-magica-lanzando-hechizos-para-colorear-or-dibujo-de-fantasia.webp', 'coloring-web/princesas/princesa-magica-lanzando-hechizos-para-colorear-or-dibujo-de-fantasia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (309, 'Conejo en un campo con huevos de Pascua para colorear', 'conejo-en-un-campo-con-huevos-de-pascua-para-colorear', 'conejo en un campo rodeado de huevos de pascua dibujo para colorear', '<p>Esta ilustración se centra en la libertad del espacio abierto. Un campo infinito sirve de escenario para que el conejo de Pascua realice su búsqueda de huevos bajo un cielo despejado, representando la esencia pura de la festividad.</p>

  <h4>Libertad y espacios abiertos</h4>
  <p>La sencillez de este campo permite que el niño se enfoque en degradados. El cielo y el suelo son grandes áreas donde se puede practicar la presión del lápiz para crear cielos que cambian de azul oscuro a claro.</p>

  <h4>Guía de color para principiantes</h4>
  <p>Al no tener elementos arquitectónicos complejos, es un dibujo ideal para iniciarse en los paisajes. Recomendamos un verde pradera para el suelo y un azul celeste para el cielo, dejando que los huevos sean los "puntos de luz" de la obra.</p>

  <h4>Satisfacción al completar</h4>
  <p>Pintar grandes fondos da una sensación de logro muy alta. El niño siente que ha "llenado" un mundo entero con su color, lo que refuerza su identidad como artista y su disfrute por las artes plásticas.</p>', 'conejo de pascua, huevos de pascua, campo, pascua infantil, colorear', 'conejo-en-un-campo-con-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:38:59.125Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675537/coloring-web/pascuas/conejo-en-un-campo-con-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-en-un-campo-con-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (311, 'Conejo feliz en campo lleno de huevos de Pascua para colorear', 'conejo-feliz-en-campo-lleno-de-huevos-de-pascua-para-colorear', 'Dibujo para colorear de un conejo alegre en un prado repleto de huevos de Pascua decorados, paisaje de primavera para niños.', '<p>La alegría desbordante es el eje de esta lámina. Un conejo salta de felicidad en medio de un prado infinito donde los huevos de Pascua parecen brotar como si fueran flores, celebrando la abundancia de la festividad.</p>
  <h4>Composición y equilibrio</h4>
  <p>Al haber tantos elementos distribuidos por todo el campo, el dibujo ayuda a los niños a organizar su trabajo de coloreado por zonas. Fomenta el orden y la limpieza al tener que navegar entre múltiples formas pequeñas sin mezclarlas.</p>
  <h4>Consejos para el paisaje</h4>
  <p>Anima a los niños a usar diferentes tonos de verde para el suelo, creando parches de sombra y luz. Para el cielo, un azul celeste suave con nubes blancas dejará que la explosión de color de los huevos sea la verdadera protagonista.</p>
  <h4>Expresión de emociones</h4>
  <p>La cara sonriente del conejo ayuda a los niños a identificar y representar emociones positivas. Colorear personajes felices tiene un impacto directo en el estado de ánimo, convirtiendo la actividad en un momento de bienestar total.</p>', 'conejo feliz, campo de flores, abundancia, pascua, dibujo para imprimir, primavera, huevos decorados, aire libre', 'conejo-feliz-en-campo-lleno-de-huevos-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:39:49.462Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675588/coloring-web/pascuas/conejo-feliz-en-campo-lleno-de-huevos-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-feliz-en-campo-lleno-de-huevos-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (313, 'Conejo feliz sosteniendo un huevo de Pascua para colorear', 'conejo-feliz-sosteniendo-un-huevo-de-pascua-para-colorear', 'conejo feliz sosteniendo un huevo de pascua dibujo para colorear', '<p>En este diseño de enfoque central, el conejo abraza con cariño un único huevo de Pascua de gran tamaño. Es una imagen icónica y sencilla, ideal para los niños que prefieren concentrarse en un solo elemento principal con mucho detalle.</p>
  <h4>Enfoque en el detalle individual</h4>
  <p>Al ser un huevo tan grande, permite realizar diseños internos más complejos: mandalas, flores o figuras geométricas. Es el lienzo perfecto para que el niño demuestre su creatividad sin las limitaciones de un espacio reducido.</p>
  <h4>Guía de estilo</h4>
  <p>Sugerimos usar colores primarios (rojo, azul, amarillo) para el huevo, creando un contraste fuerte con el blanco o gris del conejo. Pintar las mejillas del conejo con un rosa muy suave le dará un toque extra de ternura a la obra.</p>
  <h4>Psicomotricidad fina</h4>
  <p>Trabajar en el contorno del huevo ayuda a mejorar la precisión del trazo circular, una de las habilidades más importantes en la etapa de pre-escritura. Es un ejercicio de control muscular muy efectivo y divertido.</p>', 'conejo de pascua, huevo de pascua, pascua infantil, dibujos para colorear', 'conejo-feliz-sosteniendo-un-huevo-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:40:43.685Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675642/coloring-web/pascuas/conejo-feliz-sosteniendo-un-huevo-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-feliz-sosteniendo-un-huevo-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (327, 'Conejo pintando huevos de Pascua en mesa de jardín para colorear', 'conejo-pintando-huevos-de-pascua-en-mesa-de-jardin-para-colorear', 'conejo pintando huevos de pascua en una mesa de jardín dibujo para colorear', '<p>La creatividad se traslada al exterior en esta ilustración. Un conejo utiliza una mesa de jardín para organizar sus pinturas y pinceles, trabajando bajo la luz del sol en un entorno natural y relajado.</p>
  <h4>Objetos y texturas</h4>
  <p>La mesa, los botes de pintura y los pinceles añaden una capa de realismo técnico. Los niños pueden practicar cómo colorear diferentes materiales: madera para la mesa, metal para los botes y cerdas suaves para los pinceles.</p>
  <h4>Guía de colores</h4>
  <p>Recomendamos usar colores muy variados para las manchas de pintura sobre la mesa. Esto permite que el niño "juegue" a ensuciar el dibujo de forma artística, perdiendo el miedo a usar colores fuertes y contrastados.</p>
  <h4>Concentración y flujo</h4>
  <p>Esta actividad representa el estado de "flujo" creativo. Al colorear a un personaje que también está creando arte, los niños entran en una sintonía de concentración profunda, mejorando su paciencia y su enfoque en el trabajo manual.</p>', 'conejo de pascua, pintar huevos, mesa de jardín, pascua infantil, dibujos para colorear', 'conejo-pintando-huevos-de-pascua-en-mesa-de-jardin-para-colorear', 6, NULL, '2026-03-16T18:49:50.467Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676189/coloring-web/pascuas/conejo-pintando-huevos-de-pascua-en-mesa-de-jardin-para-colorear.webp', 'coloring-web/pascuas/conejo-pintando-huevos-de-pascua-en-mesa-de-jardin-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (463, 'Princesa kawaii para colorear | Dibujo tierno y adorable', 'princesa-kawaii-para-colorear-or-dibujo-tierno-y-adorable', 'Princesa estilo kawaii con ojos grandes y expresión dulce, dibujo simple para niños.', '<h3>Diseño adorable y simple</h3> <p>El estilo kawaii se caracteriza por formas redondeadas y expresiones dulces, ideal para los más pequeños.</p> <h3>Colores suaves y pasteles</h3> <p>Se recomiendan tonos como rosa, celeste y lila para mantener el estilo tierno.</p> <h3>Fácil de colorear</h3> <p>Las líneas simples ayudan a mejorar la coordinación sin frustración.</p> <h3>Perfecto para principiantes</h3> <p>Una excelente opción para introducir a los niños en el dibujo.</p>', 'princesa kawaii, dibujo tierno, estilo japonés, adorable, ojos grandes, arte infantil, kawaii para colorear, princesa dulce, dibujo simple, niños pequeños, ilustración cute, fantasía, personaje adorable, creatividad, colorear fácil', 'princesa-kawaii-para-colorear-or-dibujo-tierno-y-adorable', 8, NULL, '2026-04-01T02:07:21.551Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998440/coloring-web/princesas/princesa-kawaii-para-colorear-or-dibujo-tierno-y-adorable.webp', 'coloring-web/princesas/princesa-kawaii-para-colorear-or-dibujo-tierno-y-adorable') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (328, 'Conejo recogiendo huevo de Pascua del arbusto para colorear', 'conejo-recogiendo-huevo-de-pascua-del-arbusto-para-colorear', 'conejo recogiendo un huevo de pascua escondido en un arbusto dibujo para colorear', '<p>Esta ilustración captura el momento del descubrimiento. Un conejo aparta las hojas de un arbusto frondoso para revelar un huevo de Pascua escondido, representando la emoción de la búsqueda exitosa en el jardín.</p>
  <h4>Texturas vegetales</h4>
  <p>El arbusto es el protagonista de la textura aquí. Los niños pueden practicar el dibujo de hojas individuales usando diferentes gamas de verde y amarillo para dar volumen a la planta, haciendo que el huevo "brille" en el centro.</p>
  <h4>Consejos de iluminación</h4>
  <p>Sugerimos pintar el interior del arbusto con un verde muy oscuro para crear sombra. Esto hará que el huevo de Pascua, pintado con colores neón o muy claros, parezca estar iluminado desde dentro de la planta.</p>
  <h4>Curiosidad y exploración</h4>
  <p>Este dibujo fomenta el espíritu explorador de los niños. Al colorear una escena de búsqueda, se identifican con el personaje y se sienten parte de la aventura, lo que mantiene su interés por la actividad artística durante más tiempo.</p>', 'conejo de pascua, esconder huevos, arbusto, pascua infantil, dibujos para colorear', 'conejo-recogiendo-huevo-de-pascua-del-arbusto-para-colorear', 6, NULL, '2026-03-16T18:50:15.562Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676214/coloring-web/pascuas/conejo-recogiendo-huevo-de-pascua-del-arbusto-para-colorear.webp', 'coloring-web/pascuas/conejo-recogiendo-huevo-de-pascua-del-arbusto-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (330, 'Conejo sosteniendo dos huevos de Pascua frente a una canasta para colorear', 'conejo-sosteniendo-dos-huevos-de-pascua-frente-a-una-canasta-para-colorear', 'conejo sosteniendo dos huevos de pascua frente a una canasta dibujo para colorear', '<p>El conejo ha tenido éxito en su recolección. En esta imagen, lo vemos sosteniendo un huevo en cada pata delantera mientras se prepara para colocarlos en una canasta de mimbre que ya está casi llena de tesoros decorados.</p>
  <h4>Simetría y equilibrio</h4>
  <p>Tener un huevo en cada lado del conejo permite trabajar el concepto de simetría. El niño puede intentar pintar ambos huevos de la misma forma para practicar el control visual, o hacerlos totalmente diferentes para crear contraste.</p>
  <h4>Tips para la canasta</h4>
  <p>Sugerimos usar un patrón de color alterno para el mimbre de la canasta (marrón claro y oscuro). Esto le dará un aspecto tridimensional muy interesante que resaltará frente a la figura más suave y lisa del conejo.</p>
  <h4>Logro y organización</h4>
  <p>Esta lámina representa la etapa final de un trabajo: la organización de los premios. Ayuda a los niños a valorar el orden y a sentir la satisfacción de ver una tarea completada y bien organizada.</p>', 'conejo de pascua, huevos de pascua, canasta de pascua, dibujos para colorear', 'conejo-sosteniendo-dos-huevos-de-pascua-frente-a-una-canasta-para-colorear', 6, NULL, '2026-03-16T18:51:05.368Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676264/coloring-web/pascuas/conejo-sosteniendo-dos-huevos-de-pascua-frente-a-una-canasta-para-colorear.webp', 'coloring-web/pascuas/conejo-sosteniendo-dos-huevos-de-pascua-frente-a-una-canasta-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (315, 'Conejo sosteniendo un huevo de Pascua para colorear', 'conejo-sosteniendo-un-huevo-de-pascua-para-colorear', 'conejo de pascua sosteniendo un huevo simple dibujo para colorear', '<p>Esta ilustración presenta al conejo de Pascua en una pose clásica y frontal, sosteniendo con cuidado un huevo decorado. Es un diseño de líneas limpias y grandes espacios, pensado especialmente para los artistas más jóvenes de la casa.</p>
  <h4>Enfoque en la figura central</h4>
  <p>Al no tener un fondo complejo, este dibujo permite que el niño se concentre totalmente en el personaje. Es ideal para practicar el control del lápiz en los bordes curvos de las orejas y la forma ovalada del huevo.</p>
  <h4>Sugerencias de color</h4>
  <p>Recomendamos usar colores primarios para el huevo y un tono crema o gris suave para el conejo. Un pequeño detalle de color rosa en la nariz le dará un aspecto tierno y amigable que encantará a los más pequeños.</p>
  <h4>Iniciación al arte</h4>
  <p>Este tipo de dibujos simplificados son la puerta de entrada perfecta al mundo de la expresión plástica. Fomentan la confianza del niño al permitirle terminar una obra completa de forma rápida y con un resultado muy satisfactorio.</p>', 'conejo de pascua, huevo de pascua, pascua infantil, dibujos para colorear', 'conejo-sosteniendo-un-huevo-de-pascua-para-colorear', 6, NULL, '2026-03-16T18:41:57.233Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675716/coloring-web/pascuas/conejo-sosteniendo-un-huevo-de-pascua-para-colorear.webp', 'coloring-web/pascuas/conejo-sosteniendo-un-huevo-de-pascua-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (331, 'Conejos y pollitos recolectando huevos de Pascua en el campo para colorear', 'conejos-y-pollitos-recolectando-huevos-de-pascua-en-el-campo-para-colorear', 'conejos y pollitos recolectando huevos de pascua en un campo dibujo para colorear', '<p>La unión hace la fuerza en esta animada escena campestre. Varios conejos y pollitos colaboran para encontrar y reunir los huevos de Pascua esparcidos por el campo, creando una imagen llena de vida y acción comunitaria.</p>
  <h4>El valor de la cooperación</h4>
  <p>Esta ilustración es perfecta para hablar sobre el trabajo en equipo. Cada personaje tiene una tarea, lo que invita a los niños a identificar roles y a valorar cómo la ayuda mutua hace que las metas se alcancen más rápido.</p>
  <h4>Guía para paisajes animados</h4>
  <p>Al haber muchos personajes, sugerimos usar colores variados para que cada uno tenga su propia personalidad. El campo verde puede tener diferentes matices para separar las zonas donde están los conejos de donde se encuentran los pollitos.</p>
  <h4>Complejidad y narrativa</h4>
  <p>Al tener múltiples focos de atención, este dibujo mantiene el interés del niño durante más tiempo. Estimula la capacidad de observación y el seguimiento de historias visuales mientras se completa cada rincón del paisaje.</p>', 'conejo de pascua, pollitos, huevos de pascua, campo, dibujos para colorear', 'conejos-y-pollitos-recolectando-huevos-de-pascua-en-el-campo-para-colorear', 6, NULL, '2026-03-16T18:51:30.691Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773676289/coloring-web/pascuas/conejos-y-pollitos-recolectando-huevos-de-pascua-en-el-campo-para-colorear.webp', 'coloring-web/pascuas/conejos-y-pollitos-recolectando-huevos-de-pascua-en-el-campo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (464, 'Princesa en el salón del castillo para colorear | Dibujo elegante de interior real', 'princesa-en-el-salon-del-castillo-para-colorear-or-dibujo-elegante-de-interior-real', 'Ilustración de una princesa dentro de un salón del castillo con columnas y decoración elegante para colorear.', '<h3>Elegancia en el corazón del castillo</h3> <p>Este dibujo presenta a una princesa en el interior de un gran salón real, rodeada de elementos arquitectónicos que evocan la vida en un castillo. Es una escena que transmite sofisticación y permite a los niños imaginar historias de reyes, reinas y grandes celebraciones.</p> <h3>Explorando espacios interiores</h3> <p>A diferencia de los paisajes abiertos, esta ilustración invita a trabajar detalles como columnas, cortinas y pisos decorados. Esto ayuda a los niños a reconocer estructuras y patrones dentro de un entorno más complejo.</p> <h3>Colores inspirados en la realeza</h3> <p>Se pueden utilizar tonos intensos como rojo, dorado y violeta para representar el lujo del salón. Los detalles decorativos permiten aplicar combinaciones creativas y resaltar diferentes zonas del dibujo.</p> <h3>Desarrollo de la precisión y el detalle</h3> <p>Los elementos pequeños fomentan la concentración y la motricidad fina, convirtiendo esta actividad en una herramienta ideal para mejorar la coordinación mientras se disfruta del arte.</p>', 'princesa castillo, salón real, interior palacio, dibujo elegante, fantasía medieval, arquitectura castillo, princesa noble, arte infantil detallado, decoración clásica, colorear princesa, escena interior, lujo medieval, dibujo educativo, fantasía para niños, castillo para colorear', 'princesa-en-el-salon-del-castillo-para-colorear-or-dibujo-elegante-de-interior-real', 8, NULL, '2026-04-01T02:08:33.261Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998512/coloring-web/princesas/princesa-en-el-salon-del-castillo-para-colorear-or-dibujo-elegante-de-interior-real.webp', 'coloring-web/princesas/princesa-en-el-salon-del-castillo-para-colorear-or-dibujo-elegante-de-interior-real') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (316, 'Conejo y pollito con huevos y cartel Happy Easter para colorear', 'conejo-y-pollito-con-huevos-y-cartel-happy-easter-para-colorear', 'conejo y pollito con huevos de pascua y cartel happy easter dibujo para colorear', '<p>Esta lámina funciona como una felicitación internacional. Un conejo y un pollito saludan con un cartel de "Happy Easter", rodeados de huevos decorados, ideal para introducir vocabulario en inglés de forma divertida y artística.</p>
  <h4>Aprendizaje de idiomas</h4>
  <p>Colorear frases en otro idioma ayuda a la retención visual de las palabras. Es un recurso pedagógico fantástico para clases de inglés o para hogares bilingües donde se busca naturalizar el idioma a través del juego.</p>
  <h4>Consejos de diseño</h4>
  <p>Recomendamos usar colores muy brillantes para las letras del cartel, como si fueran luces de neón o caramelos. Esto hará que el mensaje principal sea lo primero que se vea al observar la obra terminada.</p>
  <h4>Creatividad en la felicitación</h4>
  <p>Una vez terminado, este dibujo se puede regalar como una tarjeta personalizada. Fomenta el detalle de dar y compartir el arte propio con los seres queridos, reforzando los vínculos afectivos y la generosidad.</p>', 'conejo de pascua, pollito, huevos de pascua, happy easter, dibujos para colorear', 'conejo-y-pollito-con-huevos-y-cartel-happy-easter-para-colorear', 6, NULL, '2026-03-16T18:42:24.284Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773675742/coloring-web/pascuas/conejo-y-pollito-con-huevos-y-cartel-happy-easter-para-colorear.webp', 'coloring-web/pascuas/conejo-y-pollito-con-huevos-y-cartel-happy-easter-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (334, 'Conejo y pollitos bajo un árbol para colorear', 'conejo-y-pollitos-bajo-un-arbol-para-colorear', 'conejo con pollitos bajo un árbol dibujo para colorear', '<p>La tranquilidad de la tarde se refleja en esta escena. Bajo la protección de un gran árbol frondoso, un conejo y sus amigos pollitos disfrutan de un momento de descanso, rodeados de flores silvestres y paz campestre.</p>
  <h4>Luces y sombras naturales</h4>
  <p>El árbol proporciona una oportunidad perfecta para practicar el concepto de sombra. Los niños pueden pintar el suelo bajo el árbol con un verde más oscuro, simulando el refugio del sol que buscan los personajes.</p>
  <h4>Técnicas para el follaje</h4>
  <p>Para la copa del árbol, sugerimos usar la técnica del "moteado" o pequeños círculos de diferentes verdes para dar una sensación de volumen y realismo a las hojas, lo que mejora la motricidad fina y la paciencia.</p>
  <h4>Relajación y bienestar</h4>
  <p>Pintar escenas de descanso ayuda a calmar el ritmo de los niños. Es una actividad excelente para momentos de transición o para relajarse después de un día activo, promoviendo un estado mental positivo y sereno.</p>', 'conejo de pascua, pollitos, árbol, pascua infantil, dibujos para colorear', 'conejo-y-pollitos-bajo-un-arbol-para-colorear', 6, NULL, '2026-03-17T00:50:11.546Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773697810/coloring-web/pascuas/conejo-y-pollitos-bajo-un-arbol-para-colorear.webp', 'coloring-web/pascuas/conejo-y-pollitos-bajo-un-arbol-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (4, 'Dibujo de águila volando sobre montañas para colorear e imprimir', 'dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir', 'Ilustración en blanco y negro de un águila calva volando con las alas extendidas sobre montañas y nubes, estilo dibujo para colorear.', '<p>Cambiamos el paisaje por las alturas con esta impresionante águila real. Capturada en pleno vuelo con las alas extendidas, sobrevuela una cordillera de montañas nevadas, representando la libertad y el poder de la naturaleza salvaje.</p>
  <h4>Perspectiva aérea</h4>
  <p>Este dibujo introduce la vista "a vista de pájaro". Ayuda a los niños a entender cómo se ven las cosas desde arriba y cómo las montañas se vuelven más pequeñas a medida que ganamos altura en nuestra imaginación.</p>
  <h4>Guía de sombreado para aves</h4>
  <p>Para las plumas del águila, recomendamos trazos cortos y oscuros en los bordes de las alas. Para las montañas, dejar la cima en blanco simulará la nieve perpetua, creando un contraste espectacular con el cielo.</p>
  <h4>Respeto por la fauna salvaje</h4>
  <p>Esta lámina es ideal para aprender sobre las aves rapaces y su importancia en el ecosistema. Fomenta el interés por la geografía y la biología, despertando la admiración por las especies más majestuosas de nuestro planeta.</p>', 'águila para colorear, dibujo de águila, animales para pintar, águila volando, dibujo infantil, ilustración de montañas, imprimir gratis, actividades para niños, dibujo en blanco y negro, aves rapaces para colorear.', 'dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir', 1, NULL, '2026-02-23T18:41:55.246Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280197/coloring-web/animales/dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir.webp', 'coloring-web/animales/dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (5, 'Dibujo de alce bebé en paisaje de invierno para colorear', 'dibujo-de-alce-bebe-en-paisaje-de-invierno-para-colorear', 'Dibujo tierno de un pequeño alce con astas redondeadas en un bosque de pinos con nieve, estilo infantil.', '<p>Este tierno alce bebé, con sus grandes ojos y pequeñas astas en crecimiento, nos invita a explorar los bosques fríos del norte. El paisaje invernal, con pinos cubiertos de nieve, crea una atmósfera mágica y acogedora.</p>
  <h4>Texturas de frío y pelaje</h4>
  <p>El contraste entre el pelaje grueso del alce y la suavidad de la nieve es el reto artístico aquí. Los niños pueden usar marrones oscuros para el animal y azules muy pálidos para dar sombras a la nieve blanca.</p>
  <h4>Consejos para el fondo</h4>
  <p>Los pinos pueden pintarse con un verde oscuro "azulado" para transmitir la sensación de frío. Añadir pequeños puntos blancos con corrector o pintura blanca al final puede simular una nevada suave sobre la escena.</p>
  <h4>Empatía animal</h4>
  <p>Colorear animales bebés refuerza los sentimientos de protección y cariño. Es una forma excelente de conectar a los niños con especies que habitan en climas extremos, ampliando su conocimiento sobre la diversidad climática mundial.</p>', 'alce para colorear, reno infantil, animales del bosque, invierno para niños, dibujo fácil, colorear animales tierno.', 'dibujo-de-alce-bebe-en-paisaje-de-invierno-para-colorear', 1, NULL, '2026-02-24T00:40:33.002Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280074/coloring-web/animales/dibujo-de-alce-bebe-en-paisaje-de-invierno-para-colorear.webp', 'coloring-web/animales/dibujo-de-alce-bebe-en-paisaje-de-invierno-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (6, 'Dibujo de ballena saltando en el mar para colorear', 'dibujo-de-ballena-saltando-en-el-mar-para-colorear', 'Ilustración detallada de una ballena jorobada emergiendo de una gran ola en el océano, con nubes de fondo.', '<p>La inmensidad del océano cobra vida con este salto espectacular de una ballena. El dibujo captura la fuerza del agua salpicando alrededor del gigante marino, ofreciendo una escena llena de energía y frescura oceánica.</p>
  <h4>Dinámica de fluidos</h4>
  <p>Las gotas de agua y las olas requieren un trazo curvo y libre. Los niños pueden experimentar con diferentes tonos de azul y verde mar para darle profundidad al océano y movimiento a las salpicaduras.</p>
  <h4>Tips para el gigante azul</h4>
  <p>Para el cuerpo de la ballena, sugerimos usar grises, azules oscuros y dejar la zona del vientre más clara con líneas horizontales (pliegues gulares). Esto le dará un aspecto tridimensional y realista a la ilustración.</p>
  <h4>Conciencia oceánica</h4>
  <p>Este dibujo es un excelente punto de partida para hablar sobre la conservación de los mares y la vida de los cetáceos. Fomenta el amor por la biología marina y el respeto por los animales más grandes de la Tierra.</p>', 'ballena para colorear, animales marinos, dibujo de océano, ballena jorobada, naturaleza marina, pintar olas del mar.', 'dibujo-de-ballena-saltando-en-el-mar-para-colorear', 1, NULL, '2026-02-24T00:41:10.834Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280075/coloring-web/animales/dibujo-de-ballena-saltando-en-el-mar-para-colorear.webp', 'coloring-web/animales/dibujo-de-ballena-saltando-en-el-mar-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (7, 'Dibujo de bisonte bebé tierno para colorear', 'dibujo-de-bisonte-bebe-tierno-para-colorear', 'Ilustración de un pequeño bisonte o búfalo de estilo caricatura frente a una valla de madera, trazos simples.', '<p>Incluso los animales más grandes empiezan siendo pequeños. Este dibujo presenta una cría de bisonte con rasgos suavizados y ojos expresivos, ideal para que los niños conecten con el lado más dulce de la vida salvaje.</p>
  <h4>Simplificación de formas</h4>
  <p>A diferencia del bisonte adulto, este diseño utiliza formas más redondeadas. Es mucho más fácil de colorear para niños pequeños, permitiéndoles practicar el relleno de superficies sin la complicación de texturas excesivas.</p>
  <h4>Sugerencias de color</h4>
  <p>Recomendamos un marrón canela o caramelo para el cuerpo. Al ser un bebé, los colores suelen ser más claros que en los adultos. Un fondo de flores pequeñas hará que la escena se vea todavía más adorable.</p>
  <h4>Vínculo con la naturaleza</h4>
  <p>A través de este dibujo, los niños aprenden que todos los animales tienen una etapa de infancia y crecimiento. Fomenta la ternura y el respeto hacia las crías de todas las especies, fortaleciendo sus valores éticos.</p>', 'bisonte para colorear, búfalo bebé, dibujo de granja, animales americanos, colorear para preescolar, dibujo tierno.', 'dibujo-de-bisonte-bebe-tierno-para-colorear', 1, NULL, '2026-02-24T00:42:57.964Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280076/coloring-web/animales/dibujo-de-bisonte-bebe-tierno-para-colorear.webp', 'coloring-web/animales/dibujo-de-bisonte-bebe-tierno-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (460, 'Princesa viendo el atardecer para colorear | Dibujo tranquilo y paisaje mágico', 'princesa-viendo-el-atardecer-para-colorear-or-dibujo-tranquilo-y-paisaje-magico', 'Dibujo de una princesa observando el atardecer con el sol bajando en el horizonte y cielo despejado para colorear.', '<h3>Un momento de calma al final del día</h3> <p>Este dibujo muestra a una princesa disfrutando de la tranquilidad del atardecer, un instante perfecto para conectar con la naturaleza. La escena transmite paz y contemplación, ideal para niños que disfrutan de ilustraciones relajantes.</p> <h3>Colores cálidos y degradados</h3> <p>El cielo ofrece una excelente oportunidad para trabajar tonos como naranja, rosa y amarillo. Se pueden crear degradados suaves que simulen la caída del sol en el horizonte.</p> <h3>Fomentando la creatividad emocional</h3> <p>Colorear este tipo de escenas ayuda a desarrollar la imaginación y a explorar emociones como la calma y la reflexión, algo muy valioso en edades tempranas.</p> <h3>Un paisaje fácil de personalizar</h3> <p>Se pueden agregar detalles como pájaros, nubes o montañas, haciendo que cada dibujo sea único y estimulando la creatividad.</p>', 'princesa atardecer, puesta de sol, paisaje infantil, dibujo relajante, cielo naranja, fantasía tranquila, princesa sola, naturaleza mágica, colorear paisaje, calma in', 'princesa-viendo-el-atardecer-para-colorear-or-dibujo-tranquilo-y-paisaje-magico', 8, NULL, '2026-04-01T02:05:48.535Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998347/coloring-web/princesas/princesa-viendo-el-atardecer-para-colorear-or-dibujo-tranquilo-y-paisaje-magico.webp', 'coloring-web/princesas/princesa-viendo-el-atardecer-para-colorear-or-dibujo-tranquilo-y-paisaje-magico') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (461, 'Princesa leyendo un cuento para colorear | Dibujo educativo infantil', 'princesa-leyendo-un-cuento-para-colorear-or-dibujo-educativo-infantil', 'Princesa sentada leyendo un libro abierto, ilustración simple en blanco y negro para pintar.', '<h3>El poder de la lectura</h3> <p>Esta ilustración destaca a una princesa disfrutando de un buen libro, promoviendo el amor por la lectura desde pequeños. Es ideal para acompañar actividades educativas.</p> <h3>Detalles simples y claros</h3> <p>El libro, el vestido y la postura permiten trabajar formas básicas sin dificultad, facilitando la experiencia para niños principiantes.</p> <h3>Colores que cuentan historias</h3> <p>Se pueden usar colores vibrantes para el libro y tonos suaves para el entorno, creando un contraste atractivo.</p> <h3>Estimulación de la concentración</h3> <p>Colorear mientras se observa una escena de lectura ayuda a mejorar la atención y la paciencia.</p>', 'princesa leyendo, lectura infantil, cuento de hadas, educación niños, libro para colorear, imaginación, dibujo educativo, hábito lectura, princesa tranquila, arte infantil, actividad creativa, lectura divertida, concentración niños, fantasía, dibujo simple', 'princesa-leyendo-un-cuento-para-colorear-or-dibujo-educativo-infantil', 8, NULL, '2026-04-01T02:06:14.024Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998373/coloring-web/princesas/princesa-leyendo-un-cuento-para-colorear-or-dibujo-educativo-infantil.webp', 'coloring-web/princesas/princesa-leyendo-un-cuento-para-colorear-or-dibujo-educativo-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (467, 'Princesa en campo de flores para colorear | Dibujo natural y primaveral', 'princesa-en-campo-de-flores-para-colorear-or-dibujo-natural-y-primaveral', 'Princesa rodeada de flores en un campo abierto, ilustración simple para colorear.', '<h3>Un paseo entre flores</h3> <p>La princesa se encuentra rodeada de un campo lleno de flores, una escena que conecta con la naturaleza y transmite alegría.</p> <h3>Variedad de formas</h3> <p>Las flores permiten practicar diferentes patrones y estilos de coloreado.</p> <h3>Explosión de color</h3> <p>Se pueden usar múltiples combinaciones para cada flor, estimulando la creatividad.</p> <h3>Relajación y enfoque</h3> <p>Ideal para momentos tranquilos, ayudando a reducir el estrés infantil.</p>', 'princesa flores, campo floral, primavera, naturaleza infantil, dibujo relajante, flores para colorear, paisaje natural, princesa exterior, arte infantil, colores vivos, jardín, fantasía natural, dibujo simple, actividad creativa, tranquilidad', 'princesa-en-campo-de-flores-para-colorear-or-dibujo-natural-y-primaveral', 8, NULL, '2026-04-01T02:10:17.035Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998616/coloring-web/princesas/princesa-en-campo-de-flores-para-colorear-or-dibujo-natural-y-primaveral.webp', 'coloring-web/princesas/princesa-en-campo-de-flores-para-colorear-or-dibujo-natural-y-primaveral') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (465, 'Princesa en puente del castillo para colorear | Dibujo medieval con paisaje', 'princesa-en-puente-del-castillo-para-colorear-or-dibujo-medieval-con-paisaje', 'Princesa parada sobre un puente de castillo con vista al exterior, dibujo lineal para pintar.', '<h3>Un paso hacia la aventura</h3> <p>La princesa se encuentra en un puente que conecta el castillo con el mundo exterior, simbolizando exploración y nuevas historias. Es una escena que combina arquitectura con naturaleza.</p> <h3>Combinación de elementos</h3> <p>El puente, las torres y el paisaje permiten trabajar diferentes texturas en un mismo dibujo, enriqueciendo la experiencia de coloreado.</p> <h3>Jugando con profundidad</h3> <p>Se pueden aplicar tonos más claros al fondo y más intensos en primer plano para generar sensación de distancia.</p> <h3>Estimulación de la imaginación</h3> <p>Los niños pueden inventar qué hay más allá del puente, creando historias propias mientras colorean.</p>', 'princesa puente, castillo medieval, puente levadizo, fantasía, paisaje castillo, dibujo infantil, princesa exterior, aventura medieval, arquitectura antigua, colorear castillo, fantasía clásica, escena abierta, dibujo detallado, reino mágico, ilustración niños', 'princesa-en-puente-del-castillo-para-colorear-or-dibujo-medieval-con-paisaje', 8, NULL, '2026-04-01T02:09:03.002Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998542/coloring-web/princesas/princesa-en-puente-del-castillo-para-colorear-or-dibujo-medieval-con-paisaje.webp', 'coloring-web/princesas/princesa-en-puente-del-castillo-para-colorear-or-dibujo-medieval-con-paisaje') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (466, 'Princesa en fiesta real para colorear | Dibujo de celebración en castillo', 'princesa-en-fiesta-real-para-colorear-or-dibujo-de-celebracion-en-castillo', 'Princesa en una fiesta dentro del castillo con ambiente festivo, dibujo para colorear.', '<h3>Una celebración inolvidable</h3> <p>Esta escena muestra a una princesa disfrutando de una fiesta en el castillo, rodeada de un ambiente alegre y festivo. Es ideal para transmitir emociones positivas y dinamismo.</p> <h3>Detalles que cuentan historias</h3> <p>Los elementos decorativos permiten imaginar música, baile y encuentros mágicos dentro del palacio.</p> <h3>Colores vibrantes y alegres</h3> <p>Se recomienda usar tonos brillantes como rosa, azul y dorado para reflejar el espíritu festivo.</p> <h3>Expresión y movimiento</h3> <p>El dibujo ayuda a los niños a interpretar escenas con acción, mejorando su capacidad narrativa.</p>', 'princesa fiesta, baile real, celebración castillo, evento elegante, fantasía infantil, vestido princesa, dibujo festivo, música y baile, arte infantil, princesa feliz, fiesta medieval, colorear celebración, fantasía, escena animada, diversión', 'princesa-en-fiesta-real-para-colorear-or-dibujo-de-celebracion-en-castillo', 8, NULL, '2026-04-01T02:09:33.801Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998573/coloring-web/princesas/princesa-en-fiesta-real-para-colorear-or-dibujo-de-celebracion-en-castillo.webp', 'coloring-web/princesas/princesa-en-fiesta-real-para-colorear-or-dibujo-de-celebracion-en-castillo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (471, 'Princesa cantando con notas musicales para colorear | Dibujo artístico y creativo', 'princesa-cantando-con-notas-musicales-para-colorear-or-dibujo-artistico-y-creativo', 'Princesa cantando rodeada de notas musicales flotando, dibujo lineal infantil para colorear.', '<h3>Una escena que celebra la música</h3> <p>En esta ilustración, la princesa canta rodeada de notas musicales que parecen cobrar vida. Es una escena dinámica que transmite alegría, creatividad y amor por el arte. Ideal para niños que disfrutan de la música y quieren expresarse a través del dibujo.</p> <h3>Conectando el arte visual con el sonido</h3> <p>Aunque el dibujo es silencioso, representa un mundo lleno de melodías. Esto permite introducir conceptos básicos de música de forma visual, ayudando a los niños a asociar símbolos como las notas con sonidos y ritmos.</p> <h3>Colorear al ritmo de la imaginación</h3> <p>Las notas musicales pueden pintarse con distintos colores para diferenciarlas, mientras que el vestido de la princesa puede reflejar su personalidad artística. Se pueden usar tonos vibrantes para transmitir energía y movimiento.</p> <h3>Fomento de la expresión artística</h3> <p>Este tipo de ilustraciones estimula tanto la creatividad visual como la musical, invitando a los niños a cantar, imaginar canciones y desarrollar su lado artístico de manera integral.</p>', 'princesa cantando, música infantil, notas musicales dibujo, arte creativo niños, princesa cantante, melodía, dibujo musical, fantasía sonora, actividad artística, expresión musical, colorear música, creatividad infantil, ilustración divertida, educación musical, princesa artista', 'princesa-cantando-con-notas-musicales-para-colorear-or-dibujo-artistico-y-creativo', 8, NULL, '2026-04-01T02:13:30.463Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998809/coloring-web/princesas/princesa-cantando-con-notas-musicales-para-colorear-or-dibujo-artistico-y-creativo.webp', 'coloring-web/princesas/princesa-cantando-con-notas-musicales-para-colorear-or-dibujo-artistico-y-creativo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (472, 'Princesa caminando con vestido elegante para colorear | Dibujo de moda y fantasía', 'princesa-caminando-con-vestido-elegante-para-colorear-or-dibujo-de-moda-y-fantasia', 'Princesa caminando con un vestido largo y elegante, dibujo en blanco y negro para colorear.', '<h3>Elegancia y movimiento en una sola escena</h3> <p>Esta ilustración muestra a una princesa caminando con un vestido largo que fluye con cada paso. La escena transmite gracia y sofisticación, siendo perfecta para quienes disfrutan de los detalles de vestimenta y el mundo de la moda dentro de la fantasía.</p> <h3>Explorando el diseño de vestuario</h3> <p>El vestido ofrece múltiples posibilidades para aplicar colores, patrones y combinaciones únicas. Los niños pueden experimentar con estilos propios, agregando detalles como líneas, puntos o decoraciones imaginarias.</p> <h3>Colores y combinaciones creativas</h3> <p>Desde tonos clásicos como azul y rosa hasta combinaciones más atrevidas, este dibujo permite desarrollar el sentido estético. También se puede jugar con contrastes entre el vestido y el fondo.</p> <h3>Desarrollo de la creatividad visual</h3> <p>Colorear ropa ayuda a estimular la imaginación aplicada al diseño, convirtiendo una simple actividad en una experiencia creativa más completa.</p>', 'princesa elegante, vestido largo, moda infantil, dibujo de princesa, diseño de ropa, fantasía, princesa caminando, arte para colorear, creatividad moda, ilustración infantil, vestido detallado, estilo princesa, dibujo creativo, actividad artística, fantasía clásica', 'princesa-caminando-con-vestido-elegante-para-colorear-or-dibujo-de-moda-y-fantasia', 8, NULL, '2026-04-01T02:13:59.784Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998839/coloring-web/princesas/princesa-caminando-con-vestido-elegante-para-colorear-or-dibujo-de-moda-y-fantasia.webp', 'coloring-web/princesas/princesa-caminando-con-vestido-elegante-para-colorear-or-dibujo-de-moda-y-fantasia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (473, ': Princesa bebé tierna para colorear | Dibujo simple y adorable para niños', 'princesa-bebe-tierna-para-colorear-or-dibujo-simple-y-adorable-para-ninos', 'Princesa bebé con corona pequeña y expresión dulce, ilustración infantil para colorear.', '<h3>Una ilustración llena de ternura</h3> <p>La princesa bebé destaca por su diseño adorable, con rasgos suaves y una expresión dulce que capta la atención de los más pequeños. Es perfecta para introducir a los niños en el mundo del coloreado.</p> <h3>Ideal para primeras experiencias</h3> <p>Gracias a sus formas simples y líneas claras, este dibujo es fácil de completar, permitiendo que los niños desarrollen confianza en sus habilidades desde el inicio.</p> <h3>Colores suaves y armoniosos</h3> <p>Se pueden utilizar tonos pastel como rosa, celeste o amarillo claro para mantener el estilo delicado. También es posible agregar pequeños detalles creativos para personalizar la ilustración.</p> <h3>Estimulación temprana de la creatividad</h3> <p>Este tipo de dibujos ayuda a mejorar la coordinación mano-ojo y a fomentar la creatividad en edades tempranas, convirtiéndose en una actividad educativa y entretenida.</p>', 'princesa bebé, dibujo tierno, bebé princesa, kawaii infantil, arte para niños pequeños, ilustración simple, ternura, personaje adorable, fantasía infantil, colorear fácil, creatividad temprana, princesa pequeña, dibujo básico, actividad infantil, aprendizaje creativo', 'princesa-bebe-tierna-para-colorear-or-dibujo-simple-y-adorable-para-ninos', 8, NULL, '2026-04-01T02:14:25.566Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998864/coloring-web/princesas/princesa-bebe-tierna-para-colorear-or-dibujo-simple-y-adorable-para-ninos.webp', 'coloring-web/princesas/princesa-bebe-tierna-para-colorear-or-dibujo-simple-y-adorable-para-ninos') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (474, 'Princesa bailando con vestido en movimiento para colorear | Dibujo dinámico infantil', 'princesa-bailando-con-vestido-en-movimiento-para-colorear-or-dibujo-dinamico-infantil', 'Princesa bailando con su vestido en movimiento, ilustración lineal para colorear.', '<h3>Movimiento y expresión en el baile</h3> <p>Esta escena captura a una princesa en pleno baile, transmitiendo energía, ritmo y elegancia. El movimiento del vestido aporta dinamismo y hace que el dibujo sea visualmente atractivo.</p> <h3>Interpretando el movimiento a través del color</h3> <p>El flujo del vestido permite aplicar diferentes tonos para dar sensación de movimiento. Se pueden usar colores degradados o contrastantes para destacar la acción.</p> <h3>Conexión con la música y el ritmo</h3> <p>Aunque no se escuche música, el dibujo sugiere una melodía implícita. Esto invita a los niños a imaginar canciones y coreografías mientras colorean.</p> <h3>Creatividad y expresión corporal</h3> <p>El baile es una forma de expresión, y este dibujo ayuda a los niños a conectar el arte visual con el movimiento, estimulando su imaginación y creatividad.</p>', 'princesa bailando, danza infantil, movimiento, dibujo dinámico, baile princesa, fantasía, vestido en movimiento, arte creativo, expresión corporal, actividad niños, ilustración artística, creatividad, dibujo animado, baile real, colorear', 'princesa-bailando-con-vestido-en-movimiento-para-colorear-or-dibujo-dinamico-infantil', 8, NULL, '2026-04-01T02:14:50.218Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1774998889/coloring-web/princesas/princesa-bailando-con-vestido-en-movimiento-para-colorear-or-dibujo-dinamico-infantil.webp', 'coloring-web/princesas/princesa-bailando-con-vestido-en-movimiento-para-colorear-or-dibujo-dinamico-infantil') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (9, 'Dibujo de búfalo bebé en el pasto para colorear', 'dibujo-de-bufalo-bebe-en-el-pasto-para-colorear', 'Dibujo infantil de un pequeño búfalo con cuernos curvos parado sobre el césped, estilo animado.', '<p>Esta entrañable ilustración presenta a un pequeño búfalo bebé descansando pacíficamente sobre un lecho de pasto fresco. Con sus formas redondeadas y ojos curiosos, es el diseño perfecto para que los niños más pequeños conecten con el lado tierno de la vida rural.</p>
  <h4>Texturas de hierba y suavidad</h4>
  <p>Al tener al animal sentado, se crea una gran superficie de pasto para colorear. Recomendamos usar diferentes gamas de verde y amarillo para dar volumen al suelo, haciendo que el búfalo, pintado en tonos café claro, parezca estar muy cómodo.</p>
  <h4>Consejos de estilo</h4>
  <p>Para que la escena se vea más viva, anima a los niños a añadir pequeñas flores silvestres entre el pasto usando colores brillantes como el rojo o el morado. Esto añade detalles extra que mantienen el interés visual de la obra.</p>
  <h4>Fomento de la calma</h4>
  <p>Pintar animales en reposo tiene un efecto relajante comprobado en los niños. Esta lámina es ideal para momentos de transición o para calmar el ritmo antes de dormir, promoviendo un estado de ánimo positivo y sereno.</p>', 'búfalo para colorear, animales de la selva, dibujo infantil de búfalo, pintar animales, dibujo de pasto, actividades infantiles.', 'dibujo-de-bufalo-bebe-en-el-pasto-para-colorear', 1, NULL, '2026-02-24T00:44:32.619Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280079/coloring-web/animales/dibujo-de-bufalo-bebe-en-el-pasto-para-colorear.webp', 'coloring-web/animales/dibujo-de-bufalo-bebe-en-el-pasto-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (15, 'Dibujo de canguro en el desierto australiano para colorea', 'dibujo-de-canguro-en-el-desierto-australiano-para-colorea', 'Dibujo infantil de un canguro parado junto a un cactus en un paisaje árido, estilo caricatura.', '<p>Viajamos al otro lado del mundo con este canguro explorando el desierto australiano. Con su cola larga y sus patas poderosas, este dibujo nos sumerge en el ecosistema único del *Outback*, un lugar lleno de misterio y belleza natural.</p>
  <h4>Colores de la tierra</h4>
  <p>Al ser un paisaje desértico, la paleta de colores cambia. Recomendamos usar ocres, terracotas y naranjas para el suelo y las formaciones rocosas. Para el canguro, un tono marrón rojizo o arena se integrará perfectamente con el entorno.</p>
  <h4>Tips para el cielo</h4>
  <p>Para darle un toque auténtico de calor australiano, sugerimos pintar el cielo con un degradado que vaya de naranja en el horizonte a un azul celeste muy pálido en la parte superior, simulando la calima del desierto.</p>
  <h4>Apreciación de la biodiversidad</h4>
  <p>Esta lámina es ideal para aprender sobre la fauna marsupial y los climas extremos. Fomenta el interés por la geografía y el respeto por los animales que se han adaptado a vivir en condiciones de calor intenso y poca agua.</p>', 'canguro para colorear, animales de Australia, dibujo de cactus, fauna australiana, dibujo fácil para niños, colorear naturaleza.', 'dibujo-de-canguro-en-el-desierto-australiano-para-colorea', 1, NULL, '2026-02-24T00:55:17.247Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280084/coloring-web/animales/dibujo-de-canguro-en-el-desierto-australiano-para-colorea.webp', 'coloring-web/animales/dibujo-de-canguro-en-el-desierto-australiano-para-colorea') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (12, 'Dibujo de perro cachorro feliz con flores para colorear', 'dibujo-de-perro-cachorro-feliz-con-flores-para-colorear', 'Ilustración de un cachorro sonriente tipo Golden Retriever rodeado de flores y plantas en un jardín.', '<p>La alegría se desborda en esta animada escena primaveral. Un cachorro de perro corre y salta de felicidad en medio de un prado infinito lleno de flores de todos los colores, celebrando la vitalidad de la naturaleza.</p>
  <h4>Explosión de color primaveral</h4>
  <p>Al haber tantas flores distintas (margaritas, tulipanes, hojas verdes), los niños pueden explorar una paleta de colores mucho más amplia y vibrante, jugando a combinar tonos fríos y cálidos de forma desordenada y creativa.</p>
  <h4>Técnicas sugeridas</h4>
  <p>Recomendamos usar colores muy vivos para las flores, como el fucsia, naranja neón o amarillo intenso. Para el cachorro, un color que contraste (blanco o gris) hará que la figura central del animal no compita visualmente con el fondo floral.</p>
  <h4>Estimulación visual y rítmica</h4>
  <p>Debido a la gran variedad de formas orgánicas repetitivas, este dibujo estimula la agudeza visual. Ayuda a los niños a entender cómo colorear un fondo complejo manteniendo el equilibrio visual de la composición.</p>', 'perro feliz para colorear, cachorro con flores, dibujo de jardín, animales domésticos, colorear primavera, dibujo infantil.', 'dibujo-de-perro-cachorro-feliz-con-flores-para-colorear', 1, NULL, '2026-02-24T00:51:23.323Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280082/coloring-web/animales/dibujo-de-perro-cachorro-feliz-con-flores-para-colorear.webp', 'coloring-web/animales/dibujo-de-perro-cachorro-feliz-con-flores-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (149, 'Dibujo para colorear actor en escenario', 'dibujo-para-colorear-actor-en-escenario', 'Actor actuando sobre un escenario para colorear', '<p>La magia del teatro cobra vida en este dibujo que presenta a un actor interpretando un papel en un gran escenario. Con el telón de fondo y rodeado de luces, este dibujo nos invita a explorar el emocionante mundo de las artes escénicas y la interpretación.</p>
  <h4>Texturas textiles y escénicas</h4>
  <p>El telón ofrece una gran superficie para practicar la textura de la tela. Los niños pueden usar un color rojo intenso para el telón y colores más neutros para el vestuario del actor, creando un contraste visual muy potente.</p>
  <h4>Tips para la iluminación</h4>
  <p>Sugerimos usar colores cálidos para las luces de escenario, como amarillos y naranjas. Para el fondo de la platea, un color azul oscuro simulará que el teatro está lleno de gente y la escena está en su punto culminante.</p>
  <h4>Empatía y expresión</h4>
  <p>Al pintar a un personaje interpretando un papel, los niños aprenden a reconocer emociones y expresiones corporales. Esto fortalece su capacidad de empatía y su comprensión de la comunicación no verbal.</p>', 'actor, teatro, escenario, actuación, profesión, arte escénico, dibujo para colorear', 'dibujo-para-colorear-actor-en-escenario', 4, NULL, '2026-03-07T00:21:09.654Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280234/coloring-web/profesiones-oficios/dibujo-para-colorear-actor-en-escenario.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-actor-en-escenario') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (150, 'Dibujo para colorear albañil construyendo', 'dibujo-para-colorear-albanil-construyendo', 'Albañil trabajando con ladrillos para colorear', '<p>Esta escena educativa presenta la figura del albañil, el profesional encargado de dar forma a nuestras casas y edificios. Al fondo, se observa una pared en construcción, lo que permite a los niños entender el proceso de levantar estructuras con ladrillos y cemento.</p>
  <h4>Elementos técnicos y repetitivos</h4>
  <p>Al tener ladrillos y cemento, este dibujo introduce elementos técnicos complejos. Los niños pueden practicar cómo colorear superficies rugosas y repetitivas, entendiendo cómo cada ladrillo contribuye a la solidez de la pared.</p>
  <h4>Tips para la textura</h4>
  <p>Recomendamos usar colores terracota para los ladrillos y grises para el cemento. Para el uniforme del albañil, un color azul o beige simulará que la ropa de trabajo está curtida y lista para la acción.</p>
  <h4>Habilidades cognitivas y manuales</h4>
  <p>Al colorear estructuras arquitectónicas, los niños entienden conceptos de perspectiva y proporción. Además, trabajar con líneas rectas y ángulos refuerza la coordinación ojo-mano de una manera muy estructurada.</p>', 'albañil, construcción, trabajador, profesión, ladrillos, casco, dibujo infantil', 'dibujo-para-colorear-albanil-construyendo', 4, NULL, '2026-03-07T00:21:35.802Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280235/coloring-web/profesiones-oficios/dibujo-para-colorear-albanil-construyendo.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-albanil-construyendo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (241, 'Dibujo para colorear ambulancia', 'dibujo-para-colorear-ambulancia', 'Ambulancia circulando por una calle', '<p>Esta lámina presenta la figura de la ambulancia, el vehículo encargado de trasladar a las personas heridas o enfermas a un hospital. Con las luces y la sirena encendida, este dibujo nos invita a explorar el mundo de los servicios de emergencia y primeros auxilios.</p>
  <h4>Elementos técnicos y dinámicos</h4>
  <p>Al tener luces y sirena, este dibujo introduce elementos dinámicos complejos. Los niños pueden usar colores neón para las luces y colores metálicos para la carrocería, dándole un acabado muy profesional a la ambulancia.</p>
  <h4>Tips para la iluminación</h4>
  <p>Sugerimos usar colores cálidos para las luces de sirena, como amarillos y naranjas. Para el fondo de la calle, un color azul oscuro simulará que la ambulancia se está desplazando a gran velocidad.</p>
  <h4>Educación vial y primeros auxilios</h4>
  <p>Al pintar un vehículo de emergencia, los niños entienden la importancia de la educación vial y los primeros auxilios. Esto fortalece su capacidad de reconocer símbolos de emergencia y su comprensión de la seguridad vial.</p>', 'ambulancia, vehículo de emergencia, hospital, rescate, paramédicos, transporte médico, sirena, ciudad, ayuda médica, emergencia', 'dibujo-para-colorear-ambulancia', 5, NULL, '2026-03-12T00:48:56.662Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280338/coloring-web/vehiculos/dibujo-para-colorear-ambulancia.webp', 'coloring-web/vehiculos/dibujo-para-colorear-ambulancia') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (156, 'Dibujo para colorear artista pintando en caballete', 'dibujo-para-colorear-artista-pintando-en-caballete', 'Artista pintando un cuadro en caballete', '<p>¡Arte dentro del arte! En esta ilustración, un pintor se concentra frente a su lienzo, paleta en mano, creando una nueva obra. Es una invitación directa a que los niños se sientan identificados con el personaje mientras ellos mismos colorean.</p>
  <h4>Color dentro de color</h4>
  <p>La paleta del artista es el elemento más divertido. Los niños pueden poner una gota de cada color que tengan disponible en los pequeños círculos de la paleta, convirtiendo este dibujo en un muestrario de su propio material escolar.</p>
  <h4>Tips para el lienzo</h4>
  <p>Lo más creativo de esta lámina es que el lienzo que el artista está pintando puede ser lo que el niño quiera. Pueden dibujar un pequeño paisaje dentro del cuadro o usar colores abstractos para simular una obra de arte moderno.</p>
  <h4>Libertad de expresión</h4>
  <p>Este dibujo celebra la identidad del artista. Refuerza la autoconfianza de los niños en sus propias capacidades creativas, recordándoles que el arte es una forma hermosa de comunicar sus sentimientos al mundo.</p>', 'Artista pintando un cuadro en caballete', 'dibujo-para-colorear-artista-pintando-en-caballete', 4, NULL, '2026-03-07T00:26:51.342Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280243/coloring-web/profesiones-oficios/dibujo-para-colorear-artista-pintando-en-caballete.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-artista-pintando-en-caballete') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (296, 'Dibujo para colorear ambulancia con fondo médico', 'dibujo-para-colorear-ambulancia-con-fondo-medico', 'Ambulancia frente a un hospital lista para una emergencia', '<p>Esta completa escena sitúa a la ambulancia en su entorno de trabajo: la entrada de un centro médico. Acompañada de elementos como el símbolo de la salud y equipos de asistencia, es una lámina ideal para familiarizar a los niños con el sistema de cuidados sanitarios.</p>
  <h4>Contexto y entorno hospitalario</h4>
  <p>La inclusión de un fondo con la fachada del hospital permite a los niños trabajar la profundidad. Pueden usar colores claros para el edificio y reservar los rojos y azules vibrantes para los detalles de la ambulancia, creando una jerarquía visual clara.</p>
  <h4>Sugerencias de color</h4>
  <p>Recomendamos dejar la carrocería en blanco y resaltar las cruces y luces con rojo intenso y azul cian. Para los accesorios médicos del fondo, los tonos verdes agua o azul pastel darán esa sensación de limpieza y profesionalismo propia de la medicina.</p>
  <h4>Seguridad y confianza</h4>
  <p>Colorear este tipo de escenas ayuda a reducir el miedo que algunos niños sienten hacia los entornos médicos. Al ver la ambulancia como una herramienta de ayuda, desarrollan una actitud más positiva y tranquila ante la salud.</p>', 'ambulancia, vehículo de emergencia, hospital, rescate, paramédicos, salud, transporte médico, sirena, emergencia médica', 'dibujo-para-colorear-ambulancia-con-fondo-medico', 5, NULL, '2026-03-12T04:42:33.828Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773279752/coloring-web/vehiculos/dibujo-para-colorear-ambulancia-con-fondo-medico.webp', 'coloring-web/vehiculos/dibujo-para-colorear-ambulancia-con-fondo-medico') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (244, 'Dibujo para colorear apisonadora antigua', 'dibujo-para-colorear-apisonadora-antigua', 'Apisonadora antigua utilizada en obras de construcción', '<p>Viajamos a los inicios de la ingeniería civil con esta robusta apisonadora de vapor. Con su gran chimenea y sus rodillos de hierro macizo, esta máquina nos cuenta la historia de cómo se construían las primeras carreteras modernas.</p>
  <h4>Historia y mecánica visual</h4>
  <p>Este dibujo destaca por sus engranajes y tuberías visibles. Es una oportunidad fantástica para explicar a los niños cómo funcionaba el vapor para mover objetos pesados, uniendo la historia de la tecnología con la expresión artística.</p>
  <h4>Guía de tonos metálicos</h4>
  <p>Para lograr un efecto antiguo, sugerimos usar una gama de marrones, cobres y grises oscuros. Un toque de negro cerca de la chimenea simulará el rastro del carbón, dándole un aspecto auténtico de maquinaria del siglo XIX.</p>
  <h4>Atención a la estructura</h4>
  <p>Debido a su diseño complejo y mecánico, esta lámina fomenta la observación técnica. Ayuda a los niños a entender que las máquinas están compuestas por muchas piezas pequeñas que trabajan en conjunto para un fin común.</p>', 'apisonadora antigua, rodillo compactador, maquinaria vieja, construcción, obra, maquinaria histórica, ingeniería civil, maquinaria pesada', 'dibujo-para-colorear-apisonadora-antigua', 5, NULL, '2026-03-12T00:50:30.788Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280342/coloring-web/vehiculos/dibujo-para-colorear-apisonadora-antigua.webp', 'coloring-web/vehiculos/dibujo-para-colorear-apisonadora-antigua') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (243, 'Dibujo para colorear apisonadora moderna', 'dibujo-para-colorear-apisonadora-moderna', 'Apisonadora moderna compactando suelo', '<p>La tecnología actual llega a las obras con esta apisonadora de última generación. A diferencia de las antiguas, esta presenta líneas aerodinámicas, una cabina cerrada y un diseño pensado para la eficiencia y la comodidad del operario.</p>
  <h4>Líneas limpias y diseño actual</h4>
  <p>Este dibujo se caracteriza por sus contornos suaves y superficies despejadas. Es ideal para niños que disfrutan de un estilo más minimalista y moderno, donde el enfoque está en la limpieza visual y el orden de las piezas.</p>
  <h4>Consejos para los cristales</h4>
  <p>La cabina del conductor suele ser de cristal. Un consejo artístico es usar un azul muy claro o dejar zonas en blanco para simular el reflejo de la luz, lo que da un aspecto de transparencia muy realista a la máquina.</p>
  <h4>Inspiración profesional</h4>
  <p>Este dibujo motiva a los niños a interesarse por la ingeniería moderna y las profesiones de construcción actuales. Muestra la evolución de las herramientas que usamos para dar forma a las ciudades del futuro.</p>', 'pisonadora moderna, rodillo compactador, maquinaria de construcción, obra, pavimentación, ingeniería, maquinaria pesada, construcción de carreteras', 'dibujo-para-colorear-apisonadora-moderna', 5, NULL, '2026-03-12T00:49:59.895Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280341/coloring-web/vehiculos/dibujo-para-colorear-apisonadora-moderna.webp', 'coloring-web/vehiculos/dibujo-para-colorear-apisonadora-moderna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (154, 'Dibujo para colorear arquitecto con planos', 'dibujo-para-colorear-arquitecto-con-planos', 'Arquitecto sosteniendo planos de construcción', '<p>Esta escena captura el momento de la creación: el arquitecto en su estudio diseñando las estructuras del mañana. Con grandes hojas de planos desplegadas, la ilustración muestra el lado más intelectual y detallista de esta profesión.</p>
  <h4>Precisión geométrica</h4>
  <p>Los planos en el dibujo están llenos de líneas rectas y formas geométricas. Es una oportunidad excelente para que los niños practiquen la precisión, usando reglas si lo desean para colorear los esquemas de los edificios.</p>
  <h4>Sugerencias de color</h4>
  <p>Para los planos, el clásico color azul cian con líneas blancas (blueprint) es una opción muy creativa. El escritorio puede ser de madera cálida para contrastar con el blanco del papel y el rigor del dibujo técnico.</p>
  <h4>Habilidades de planificación</h4>
  <p>Al colorear a alguien que está planificando, los niños refuerzan la idea de que todo gran proyecto nace primero de una idea escrita. Ayuda a desarrollar el pensamiento lógico y la valoración de la etapa de diseño.</p>', 'arquitecto, planos, diseño, construcción, profesión, dibujo educativo', 'dibujo-para-colorear-arquitecto-con-planos', 4, NULL, '2026-03-07T00:26:03.679Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280240/coloring-web/profesiones-oficios/dibujo-para-colorear-arquitecto-con-planos.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-arquitecto-con-planos') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (247, 'Dibujo para colorear avión caza militar en pista', 'dibujo-para-colorear-avion-caza-militar-en-pista', 'Avión de combate estacionado en la pista de un aeropuerto militar', '<p>La velocidad y la ingeniería se unen en este avión de combate estacionado en la pista de aterrizaje. Con su diseño aerodinámico y detalles técnicos, es una lámina perfecta para los entusiastas de la aviación moderna.</p>
  <h4>Detalles de ingeniería aeronáutica</h4>
  <p>La ilustración destaca la cabina del piloto, las alas en flecha y el tren de aterrizaje. Colorear estas piezas ayuda a los niños a entender cómo se estructuran los aviones más rápidos del mundo, mejorando su atención al detalle.</p>
  <h4>Guía de camuflaje</h4>
  <p>Sugerimos usar una paleta de grises, verdes oscuros o incluso un patrón de camuflaje con manchas de diferentes tonos. Esto permite experimentar con texturas militares y sombras para darle un aspecto potente y profesional.</p>', 'avión caza, avión militar, avión de combate, aviación militar, fuerza aérea, pista de aeropuerto, avión rápido, aeronave militar', 'dibujo-para-colorear-avion-caza-militar-en-pista', 5, NULL, '2026-03-12T00:51:42.688Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280345/coloring-web/vehiculos/dibujo-para-colorear-avion-caza-militar-en-pista.webp', 'coloring-web/vehiculos/dibujo-para-colorear-avion-caza-militar-en-pista') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (120, 'Dibujo para colorear astronauta caminando en la Luna', 'dibujo-para-colorear-astronauta-caminando-en-la-luna', 'Astronauta caminando sobre el suelo lunar con estrellas alrededor.', '<p>Esta épica imagen nos traslada a la superficie de nuestro satélite. El astronauta camina con paso ligero debido a la baja gravedad, dejando sus huellas en el polvo lunar mientras observa nuestro planeta azul a lo lejos.</p>
  <h4>Contraste espacial y sombras</h4>
  <p>En la Luna no hay atmósfera, por lo que las sombras son muy oscuras y marcadas. Los niños pueden practicar el contraste fuerte pintando el cielo de negro profundo y dejando el traje del astronauta en un blanco brillante.</p>
  <h4>Guía para el suelo lunar</h4>
  <p>La superficie lunar (regolito) es de un tono gris ceniza. Sugerimos usar diferentes presiones del lápiz gris para crear los cráteres y las rocas, dando una textura rugosa que haga resaltar las botas del explorador.</p>
  <h4>Asombro científico</h4>
  <p>Este dibujo motiva a los niños a preguntar sobre los viajes espaciales y la ciencia. Es un disparador de curiosidad sobre el universo, fomentando el interés por la tecnología y la exploración de lo desconocido.</p>', 'astronauta, luna, caminar en la luna, espacio, estrellas, exploración espacial, traje espacial', 'dibujo-para-colorear-astronauta-caminando-en-la-luna', 3, NULL, '2026-03-03T02:56:46.111Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280191/coloring-web/espacio/dibujo-para-colorear-astronauta-caminando-en-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-caminando-en-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (122, 'Dibujo para colorear astronauta dentro de nave espacial', 'dibujo-para-colorear-astronauta-dentro-de-nave-espacial', 'Astronauta sentado dentro de una nave espacial con controles.', '<p>¿Cómo es la vida en gravedad cero? Esta lámina muestra el interior de una cápsula tecnológica donde el astronauta flota rodeado de pantallas y paneles de control, ofreciendo una visión fascinante de la tecnología espacial.</p>
  <h4>Detalles mecánicos y luces</h4>
  <p>La cabina está llena de botones y mandos pequeños. Recomendamos usar colores brillantes como el rojo, verde y amarillo para las luces de los indicadores, haciendo que la nave parezca "viva" y operativa.</p>
  <h4>Tips para la ventana</h4>
  <p>La escotilla o ventana permite ver el espacio exterior. Un efecto muy profesional se logra pintando esa zona de un azul oscuro casi negro y añadiendo pequeñas estrellas blancas, creando una sensación de profundidad infinita.</p>
  <h4>Concentración y precisión</h4>
  <p>Debido a la cantidad de elementos técnicos, este dibujo es excelente para trabajar la motricidad fina. Los niños deben concentrarse en colorear cada botón sin salirse, mejorando su atención y su pulso.</p>', 'astronauta, nave espacial, cabina, controles, viaje espacial, ciencia infantil', 'dibujo-para-colorear-astronauta-dentro-de-nave-espacial', 3, NULL, '2026-03-03T03:03:27.309Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280206/coloring-web/espacio/dibujo-para-colorear-astronauta-dentro-de-nave-espacial.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-dentro-de-nave-espacial') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (126, 'Dibujo para colorear astronauta junto a módulo lunar', 'dibujo-para-colorear-astronauta-junto-a-modulo-lunar', 'Astronauta al lado de un módulo lunar en la Luna para colorear.', '<p>Viajamos a la época dorada de la exploración espacial con esta escena histórica. El astronauta posa con orgullo junto al Módulo Excursionista Lunar (LEM), la nave que hizo posible el sueño de caminar sobre la Luna.</p>
  <h4>Ingeniería y diseño espacial</h4>
  <p>Este dibujo destaca por los detalles del módulo lunar: patas de aterrizaje, paneles y antenas. Es una oportunidad excelente para explicar a los niños cómo la tecnología permitió a los humanos sobrevivir en un entorno hostil.</p>
  <h4>Guía para el suelo y la nave</h4>
  <p>La superficie lunar es de un gris ceniza. Sugerimos usar diferentes presiones del lápiz gris para crear textura. Para el módulo lunar, los tonos metálicos como el dorado o el plateado en los paneles le darán un aspecto auténtico.</p>
  <h4>Hitos de la humanidad</h4>
  <p>Este dibujo celebra el valor de la perseverancia científica. Fomenta el interés por la historia de la astronomía y el respeto por los pioneros que abrieron el camino hacia las estrellas con valentía y conocimiento.</p>', 'astronauta, módulo lunar, luna, exploración espacial, misión espacial', 'dibujo-para-colorear-astronauta-junto-a-modulo-lunar', 3, NULL, '2026-03-04T02:28:07.776Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280210/coloring-web/espacio/dibujo-para-colorear-astronauta-junto-a-modulo-lunar.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-junto-a-modulo-lunar') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (125, 'Dibujo para colorear astronauta leyendo libro en el espacio', 'dibujo-para-colorear-astronauta-leyendo-libro-en-el-espacio', 'Astronauta leyendo un libro en una nave espacial para colorear.', '<p>¿Quién dice que no se puede leer en el espacio? Esta simpática ilustración muestra a un astronauta flotando cómodamente en la cabina de su nave mientras disfruta de una lectura, demostrando que la cultura también viaja a las estrellas.</p>
  <h4>La vida cotidiana en órbita</h4>
  <p>Al tener al personaje en una actividad tan normal, el dibujo humaniza la figura del astronauta. Invita a los niños a imaginar cómo adaptamos nuestras rutinas (como sostener un libro sin que se caiga) en un entorno sin gravedad.</p>
  <h4>Tips para la cabina tecnológica</h4>
  <p>La cabina está llena de botones y pantallas. Recomendamos usar colores brillantes para los indicadores, haciendo que la nave parezca operativa. El libro puede tener una portada colorida diseñada por el propio niño.</p>
  <h4>Concentración y bienestar</h4>
  <p>Pintar escenas de lectura tiene un efecto calmante. Esta lámina es perfecta para momentos de tranquilidad, uniendo la fascinación por el espacio con el fomento del hábito de la lectura en los pequeños artistas.</p>', 'astronauta, libro, nave espacial, espacio, aprendizaje, ciencia infantil', 'dibujo-para-colorear-astronauta-leyendo-libro-en-el-espacio', 3, NULL, '2026-03-04T02:27:38.404Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280209/coloring-web/espacio/dibujo-para-colorear-astronauta-leyendo-libro-en-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-leyendo-libro-en-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (251, 'Dibujo para colorear barco pesquero en el puerto', 'dibujo-para-colorear-barco-pesquero-en-el-puerto', 'Barco pesquero amarrado en el puerto después de pescar', '<p>Esta lámina nos lleva al muelle, donde un robusto barco de pesca descansa junto al puerto. Con redes, flotadores y el reflejo del agua, es una escena llena de detalles marineros y tradición pesquera.</p>
  <h4>Detalles náuticos</h4>
  <p>El dibujo incluye elementos específicos como el mástil y las redes de pesca. Colorear estas piezas finas ayuda a mejorar la precisión manual. Para el casco del barco, los colores primarios fuertes como el rojo o azul son ideales.</p>
  <h4>El agua del puerto</h4>
  <p>Sugerimos pintar el agua con trazos horizontales cortos de diferentes tonos de azul para simular el suave movimiento de las olas chocando contra el muelle, dándole vida y profundidad a la composición.</p>', 'barco pesquero, barco de pesca, puerto, pesca, mar, océano, barco, trabajo en el mar', 'dibujo-para-colorear-barco-pesquero-en-el-puerto', 5, NULL, '2026-03-12T00:53:16.850Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280351/coloring-web/vehiculos/dibujo-para-colorear-barco-pesquero-en-el-puerto.webp', 'coloring-web/vehiculos/dibujo-para-colorear-barco-pesquero-en-el-puerto') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (119, 'Dibujo para colorear astronauta plantando bandera en la Luna', 'dibujo-para-colorear-astronauta-plantando-bandera-en-la-luna', 'Astronauta colocando una bandera sobre la superficie de la Luna para colorear.', '<p>Esta imagen captura el momento culminante de cualquier misión de alunizaje: la plantación de la bandera. El astronauta clava el mástil en el regolito lunar, simbolizando el éxito de la misión y la presencia humana en otro mundo.</p>
  <h4>Historia y simbolismo nacional</h4>
  <p>Este dibujo es una herramienta pedagógica para hablar sobre la carrera espacial y los grandes logros del siglo XX. La bandera es el lienzo perfecto para que los niños representen su propio país o creen un diseño universal.</p>
  <h4>Tips para el movimiento y el suelo</h4>
  <p>Sugerimos pintar la bandera con colores vibrantes para que contraste con el entorno gris. Para el suelo alrededor del mástil, el uso de trazos circulares y puntos simulará el polvo lunar removido por el esfuerzo del explorador.</p>
  <h4>Orgullo y perseverancia</h4>
  <p>Este dibujo celebra el orgullo del trabajo bien hecho. Fomenta en los niños valores como la perseverancia ante desafíos difíciles y la importancia de trabajar en equipo para alcanzar metas que parecen imposibles.</p>', 'astronauta, luna, bandera, espacio, misión espacial, superficie lunar, ciencia infantil, exploración espacial', 'dibujo-para-colorear-astronauta-plantando-bandera-en-la-luna', 3, NULL, '2026-03-03T02:55:57.273Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280190/coloring-web/espacio/dibujo-para-colorear-astronauta-plantando-bandera-en-la-luna.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-plantando-bandera-en-la-luna') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (127, 'Dibujo para colorear astronauta reparando satélite en el espacio', 'dibujo-para-colorear-astronauta-reparando-satelite-en-el-espacio', 'Astronauta arreglando un satélite flotando en el espacio.', '<p>¿Quién arregla las máquinas en el espacio? Esta detallada ilustración muestra a un astronauta de mantenimiento realizando reparaciones en un satélite artificial, demostrando que el trabajo técnico es vital en órbita.</p>
  <h4>Ingeniería y precisión mecánica</h4>
  <p>El dibujo destaca por los detalles del satélite: paneles solares, antenas y circuitos. Es una oportunidad excelente para explicar a los niños cómo funcionan las telecomunicaciones y la importancia del mantenimiento espacial.</p>
  <h4>Guía de colores tecnológicos</h4>
  <p>Recomendamos usar colores metálicos como plata o cobre para el cuerpo del satélite. Los paneles solares pueden pintarse con un azul oscuro brillante, creando un contraste espectacular con el fondo negro del espacio.</p>
  <h4>Habilidades de resolución de problemas</h4>
  <p>Al colorear a alguien que está arreglando algo, los niños refuerzan la idea de que todo problema técnico tiene una solución. Ayuda a desarrollar el pensamiento lógico y la valoración de las carreras de ingeniería y tecnología.</p>', 'astronauta, satélite, paneles solares, reparación espacial, tecnología espacial', 'dibujo-para-colorear-astronauta-reparando-satelite-en-el-espacio', 3, NULL, '2026-03-04T02:28:29.008Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280211/coloring-web/espacio/dibujo-para-colorear-astronauta-reparando-satelite-en-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-reparando-satelite-en-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (128, 'Dibujo para colorear astronauta saludando en el espacio', 'dibujo-para-colorear-astronauta-saludando-en-el-espacio', 'Astronauta flotando y saludando entre estrellas para colorear.', '<p>¡Un saludo entre estrellas! En esta dinámica ilustración, el astronauta flota libremente en el espacio mientras nos dedica un saludo amistoso, con nuestro planeta azul suspendido en la inmensidad del cosmos de fondo.</p>
  <h4>La sensación de ingravidez</h4>
  <p>El dibujo captura la libertad del movimiento en gravedad cero. Al no tener un suelo firme, la pose del astronauta es relajada y fluida, lo que permite a los niños imaginar cómo sería no sentir el peso de su propio cuerpo.</p>
  <h4>Tips para la Tierra lejana</h4>
  <p>La Tierra es la protagonista aquí. Anima a usar azules intensos para los océanos y verdes vibrantes para los continentes. Para el espacio, el negro profundo dejará que el astronauta y la Tierra brillen con fuerza en la página.</p>
  <h4>Asombro científico y exploración</h4>
  <p>Este dibujo motiva a los niños a preguntar sobre la física del espacio y las misiones internacionales. Es un disparador de curiosidad sobre el universo, fomentando el interés por la ciencia y la colaboración tecnológica global.</p>', 'astronauta, espacio, gravedad cero, estrellas, traje espacial', 'dibujo-para-colorear-astronauta-saludando-en-el-espacio', 3, NULL, '2026-03-04T02:28:52.419Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280193/coloring-web/espacio/dibujo-para-colorear-astronauta-saludando-en-el-espacio.webp', 'coloring-web/espacio/dibujo-para-colorear-astronauta-saludando-en-el-espacio') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (162, 'Dibujo para colorear bombero frente a camión', 'dibujo-para-colorear-bombero-frente-a-camion', 'Bombero de pie junto a camión de bomberos', '<p>Esta lámina se centra en la preparación y la guardia. Un bombero posa con su equipo completo junto a su camión, representando la disposición y el compromiso de estar siempre listos para ayudar en cualquier situación de riesgo.</p>
  <h4>Texturas metálicas y textiles</h4>
  <p>El contraste entre el metal brillante del camión y la tela resistente del uniforme es el reto artístico aquí. Recomendamos usar grises metálicos para las llantas y el parachoques, contrastando con el rojo vibrante característico de los bomberos.</p>
  <h4>Identificación de roles</h4>
  <p>Este dibujo es ideal para hablar con los niños sobre la prevención de accidentes. Mientras colorean, se les puede explicar las diferentes herramientas que porta el bombero, como el hacha, el casco y el radiotransmisor.</p>', 'bombero, camión de bomberos, rescate, profesión, vehículo de emergencia', 'dibujo-para-colorear-bombero-frente-a-camion', 4, NULL, '2026-03-07T00:31:19.174Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280249/coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-frente-a-camion.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-bombero-frente-a-camion') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (132, 'Dibujo para colorear cabina de nave espacial con controles', 'dibujo-para-colorear-cabina-de-nave-espacial-con-controles', 'Interior de cabina de nave espacial con paneles para colorear.', '<p>¿Te imaginas pilotar a través de las galaxias? Esta ilustración detallada del interior de una nave espacial pone al niño al mando de cientos de botones, palancas y pantallas digitales que controlan el viaje estelar.</p>
  <h4>Estimulación cognitiva y lógica</h4>
  <p>Debido a la gran cantidad de interruptores pequeños, este dibujo es un ejercicio de precisión extrema. Ayuda a los niños a clasificar elementos: pueden elegir colores por "función", como botones rojos para emergencia y verdes para navegación.</p>
  <h4>La ventana al cosmos</h4>
  <p>A través del cristal frontal de la cabina, se puede ver el espacio. Sugerimos pintar esa zona de un negro profundo con puntos blancos para las estrellas, creando un contraste visual que haga que el panel de control parezca estar iluminado.</p>', 'cabina espacial, nave espacial, controles, botones, tecnología', 'dibujo-para-colorear-cabina-de-nave-espacial-con-controles', 3, NULL, '2026-03-04T02:30:47.127Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280213/coloring-web/espacio/dibujo-para-colorear-cabina-de-nave-espacial-con-controles.webp', 'coloring-web/espacio/dibujo-para-colorear-cabina-de-nave-espacial-con-controles') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (254, 'Dibujo para colorear camión de basura recolectando residuos', 'dibujo-para-colorear-camion-de-basura-recolectando-residuos', 'Camión de basura recorriendo una calle para recoger residuos', '<p>Esta lámina educativa destaca la labor fundamental de los servicios de limpieza urbana. El camión recolector, con su mecanismo de carga, ayuda a mantener nuestras ciudades limpias y nos enseña sobre la gestión de residuos.</p>
  <h4>Educación ambiental</h4>
  <p>Este dibujo es el disparador perfecto para hablar sobre el reciclaje. Se puede invitar al niño a colorear los diferentes cubos de basura con los colores internacionales de reciclaje (azul para papel, verde para vidrio, amarillo para plástico).</p>
  <h4>Detalles mecánicos de carga</h4>
  <p>El sistema hidráulico de la parte trasera es muy interesante para colorear. Usar tonos grises y sombras bajo el camión le dará peso y realismo a una escena que vemos cada noche en nuestra propia calle.</p>', 'camión de basura, recolección de basura, reciclaje, limpieza urbana, camión recolector, ciudad, servicio municipal, vehículo de trabajo', 'dibujo-para-colorear-camion-de-basura-recolectando-residuos', 5, NULL, '2026-03-12T01:55:24.057Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280354/coloring-web/vehiculos/dibujo-para-colorear-camion-de-basura-recolectando-residuos.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-de-basura-recolectando-residuos') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (257, 'Dibujo para colorear camioneta de helados', 'dibujo-para-colorear-camioneta-de-helados', 'Camioneta de helados vendiendo helados en la calle', '<p>¡Llegó la alegría del verano! Esta simpática camioneta de helados, con su gran cono en el techo y su ventanilla de servicio, es un clásico que evoca felicidad, parques y tardes de sol con amigos.</p>
  <h4>Creatividad y paleta de colores pastel</h4>
  <p>A diferencia de los vehículos de trabajo, la camioneta de helados invita a usar colores suaves: rosa fresa, amarillo vainilla, celeste menta y marrón chocolate. Es un ejercicio fantástico de armonía de colores.</p>
  <h4>Personalización del menú</h4>
  <p>Los niños pueden dibujar sus helados favoritos en la ventanilla de la camioneta. Esto fomenta la creatividad individual y convierte un simple dibujo para colorear en una actividad de diseño personalizada.</p>', 'camioneta de helados, heladero, carrito de helados, dulces, verano, vehículo de venta, comida dulce', 'dibujo-para-colorear-camioneta-de-helados', 5, NULL, '2026-03-12T01:56:34.373Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280358/coloring-web/vehiculos/dibujo-para-colorear-camioneta-de-helados.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camioneta-de-helados') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (258, 'Dibujo para colorear camioneta pickup', 'dibujo-para-colorear-camioneta-pickup', 'Camioneta pickup estacionada lista para transportar carga', '<p>Este robusto vehículo todoterreno es el símbolo del trabajo duro y la aventura. Con su amplia caja trasera y ruedas reforzadas, la camioneta pickup es capaz de transportar cargas pesadas por caminos difíciles, desde granjas hasta zonas de montaña.</p>
  <h4>Potencia y diseño funcional</h4>
  <p>Al colorear este dibujo, los niños pueden notar la diferencia entre la cabina de pasajeros y la zona de carga. Es una excelente oportunidad para practicar líneas rectas y entender cómo se diseñan los vehículos para el transporte de materiales.</p>
  <h4>Consejos de color</h4>
  <p>Recomendamos colores sólidos y fuertes como el azul metálico, el rojo oscuro o el verde bosque. Pintar las llantas de un gris carbón y añadir "manchas de barro" con marrón en la parte baja dará un aspecto de aventura real.</p>', 'camioneta pickup, pickup truck, vehículo utilitario, transporte, carga, camioneta, vehículo de trabajo', 'dibujo-para-colorear-camioneta-pickup', 5, NULL, '2026-03-12T01:56:57.581Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280359/coloring-web/vehiculos/dibujo-para-colorear-camioneta-pickup.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camioneta-pickup') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (259, 'Dibujo para colorear camión grúa de remolque', 'dibujo-para-colorear-camion-grua-de-remolque', 'Camión grúa remolcando un vehículo averiado', '<p>Cuando un coche tiene problemas en la carretera, el camión grúa es el encargado de acudir al rescate. Este vehículo de asistencia cuenta con un brazo hidráulico y ganchos especiales diseñados para elevar y mover otros automóviles de forma segura.</p>
  <h4>Mecánica de asistencia vial</h4>
  <p>La ilustración destaca el sistema de remolque trasero, lo que permite a los pequeños artistas comprender cómo funcionan las poleas y los cables. Es un dibujo técnico que fomenta la observación y el respeto por los servicios de auxilio en carretera.</p>
  <h4>Seguridad y visibilidad</h4>
  <p>Sugerimos usar colores de alta visibilidad como el naranja o el amarillo industrial. Las luces de emergencia en el techo se ven fantásticas si se pintan con un degradado de naranja y blanco para simular que están encendidas.</p>', 'camión grúa, remolque, grúa de rescate, vehículo de asistencia, transporte, carretera, mecánica', 'dibujo-para-colorear-camion-grua-de-remolque', 5, NULL, '2026-03-12T01:58:19.879Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280361/coloring-web/vehiculos/dibujo-para-colorear-camion-grua-de-remolque.webp', 'coloring-web/vehiculos/dibujo-para-colorear-camion-grua-de-remolque') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (165, 'Dibujo para colorear cantante en concierto', 'dibujo-para-colorear-cantante-en-concierto', 'Cantante actuando en un concierto para colorear', '<p>La música y la energía se unen en esta escena de espectáculo. El cantante, micrófono en mano, se entrega a su público bajo las luces del escenario, representando la pasión por el arte, la voz y la expresión corporal ante una audiencia.</p>
  <h4>Iluminación de escenario</h4>
  <p>Esta es una oportunidad perfecta para jugar con los contrastes. Los niños pueden colorear los focos del fondo con amarillos y rosas vibrantes, creando "haces de luz" que crucen la página y resalten la figura central del artista.</p>
  <h4>Creatividad en el vestuario</h4>
  <p>Al ser una estrella del espectáculo, el vestuario puede ser tan original como se desee. Desde colores neón hasta detalles metalizados, este dibujo fomenta la libertad creativa y la identificación con el mundo de las artes escénicas.</p>', 'cantante, concierto, música, espectáculo, profesión artística', 'dibujo-para-colorear-cantante-en-concierto', 4, NULL, '2026-03-07T00:36:23.296Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280252/coloring-web/profesiones-oficios/dibujo-para-colorear-cantante-en-concierto.webp', 'coloring-web/profesiones-oficios/dibujo-para-colorear-cantante-en-concierto') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, subcategory_id, created_at, cloudinary_url, public_id) VALUES (262, 'Dibujo para colorear carreta de caballos en el campo', 'dibujo-para-colorear-carreta-de-caballos-en-el-campo', 'Carreta tirada por caballos en un camino rural', '<p>Viajamos al pasado con este medio de transporte tradicional. La carreta tirada por caballos nos recuerda una época más tranquila y rural, donde la conexión con los animales y la naturaleza era fundamental para el transporte y el comercio.</p>
  <h4>Naturaleza e historia</h4>
  <p>El paisaje de campo al fondo, con colinas y nubes, permite practicar el coloreado de grandes superficies naturales. Es una excelente forma de introducir a los niños en la historia de la movilidad antes de la invención del motor.</p>
  <h4>Texturas de madera y pelaje</h4>
  <p>Sugerimos usar marrones para la carreta y tonos variados (blanco, negro o café) para los caballos. Trabajar en el detalle de las ruedas de madera y las riendas fortalece la paciencia y el pulso de los pequeños artistas.</p>', 'carreta de caballos, transporte antiguo, campo, caballos, granja, vehículo tradicional', 'dibujo-para-colorear-carreta-de-caballos-en-el-campo', 5, NULL, '2026-03-12T01:59:24.664Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280365/coloring-web/vehiculos/dibujo-para-colorear-carreta-de-caballos-en-el-campo.webp', 'coloring-web/vehiculos/dibujo-para-colorear-carreta-de-caballos-en-el-campo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, subcategory_id = EXCLUDED.subcategory_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
